#[derive(Clone, Debug, PartialEq, Eq)]
struct VulkanResidentInProcessPlacedActivePromptEvent {
    input_event: VulkanResidentTokenInputEvent,
    start_stream_tick: u64,
    next_external_input_index: usize,
    pending_feedback: Option<VulkanResidentPendingPrivateFeedback>,
    remaining_public_outputs: usize,
    stop_reason: Option<String>,
    terminated: bool,
    tick_count: usize,
    scheduler_turn_count: usize,
    completed_stage_count: usize,
    transport_stats: VulkanPlacedCableTransportStats,
    generated_token_ids: Vec<u32>,
    output_source_stream_ticks: Vec<u64>,
    output_events: Vec<VulkanResidentTokenOutputEvent>,
    speculative_decode: VulkanSpeculativeDecodeStats,
}

impl VulkanResidentInProcessPlacedActivePromptEvent {
    fn new(
        input_event: VulkanResidentTokenInputEvent,
        start_stream_tick: u64,
    ) -> Result<Self, VulkanResidentInProcessPlacedRuntimeError> {
        if input_event.token_ids.is_empty() {
            return Err(VulkanResidentInProcessPlacedRuntimeError::EmptyPromptEvent);
        }
        let remaining_public_outputs = input_event.max_public_tokens;
        let stop_reason = (remaining_public_outputs == 0).then(|| "max_new_tokens".to_string());
        Ok(Self {
            generated_token_ids: Vec::with_capacity(remaining_public_outputs),
            output_source_stream_ticks: Vec::with_capacity(remaining_public_outputs),
            output_events: Vec::with_capacity(remaining_public_outputs),
            input_event,
            start_stream_tick,
            next_external_input_index: 0,
            pending_feedback: None,
            remaining_public_outputs,
            stop_reason,
            terminated: false,
            tick_count: 0,
            scheduler_turn_count: 0,
            completed_stage_count: 0,
            transport_stats: VulkanPlacedCableTransportStats::default(),
            speculative_decode: VulkanSpeculativeDecodeStats::default(),
        })
    }

    fn next_activation(&self) -> Option<VulkanResidentInProcessPlacedPromptActivation> {
        if self.terminated {
            return None;
        }
        let (
            input_token_id,
            input_feedback_depth,
            input_closes_loop_after_processing,
            input_is_feedback,
        ) = if self.next_external_input_index < self.input_event.token_ids.len() {
            (
                self.input_event.token_ids[self.next_external_input_index],
                0,
                false,
                false,
            )
        } else {
            let feedback = self.pending_feedback.as_ref()?;
            (
                feedback.token_id,
                feedback.feedback_depth,
                feedback.closes_loop_after_processing,
                true,
            )
        };
        let external_inputs_remaining = self.input_event.token_ids.len()
            - self.next_external_input_index
            - usize::from(!input_is_feedback);
        Some(VulkanResidentInProcessPlacedPromptActivation {
            input_token_id,
            input_feedback_depth,
            input_closes_loop_after_processing,
            input_is_feedback,
            should_emit_public_output: self.remaining_public_outputs > 0
                && external_inputs_remaining == 0,
        })
    }

    fn resident_feedback_window_tick_count(&self, mounted_window_width: usize) -> usize {
        if mounted_window_width < 2 || self.remaining_public_outputs < 2 {
            return 0;
        }
        let Some(activation) = self.next_activation() else {
            return 0;
        };
        if !activation.input_is_feedback
            || activation.input_closes_loop_after_processing
            || !activation.should_emit_public_output
        {
            return 0;
        }
        mounted_window_width.min(self.remaining_public_outputs)
    }

    fn complete_activation(
        &mut self,
        activation: &VulkanResidentInProcessPlacedPromptActivation,
        stream_tick: u64,
        scheduler_turn_count: usize,
        completed_stage_count: usize,
        transport_stats: &VulkanPlacedCableTransportStats,
        sampled_token_id: Option<u32>,
    ) -> Result<Option<VulkanResidentTokenOutputEvent>, VulkanResidentInProcessPlacedRuntimeError>
    {
        if activation.input_is_feedback {
            self.pending_feedback
                .take()
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
        } else {
            self.next_external_input_index = self.next_external_input_index.saturating_add(1);
        }

        self.tick_count = self.tick_count.saturating_add(1);
        self.scheduler_turn_count = self
            .scheduler_turn_count
            .saturating_add(scheduler_turn_count);
        self.completed_stage_count = self
            .completed_stage_count
            .saturating_add(completed_stage_count);
        self.transport_stats.accumulate(transport_stats);

        let output_event = if activation.should_emit_public_output {
            let sampled_token_id = sampled_token_id
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingFusedSamplerRun)?;
            let output_index = self.generated_token_ids.len();
            let output_event = VulkanResidentTokenOutputEvent {
                id: format!("{}.{}", self.input_event.id, output_index),
                input_event_id: self.input_event.id.clone(),
                output_index,
                token_id: sampled_token_id,
                source_stream_tick: stream_tick,
            };
            self.generated_token_ids.push(sampled_token_id);
            self.output_source_stream_ticks.push(stream_tick);
            self.output_events.push(output_event.clone());
            self.remaining_public_outputs -= 1;

            let closes_loop_after_processing =
                if self.input_event.stop_token_ids.contains(&sampled_token_id) {
                    self.remaining_public_outputs = 0;
                    self.stop_reason = Some("eos".to_string());
                    true
                } else if self.remaining_public_outputs == 0 {
                    self.stop_reason = Some("max_new_tokens".to_string());
                    true
                } else {
                    false
                };
            self.pending_feedback = Some(VulkanResidentPendingPrivateFeedback {
                token_id: sampled_token_id,
                feedback_depth: activation
                    .input_feedback_depth
                    .checked_add(1)
                    .ok_or(VulkanResidentInProcessPlacedRuntimeError::FeedbackDepthOverflow)?,
                closes_loop_after_processing,
            });
            Some(output_event)
        } else {
            None
        };

        if activation.input_closes_loop_after_processing {
            self.pending_feedback = None;
        }
        Ok(output_event)
    }

    fn is_complete(&self) -> bool {
        self.terminated
            || (self.next_external_input_index == self.input_event.token_ids.len()
                && self.pending_feedback.is_none())
    }

    fn interrupt(&mut self, reason: impl Into<String>) -> VulkanResidentStreamControlEvent {
        let reason = reason.into();
        let cleared_private_feedback_ids = self
            .pending_feedback
            .take()
            .map(|_| self.pending_feedback_id())
            .into_iter()
            .collect();
        self.remaining_public_outputs = 0;
        self.stop_reason = Some(reason.clone());
        self.terminated = true;
        VulkanResidentStreamControlEvent {
            event_type: VulkanResidentStreamControlEventType::Interrupt,
            reason,
            cleared_private_feedback_ids,
            closing_private_feedback_id: None,
            state_preserved: true,
        }
    }

    fn stop_after_current(
        &mut self,
        reason: impl Into<String>,
    ) -> VulkanResidentStreamControlEvent {
        let reason = reason.into();
        let closing_private_feedback_id = self
            .pending_feedback
            .as_ref()
            .map(|_| self.pending_feedback_id());
        if let Some(feedback) = &mut self.pending_feedback {
            feedback.closes_loop_after_processing = true;
        }
        self.remaining_public_outputs = 0;
        self.stop_reason = Some(reason.clone());
        VulkanResidentStreamControlEvent {
            event_type: VulkanResidentStreamControlEventType::StopAfterCurrent,
            reason,
            cleared_private_feedback_ids: Vec::new(),
            closing_private_feedback_id,
            state_preserved: true,
        }
    }

    fn pending_feedback_id(&self) -> String {
        format!(
            "{}.feedback.{}",
            self.input_event.id,
            self.generated_token_ids.len().saturating_sub(1)
        )
    }

    fn into_event_run(
        self,
        input_device_id: String,
        output_device_id: String,
    ) -> VulkanResidentInProcessPlacedPromptEventRun {
        let output_token_ids = self.input_event.token_ids[..self.next_external_input_index]
            .iter()
            .copied()
            .chain(self.generated_token_ids.iter().copied())
            .collect();
        VulkanResidentInProcessPlacedPromptEventRun {
            input_device_id,
            output_device_id,
            prompt_token_ids: self.input_event.token_ids,
            generated_token_ids: self.generated_token_ids,
            output_token_ids,
            stop_reason: self
                .stop_reason
                .unwrap_or_else(|| "max_new_tokens".to_string()),
            tick_count: self.tick_count,
            scheduler_turn_count: self.scheduler_turn_count,
            completed_stage_count: self.completed_stage_count,
            transport_stats: self.transport_stats,
            output_source_stream_ticks: self.output_source_stream_ticks,
            speculative_decode: self.speculative_decode,
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct VulkanResidentInProcessPlacedPromptActivation {
    input_token_id: u32,
    input_feedback_depth: u32,
    input_closes_loop_after_processing: bool,
    input_is_feedback: bool,
    should_emit_public_output: bool,
}

pub struct VulkanResidentInProcessPlacedPromptSession {
    pub next_stream_tick: u64,
    pub completed_prompt_event_count: usize,
    pub generated_token_count: usize,
    pub output_token_count: usize,
    transport: VulkanInProcessPlacedCableTransport,
}

impl VulkanResidentInProcessPlacedPromptSession {
    pub fn new(start_stream_tick: u64) -> Self {
        Self {
            next_stream_tick: start_stream_tick,
            completed_prompt_event_count: 0,
            generated_token_count: 0,
            output_token_count: 0,
            transport: VulkanInProcessPlacedCableTransport::new(),
        }
    }

    pub fn transport_direct_cable_binding_count(&self) -> usize {
        self.transport.direct_cable_binding_count()
    }

    pub fn transport_stats(&self) -> VulkanPlacedCableTransportStats {
        self.transport.stats()
    }

    fn complete_prompt_event(
        &mut self,
        start_stream_tick: u64,
        run: VulkanResidentInProcessPlacedPromptEventRun,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptSessionRun,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        let tick_count = run.tick_count;
        let tick_delta = u64::try_from(tick_count)
            .map_err(|_| VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
        let next_stream_tick = start_stream_tick
            .checked_add(tick_delta)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
        let prompt_event_index = self.completed_prompt_event_count;

        self.next_stream_tick = next_stream_tick;
        self.completed_prompt_event_count = self.completed_prompt_event_count.saturating_add(1);
        self.generated_token_count = self
            .generated_token_count
            .saturating_add(run.generated_token_ids.len());
        self.output_token_count = self
            .output_token_count
            .saturating_add(run.output_token_ids.len());

        Ok(VulkanResidentInProcessPlacedPromptSessionRun {
            prompt_event_index,
            start_stream_tick,
            next_stream_tick,
            tick_count,
            run,
        })
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedPromptSessionRun {
    pub prompt_event_index: usize,
    pub start_stream_tick: u64,
    pub next_stream_tick: u64,
    pub tick_count: usize,
    pub run: VulkanResidentInProcessPlacedPromptEventRun,
}

pub struct VulkanResidentInProcessPlacedPromptStream {
    package: Arc<VulkanResidentInProcessPlacedModelPackage>,
    processor: VulkanResidentInProcessPlacedStreamProcessor,
    devices: BTreeMap<String, Rc<VulkanComputeDevice>>,
    session: VulkanResidentInProcessPlacedPromptSession,
    active_input_event: Option<VulkanResidentInProcessPlacedActivePromptEvent>,
    pending_input_events: VecDeque<VulkanResidentTokenInputEvent>,
    speculative_draft_tokens: usize,
}

impl VulkanResidentInProcessPlacedPromptStream {
    pub fn new(
        package: Arc<VulkanResidentInProcessPlacedModelPackage>,
        devices: BTreeMap<String, Rc<VulkanComputeDevice>>,
        random_seed: u32,
    ) -> Result<Self, VulkanResidentInProcessPlacedRuntimeError> {
        Self::from_package_devices_and_session(package, devices, random_seed, 0)
    }

    pub fn from_runtime_model_for_bound_devices(
        devices: BTreeMap<String, Rc<VulkanComputeDevice>>,
        manifest_dir: impl AsRef<Path>,
        runtime_model: VulkanResidentRuntimeModel,
        dynamic_state_capacity_activations: Option<usize>,
        random_seed: u32,
        speculative_draft_tokens: usize,
    ) -> Result<Self, VulkanResidentInProcessPlacedRuntimeError> {
        let package = Arc::new(
            VulkanResidentInProcessPlacedModelPackage::from_runtime_model_for_bound_devices(
                &devices,
                manifest_dir,
                runtime_model,
                dynamic_state_capacity_activations,
                speculative_draft_tokens > 0,
            )?,
        );
        let mut stream = Self::new(package, devices, random_seed)?;
        stream.speculative_draft_tokens = speculative_draft_tokens;
        Ok(stream)
    }

    pub fn from_package_devices_and_session(
        package: Arc<VulkanResidentInProcessPlacedModelPackage>,
        devices: BTreeMap<String, Rc<VulkanComputeDevice>>,
        random_seed: u32,
        start_stream_tick: u64,
    ) -> Result<Self, VulkanResidentInProcessPlacedRuntimeError> {
        for device_id in &package.device_ids {
            if !devices.contains_key(device_id) {
                return Err(
                    VulkanResidentInProcessPlacedRuntimeError::MissingBoundDevice {
                        device_id: device_id.clone(),
                    },
                );
            }
        }
        let processor = package.create_stream_processor_for_bound_devices(&devices, random_seed)?;
        let session = processor.prompt_session_from_stream_tick(start_stream_tick);
        Ok(Self {
            package,
            processor,
            devices,
            session,
            active_input_event: None,
            pending_input_events: VecDeque::new(),
            speculative_draft_tokens: 0,
        })
    }

    pub fn package(&self) -> &VulkanResidentInProcessPlacedModelPackage {
        &self.package
    }

    pub fn session(&self) -> &VulkanResidentInProcessPlacedPromptSession {
        &self.session
    }

    pub fn devices(&self) -> &BTreeMap<String, Rc<VulkanComputeDevice>> {
        &self.devices
    }

    pub fn remount_model_preserving_state(
        &mut self,
        package: Arc<VulkanResidentInProcessPlacedModelPackage>,
        random_seed: u32,
    ) -> Result<(), VulkanResidentInProcessPlacedRuntimeError> {
        let processor = package.create_stream_processor_inheriting_state_for_bound_devices(
            &self.devices,
            random_seed,
            &self.processor,
        )?;
        self.session.transport = VulkanInProcessPlacedCableTransport::new();
        self.package = package;
        self.processor = processor;
        Ok(())
    }

    pub fn next_stream_tick(&self) -> u64 {
        self.session.next_stream_tick
    }

    pub fn completed_prompt_event_count(&self) -> usize {
        self.session.completed_prompt_event_count
    }

    pub fn pending_input_event_count(&self) -> usize {
        self.pending_input_events.len() + usize::from(self.active_input_event.is_some())
    }

    pub fn is_idle(&self) -> bool {
        self.active_input_event.is_none() && self.pending_input_events.is_empty()
    }

    pub fn enqueue_input_event(
        &mut self,
        event: VulkanResidentTokenInputEvent,
    ) -> VulkanResidentInProcessPlacedQueuedInputEvent {
        self.pending_input_events.push_back(event.clone());
        VulkanResidentInProcessPlacedQueuedInputEvent {
            input_event: event,
            pending_input_event_count: self.pending_input_event_count(),
            next_stream_tick: self.next_stream_tick(),
        }
    }

    fn activate_next_input_event(
        &mut self,
    ) -> Result<bool, VulkanResidentInProcessPlacedRuntimeError> {
        if self.active_input_event.is_some() {
            return Ok(true);
        }
        let Some(input_event) = self.pending_input_events.pop_front() else {
            return Ok(false);
        };
        self.active_input_event = Some(VulkanResidentInProcessPlacedActivePromptEvent::new(
            input_event,
            self.session.next_stream_tick,
        )?);
        Ok(true)
    }

    fn run_temporal_external_input_block_with_output<F>(
        &mut self,
        on_output_event: &mut F,
    ) -> Result<
        (bool, Option<VulkanResidentInProcessPlacedSubmittedInputRun>),
        VulkanResidentInProcessPlacedRuntimeError,
    >
    where
        F: FnMut(VulkanResidentTokenOutputEvent),
    {
        if !self.activate_next_input_event()? {
            return Ok((false, None));
        }
        let active = self
            .active_input_event
            .as_ref()
            .expect("temporal block requires an active input event");
        let external_input_count = active
            .input_event
            .token_ids
            .len()
            .saturating_sub(active.next_external_input_index);
        if external_input_count < 2 || active.pending_feedback.is_some() {
            return Ok((false, None));
        }
        let block_width = self.processor.temporal_block_width(external_input_count)?;
        if block_width < 2 {
            return Ok((false, None));
        }
        let block_start_index = active.next_external_input_index;
        let block_end_index = block_start_index + block_width;
        let input_token_ids =
            active.input_event.token_ids[block_start_index..block_end_index].to_vec();
        let sample_last = block_end_index == active.input_event.token_ids.len()
            && active.remaining_public_outputs > 0;
        let start_stream_tick = self.session.next_stream_tick;
        let block_run = self.processor.run_temporal_prompt_block(
            &self.devices,
            &input_token_ids,
            start_stream_tick,
            sample_last,
        )?;

        for (block_index, input_token_id) in input_token_ids.iter().enumerate() {
            let stream_tick = self.session.next_stream_tick;
            let activation = self
                .active_input_event
                .as_ref()
                .and_then(VulkanResidentInProcessPlacedActivePromptEvent::next_activation)
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
            if activation.input_is_feedback || activation.input_token_id != *input_token_id {
                return Err(VulkanResidentInProcessPlacedRuntimeError::BackendLoop(
                    VulkanError(
                        "temporal block diverged from the external input queue".to_string(),
                    ),
                ));
            }
            let transport_stats = if block_index + 1 == block_width {
                &block_run.transport_stats
            } else {
                &VulkanPlacedCableTransportStats::default()
            };
            let sampled_token_id = (block_index + 1 == block_width)
                .then_some(block_run.sampled_token_id)
                .flatten();
            let output_event = self
                .active_input_event
                .as_mut()
                .expect("temporal block requires an active input event")
                .complete_activation(
                    &activation,
                    stream_tick,
                    block_run.scheduler_turn_count_per_tick,
                    block_run.completed_stage_count_per_tick,
                    transport_stats,
                    sampled_token_id,
                )?;
            self.session.next_stream_tick = stream_tick
                .checked_add(1)
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
            if let Some(output_event) = output_event {
                on_output_event(output_event);
            }
        }

        let completed_input_run = self
            .active_input_event
            .as_ref()
            .is_some_and(VulkanResidentInProcessPlacedActivePromptEvent::is_complete)
            .then(|| self.complete_active_input_event())
            .transpose()?;
        Ok((true, completed_input_run))
    }

    pub fn run_next_activation(
        &mut self,
    ) -> Result<
        Option<VulkanResidentInProcessPlacedPromptStreamActivationRun>,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        if !self.activate_next_input_event()? {
            return Ok(None);
        }

        let activation = self
            .active_input_event
            .as_ref()
            .and_then(VulkanResidentInProcessPlacedActivePromptEvent::next_activation)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
        let input_event_id = self
            .active_input_event
            .as_ref()
            .expect("active prompt event was initialized")
            .input_event
            .id
            .clone();
        let stream_tick = self.session.next_stream_tick;
        let tail = if activation.should_emit_public_output {
            VulkanResidentPlacedTokenTickTail::Sample
        } else if self.processor.speculative_decoder_count() > 0 {
            VulkanResidentPlacedTokenTickTail::Hidden
        } else {
            VulkanResidentPlacedTokenTickTail::None
        };
        self.processor.prepare_token_input(placed_token_input(
            activation.input_token_id,
            &self.processor.model.input_device_id,
            &self.processor.model.output_device_id,
            activation.input_is_feedback,
        ))?;
        let placed_run = self
            .processor
            .execute_prepared_token_id_stream_tick_on_bound_devices_in_process_with_transport(
                &self.devices,
                &mut self.session.transport,
                stream_tick,
                tail,
            )?;
        let sampled_token_id = if activation.should_emit_public_output {
            Some(
                self.processor
                    .sampler
                    .completed_token_id()
                    .map_err(VulkanResidentInProcessPlacedRuntimeError::Sampler)?,
            )
        } else {
            None
        };
        self.processor
            .synchronize_speculative_decoders_after_target_tick(&self.devices, stream_tick)?;
        let output_event = self
            .active_input_event
            .as_mut()
            .expect("active prompt event was initialized")
            .complete_activation(
                &activation,
                stream_tick,
                placed_run.scheduler_turn_count,
                placed_run.completed_stage_delta,
                &placed_run.transport_stats,
                sampled_token_id,
            )?;
        self.session.next_stream_tick = stream_tick
            .checked_add(1)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;

        let completed_input_run = if self
            .active_input_event
            .as_ref()
            .is_some_and(VulkanResidentInProcessPlacedActivePromptEvent::is_complete)
        {
            Some(self.complete_active_input_event()?)
        } else {
            None
        };

        Ok(Some(
            VulkanResidentInProcessPlacedPromptStreamActivationRun {
                input_event_id,
                stream_tick,
                input_token_id: activation.input_token_id,
                input_is_feedback: activation.input_is_feedback,
                output_event,
                completed_input_run,
            },
        ))
    }

    pub fn interrupt(
        &mut self,
        reason: impl Into<String>,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptStreamControlRun,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        let reason = reason.into();
        let control_event = if let Some(active_input_event) = &mut self.active_input_event {
            active_input_event.interrupt(reason)
        } else {
            VulkanResidentStreamControlEvent {
                event_type: VulkanResidentStreamControlEventType::Interrupt,
                reason,
                cleared_private_feedback_ids: Vec::new(),
                closing_private_feedback_id: None,
                state_preserved: true,
            }
        };
        let completed_input_run = self
            .active_input_event
            .as_ref()
            .is_some_and(VulkanResidentInProcessPlacedActivePromptEvent::is_complete)
            .then(|| self.complete_active_input_event())
            .transpose()?;
        Ok(VulkanResidentInProcessPlacedPromptStreamControlRun {
            control_event,
            completed_input_run,
        })
    }

    pub fn stop_after_current(
        &mut self,
        reason: impl Into<String>,
    ) -> VulkanResidentInProcessPlacedPromptStreamControlRun {
        let reason = reason.into();
        let control_event = if let Some(active_input_event) = &mut self.active_input_event {
            active_input_event.stop_after_current(reason)
        } else {
            VulkanResidentStreamControlEvent {
                event_type: VulkanResidentStreamControlEventType::StopAfterCurrent,
                reason,
                cleared_private_feedback_ids: Vec::new(),
                closing_private_feedback_id: None,
                state_preserved: true,
            }
        };
        VulkanResidentInProcessPlacedPromptStreamControlRun {
            control_event,
            completed_input_run: None,
        }
    }

    pub fn run_next_queued_input_event(
        &mut self,
    ) -> Result<
        Option<VulkanResidentInProcessPlacedSubmittedInputRun>,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        self.run_next_queued_input_event_with_output(|_| {})
    }

    pub fn run_next_queued_input_event_with_output<F>(
        &mut self,
        mut on_output_event: F,
    ) -> Result<
        Option<VulkanResidentInProcessPlacedSubmittedInputRun>,
        VulkanResidentInProcessPlacedRuntimeError,
    >
    where
        F: FnMut(VulkanResidentTokenOutputEvent),
    {
        if self.is_idle() {
            return Ok(None);
        }
        loop {
            let (ran_temporal_block, completed_input_run) =
                self.run_temporal_external_input_block_with_output(&mut on_output_event)?;
            if let Some(completed_input_run) = completed_input_run {
                return Ok(Some(completed_input_run));
            }
            if ran_temporal_block {
                continue;
            }
            if self.run_speculative_feedback_window_with_output(&mut on_output_event)? {
                if self
                    .active_input_event
                    .as_ref()
                    .is_some_and(VulkanResidentInProcessPlacedActivePromptEvent::is_complete)
                {
                    return Ok(Some(self.complete_active_input_event()?));
                }
                continue;
            }
            if self.run_resident_feedback_window_with_output(&mut on_output_event)? {
                if self
                    .active_input_event
                    .as_ref()
                    .is_some_and(VulkanResidentInProcessPlacedActivePromptEvent::is_complete)
                {
                    return Ok(Some(self.complete_active_input_event()?));
                }
                continue;
            }
            let activation = self
                .run_next_activation()?
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
            if let Some(output_event) = activation.output_event {
                on_output_event(output_event);
            }
            if let Some(completed_input_run) = activation.completed_input_run {
                return Ok(Some(completed_input_run));
            }
        }
    }

    fn run_speculative_feedback_window_with_output<F>(
        &mut self,
        on_output_event: &mut F,
    ) -> Result<bool, VulkanResidentInProcessPlacedRuntimeError>
    where
        F: FnMut(VulkanResidentTokenOutputEvent),
    {
        if self.speculative_draft_tokens == 0 || self.processor.speculative_decoder_count() == 0 {
            return Ok(false);
        }
        let Some(active) = self.active_input_event.as_ref() else {
            return Ok(false);
        };
        let Some(activation) = active.next_activation() else {
            return Ok(false);
        };
        if !activation.input_is_feedback
            || activation.input_closes_loop_after_processing
            || !activation.should_emit_public_output
            || active.remaining_public_outputs < 2
        {
            return Ok(false);
        }
        let draft_token_count = self
            .speculative_draft_tokens
            .min(active.remaining_public_outputs - 1);
        let stop_token_ids = active
            .input_event
            .stop_token_ids
            .iter()
            .copied()
            .collect::<BTreeSet<_>>();
        let start_stream_tick = self.session.next_stream_tick;
        let cycle = self.processor.run_speculative_cycle_on_bound_devices(
            &self.devices,
            activation.input_token_id,
            start_stream_tick,
            draft_token_count,
            &stop_token_ids,
        )?;
        self.active_input_event
            .as_mut()
            .expect("speculative feedback cycle requires an active input event")
            .speculative_decode
            .record_cycle(&cycle);
        for sampled_token_id in cycle.verification.emitted_token_ids {
            let stream_tick = self.session.next_stream_tick;
            let output_event = {
                let active = self
                    .active_input_event
                    .as_mut()
                    .expect("speculative feedback cycle requires an active input event");
                let activation = active
                    .next_activation()
                    .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
                active.complete_activation(
                    &activation,
                    stream_tick,
                    0,
                    0,
                    &VulkanPlacedCableTransportStats::default(),
                    Some(sampled_token_id),
                )?
            };
            self.session.next_stream_tick = stream_tick
                .checked_add(1)
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
            if let Some(output_event) = output_event {
                on_output_event(output_event);
            }
        }
        Ok(true)
    }

    pub fn submit_input_event(
        &mut self,
        event: VulkanResidentTokenInputEvent,
    ) -> Result<
        VulkanResidentInProcessPlacedSubmittedInputRun,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        self.ensure_idle_for_immediate_input_event()?;
        self.enqueue_input_event(event);
        self.run_next_queued_input_event()?
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::EmptyPromptEvent)
    }

    pub fn run_queued_input_events_until_idle(
        &mut self,
    ) -> Result<VulkanResidentInProcessPlacedInputQueueRun, VulkanResidentInProcessPlacedRuntimeError>
    {
        let start_stream_tick = self.next_stream_tick();
        let mut submitted_runs = Vec::new();
        while let Some(submitted_run) = self.run_next_queued_input_event()? {
            submitted_runs.push(submitted_run);
        }
        let next_stream_tick = self.next_stream_tick();
        let output_events = submitted_runs
            .iter()
            .flat_map(|submitted_run| submitted_run.output_events.iter().cloned())
            .collect::<Vec<_>>();
        let generated_token_ids = output_events
            .iter()
            .map(|event| event.token_id)
            .collect::<Vec<_>>();
        let tick_count = submitted_runs
            .iter()
            .map(|submitted_run| submitted_run.session_run.tick_count)
            .sum::<usize>();

        Ok(VulkanResidentInProcessPlacedInputQueueRun {
            start_stream_tick,
            next_stream_tick,
            submitted_runs,
            output_events,
            generated_token_ids,
            tick_count,
            pending_input_event_count: self.pending_input_event_count(),
        })
    }

    pub fn submit_input_events_until_idle<I>(
        &mut self,
        events: I,
    ) -> Result<VulkanResidentInProcessPlacedInputQueueRun, VulkanResidentInProcessPlacedRuntimeError>
    where
        I: IntoIterator<Item = VulkanResidentTokenInputEvent>,
    {
        for event in events {
            self.enqueue_input_event(event);
        }
        self.run_queued_input_events_until_idle()
    }

    fn ensure_idle_for_immediate_input_event(
        &self,
    ) -> Result<(), VulkanResidentInProcessPlacedRuntimeError> {
        if self.is_idle() {
            Ok(())
        } else {
            Err(VulkanResidentInProcessPlacedRuntimeError::PromptStreamBusy)
        }
    }

    fn run_resident_feedback_window_with_output<F>(
        &mut self,
        on_output_event: &mut F,
    ) -> Result<bool, VulkanResidentInProcessPlacedRuntimeError>
    where
        F: FnMut(VulkanResidentTokenOutputEvent),
    {
        let tick_count = self
            .active_input_event
            .as_ref()
            .map(|event| {
                event.resident_feedback_window_tick_count(
                    self.processor.resident_feedback_window_width(),
                )
            })
            .unwrap_or(0);
        if tick_count == 0 {
            return Ok(false);
        }
        let tick_delta = u64::try_from(tick_count)
            .map_err(|_| VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
        self.session
            .next_stream_tick
            .checked_add(tick_delta)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
        let feedback_depth_delta = u32::try_from(tick_count)
            .map_err(|_| VulkanResidentInProcessPlacedRuntimeError::FeedbackDepthOverflow)?;
        self.active_input_event
            .as_ref()
            .and_then(VulkanResidentInProcessPlacedActivePromptEvent::next_activation)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?
            .input_feedback_depth
            .checked_add(feedback_depth_delta)
            .ok_or(VulkanResidentInProcessPlacedRuntimeError::FeedbackDepthOverflow)?;
        let device_id = &self.processor.model.input_device_id;
        let device = self.devices.get(device_id).cloned().ok_or_else(|| {
            VulkanResidentInProcessPlacedRuntimeError::MissingBoundDevice {
                device_id: device_id.clone(),
            }
        })?;
        let start_stream_tick = self.session.next_stream_tick;
        let feedback_run = self.processor.run_resident_feedback_window(
            device.as_ref(),
            start_stream_tick,
            tick_count,
        )?;
        let mut restore_after_tick = None;
        for (tick_index, sampled_token_id) in feedback_run.sampled_token_ids.into_iter().enumerate()
        {
            let stream_tick = self.session.next_stream_tick;
            let (output_event, closes_loop) = {
                let active_input_event = self
                    .active_input_event
                    .as_mut()
                    .expect("resident feedback window requires an active input event");
                let activation = active_input_event
                    .next_activation()
                    .ok_or(VulkanResidentInProcessPlacedRuntimeError::MissingPrivateFeedback)?;
                let closes_loop = activation.input_closes_loop_after_processing;
                let output_event = active_input_event.complete_activation(
                    &activation,
                    stream_tick,
                    feedback_run.scheduler_turn_count_per_tick,
                    feedback_run.completed_stage_count_per_tick,
                    &VulkanPlacedCableTransportStats::default(),
                    activation
                        .should_emit_public_output
                        .then_some(sampled_token_id),
                )?;
                (output_event, closes_loop)
            };
            self.session.next_stream_tick = stream_tick
                .checked_add(1)
                .ok_or(VulkanResidentInProcessPlacedRuntimeError::StreamTickOverflow)?;
            if let Some(output_event) = output_event {
                on_output_event(output_event);
            }
            if closes_loop {
                restore_after_tick = Some(tick_index);
                break;
            }
        }
        if let Some(tick_index) = restore_after_tick {
            self.processor
                .restore_resident_feedback_state_after_tick(tick_index)?;
        }
        Ok(true)
    }

    fn complete_active_input_event(
        &mut self,
    ) -> Result<
        VulkanResidentInProcessPlacedSubmittedInputRun,
        VulkanResidentInProcessPlacedRuntimeError,
    > {
        let active_input_event = self
            .active_input_event
            .take()
            .expect("completed prompt event was active");
        debug_assert!(active_input_event.is_complete());
        let input_event = active_input_event.input_event.clone();
        let output_events = active_input_event.output_events.clone();
        let generated_token_ids = active_input_event.generated_token_ids.clone();
        let start_stream_tick = active_input_event.start_stream_tick;
        let event_run = active_input_event.into_event_run(
            self.package.input_device_id.clone(),
            self.package.output_device_id.clone(),
        );
        let session_run = self
            .session
            .complete_prompt_event(start_stream_tick, event_run)?;
        Ok(VulkanResidentInProcessPlacedSubmittedInputRun {
            input_event,
            pending_input_event_count: self.pending_input_event_count(),
            session_run,
            output_events,
            generated_token_ids,
        })
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedQueuedInputEvent {
    pub input_event: VulkanResidentTokenInputEvent,
    pub pending_input_event_count: usize,
    pub next_stream_tick: u64,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedSubmittedInputRun {
    pub input_event: VulkanResidentTokenInputEvent,
    pub pending_input_event_count: usize,
    pub session_run: VulkanResidentInProcessPlacedPromptSessionRun,
    pub output_events: Vec<VulkanResidentTokenOutputEvent>,
    pub generated_token_ids: Vec<u32>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedPromptStreamActivationRun {
    pub input_event_id: String,
    pub stream_tick: u64,
    pub input_token_id: u32,
    pub input_is_feedback: bool,
    pub output_event: Option<VulkanResidentTokenOutputEvent>,
    pub completed_input_run: Option<VulkanResidentInProcessPlacedSubmittedInputRun>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedPromptStreamControlRun {
    pub control_event: VulkanResidentStreamControlEvent,
    pub completed_input_run: Option<VulkanResidentInProcessPlacedSubmittedInputRun>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentInProcessPlacedInputQueueRun {
    pub start_stream_tick: u64,
    pub next_stream_tick: u64,
    pub submitted_runs: Vec<VulkanResidentInProcessPlacedSubmittedInputRun>,
    pub output_events: Vec<VulkanResidentTokenOutputEvent>,
    pub generated_token_ids: Vec<u32>,
    pub tick_count: usize,
    pub pending_input_event_count: usize,
}

#[derive(Default)]
pub struct VulkanResidentInProcessPlacedPromptEngine {
    streams: BTreeMap<String, VulkanResidentInProcessPlacedPromptStream>,
    active_queue: VecDeque<String>,
}

impl VulkanResidentInProcessPlacedPromptEngine {
    pub fn new() -> Self {
        Self {
            streams: BTreeMap::new(),
            active_queue: VecDeque::new(),
        }
    }

    pub fn add_stream(
        &mut self,
        stream_id: impl Into<String>,
        stream: VulkanResidentInProcessPlacedPromptStream,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineStreamSnapshot,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        let stream_id = stream_id.into();
        if self.streams.contains_key(&stream_id) {
            return Err(VulkanResidentInProcessPlacedPromptEngineError::DuplicateStream(stream_id));
        }
        let snapshot = placed_prompt_engine_stream_snapshot(&stream_id, &stream);
        if !stream.is_idle() {
            self.activate_stream_id(&stream_id);
        }
        self.streams.insert(stream_id, stream);
        Ok(snapshot)
    }

    pub fn stream(&self, stream_id: &str) -> Option<&VulkanResidentInProcessPlacedPromptStream> {
        self.streams.get(stream_id)
    }

    pub fn enqueue_input_event(
        &mut self,
        stream_id: &str,
        event: VulkanResidentTokenInputEvent,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineQueuedInputEvent,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        let queued_input_event = {
            let stream = self.streams.get_mut(stream_id).ok_or_else(|| {
                VulkanResidentInProcessPlacedPromptEngineError::UnknownStream {
                    stream_id: stream_id.to_string(),
                }
            })?;
            stream.enqueue_input_event(event)
        };
        self.activate_stream_id(stream_id);
        Ok(VulkanResidentInProcessPlacedPromptEngineQueuedInputEvent {
            stream_id: stream_id.to_string(),
            queued_input_event,
        })
    }

    pub fn interrupt_stream(
        &mut self,
        stream_id: &str,
        reason: impl Into<String>,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineControlRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        let (stream_control_run, stream_still_active) = {
            let stream = self.streams.get_mut(stream_id).ok_or_else(|| {
                VulkanResidentInProcessPlacedPromptEngineError::UnknownStream {
                    stream_id: stream_id.to_string(),
                }
            })?;
            let stream_control_run = stream.interrupt(reason)?;
            (stream_control_run, !stream.is_idle())
        };
        if stream_still_active {
            self.activate_stream_id(stream_id);
        } else {
            self.active_queue.retain(|active| active != stream_id);
        }
        Ok(VulkanResidentInProcessPlacedPromptEngineControlRun {
            stream_id: stream_id.to_string(),
            stream_control_run,
        })
    }

    pub fn stop_stream_after_current(
        &mut self,
        stream_id: &str,
        reason: impl Into<String>,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineControlRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        let (stream_control_run, stream_still_active) = {
            let stream = self.streams.get_mut(stream_id).ok_or_else(|| {
                VulkanResidentInProcessPlacedPromptEngineError::UnknownStream {
                    stream_id: stream_id.to_string(),
                }
            })?;
            let stream_control_run = stream.stop_after_current(reason);
            (stream_control_run, !stream.is_idle())
        };
        if stream_still_active {
            self.activate_stream_id(stream_id);
        }
        Ok(VulkanResidentInProcessPlacedPromptEngineControlRun {
            stream_id: stream_id.to_string(),
            stream_control_run,
        })
    }

    pub fn submit_input_event_until_idle(
        &mut self,
        stream_id: &str,
        event: VulkanResidentTokenInputEvent,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineSubmittedInputRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        self.submit_input_event_until_idle_with_output(stream_id, event, |_| {})
    }

    pub fn submit_input_event_until_idle_with_output<F>(
        &mut self,
        stream_id: &str,
        event: VulkanResidentTokenInputEvent,
        on_output_event: F,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineSubmittedInputRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    >
    where
        F: FnMut(VulkanResidentTokenRuntimeSchedulerOutputEvent),
    {
        let input_event_id = event.id.clone();
        let queued_input_event = self.enqueue_input_event(stream_id, event)?;
        let engine_run = self.run_until_idle_bounded_with_output(usize::MAX, on_output_event)?;
        let output_events = engine_run
            .output_events
            .iter()
            .filter(|event| {
                event.stream_id == stream_id && event.output_event.input_event_id == input_event_id
            })
            .cloned()
            .collect::<Vec<_>>();
        let generated_token_ids = output_events
            .iter()
            .map(|event| event.output_event.token_id)
            .collect::<Vec<_>>();

        Ok(VulkanResidentInProcessPlacedPromptEngineSubmittedInputRun {
            stream_id: stream_id.to_string(),
            input_event_id,
            queued_input_event,
            engine_run,
            output_events,
            generated_token_ids,
        })
    }

    pub fn submit_input_events_until_idle_bounded<I>(
        &mut self,
        requests: I,
        max_input_events: usize,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineBatchRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    >
    where
        I: IntoIterator<Item = VulkanResidentInProcessPlacedPromptEngineInputRequest>,
    {
        let mut queued_input_events = Vec::new();
        for request in requests {
            queued_input_events
                .push(self.enqueue_input_event(&request.stream_id, request.input_event)?);
        }
        let engine_run = self.run_until_idle_bounded(max_input_events)?;
        let output_events = engine_run.output_events.clone();
        let generated_token_ids = engine_run.generated_token_ids.clone();

        Ok(VulkanResidentInProcessPlacedPromptEngineBatchRun {
            queued_input_events,
            engine_run,
            output_events,
            generated_token_ids,
        })
    }

    pub fn run_until_idle_bounded(
        &mut self,
        max_input_events: usize,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    > {
        self.run_until_idle_bounded_with_output(max_input_events, |_| {})
    }

    pub fn run_until_idle_bounded_with_output<F>(
        &mut self,
        max_input_events: usize,
        mut on_output_event: F,
    ) -> Result<
        VulkanResidentInProcessPlacedPromptEngineRun,
        VulkanResidentInProcessPlacedPromptEngineError,
    >
    where
        F: FnMut(VulkanResidentTokenRuntimeSchedulerOutputEvent),
    {
        let start_snapshot = self.snapshot();
        let mut input_runs = Vec::new();
        let mut output_events = Vec::new();
        self.refresh_active_queue();

        while input_runs.len() < max_input_events {
            let Some(stream_id) = self.active_queue.pop_front() else {
                break;
            };
            let stream = self.streams.get_mut(&stream_id).ok_or_else(|| {
                VulkanResidentInProcessPlacedPromptEngineError::UnknownStream {
                    stream_id: stream_id.clone(),
                }
            })?;
            if stream.is_idle() {
                continue;
            }
            let callback_stream_id = stream_id.clone();
            let Some(submitted_run) =
                stream.run_next_queued_input_event_with_output(|output_event| {
                    on_output_event(VulkanResidentTokenRuntimeSchedulerOutputEvent {
                        stream_id: callback_stream_id.clone(),
                        output_event,
                    });
                })?
            else {
                continue;
            };
            let stream_still_active = !stream.is_idle();
            let stream_output_events =
                placed_prompt_engine_output_events_for(&stream_id, &submitted_run.output_events);
            let stream_generated_token_ids = stream_output_events
                .iter()
                .map(|event| event.output_event.token_id)
                .collect::<Vec<_>>();
            output_events.extend(stream_output_events.iter().cloned());
            input_runs.push(VulkanResidentInProcessPlacedPromptEngineInputRun {
                stream_id: stream_id.clone(),
                submitted_run,
                output_events: stream_output_events,
                generated_token_ids: stream_generated_token_ids,
            });
            if stream_still_active {
                self.active_queue.push_back(stream_id);
            }
        }

        let end_snapshot = self.snapshot();
        let generated_token_ids = output_events
            .iter()
            .map(|event| event.output_event.token_id)
            .collect::<Vec<_>>();
        let stop_condition = if end_snapshot.idle {
            VulkanResidentInProcessPlacedPromptEngineRunStopCondition::Idle
        } else {
            VulkanResidentInProcessPlacedPromptEngineRunStopCondition::InputEventBudget
        };

        Ok(VulkanResidentInProcessPlacedPromptEngineRun {
            max_input_events,
            stop_condition,
            processed_input_event_count: input_runs.len(),
            input_runs,
            output_events,
            generated_token_ids,
            start_snapshot,
            end_snapshot,
        })
    }

    pub fn snapshot(&self) -> VulkanResidentInProcessPlacedPromptEngineSnapshot {
        let streams = self
            .streams
            .iter()
            .map(|(stream_id, stream)| placed_prompt_engine_stream_snapshot(stream_id, stream))
            .collect::<Vec<_>>();
        let idle = streams.iter().all(|stream| stream.idle);
        let active_stream_ids = streams
            .iter()
            .filter(|stream| !stream.idle)
            .map(|stream| stream.stream_id.clone())
            .collect::<Vec<_>>();
        VulkanResidentInProcessPlacedPromptEngineSnapshot {
            stream_count: streams.len(),
            active_stream_count: active_stream_ids.len(),
            active_stream_ids,
            idle,
            streams,
        }
    }

    fn activate_stream_id(&mut self, stream_id: &str) {
        if !self.active_queue.iter().any(|active| active == stream_id) {
            self.active_queue.push_back(stream_id.to_string());
        }
    }

    fn refresh_active_queue(&mut self) {
        let active_stream_ids = self
            .streams
            .iter()
            .filter(|(_, stream)| !stream.is_idle())
            .map(|(stream_id, _)| stream_id.clone())
            .collect::<Vec<_>>();
        for stream_id in active_stream_ids {
            self.activate_stream_id(&stream_id);
        }
    }
}

