pub struct VulkanResidentTokenEngineTextCycleRun {
    pub scheduler_run: VulkanResidentTokenRuntimeSchedulerRun,
    pub output_events: Vec<VulkanResidentTokenEngineTextOutputEvent>,
    pub generated_token_ids: Vec<u32>,
    pub generated_text: String,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentTokenEngineTextOutputEvent {
    pub stream_id: String,
    pub input_event_id: String,
    pub output_index: usize,
    pub token_id: u32,
    pub text: String,
    pub source_stream_tick: u64,
}

pub trait VulkanResidentTokenTextCodec {
    fn encode_text(&self, text: &str) -> Result<Vec<u32>, VulkanResidentTokenTextCodecError>;

    fn decode_tokens(&self, token_ids: &[u32])
    -> Result<String, VulkanResidentTokenTextCodecError>;
}

#[cfg(feature = "tokenizers")]
pub struct VulkanResidentHfTokenizerTextCodec {
    tokenizer: tokenizers::Tokenizer,
    add_special_tokens: bool,
    skip_special_tokens: bool,
}

#[cfg(feature = "tokenizers")]
pub struct VulkanResidentHfTokenDecodeStream<'a> {
    stream: tokenizers::DecodeStream<
        'a,
        tokenizers::models::ModelWrapper,
        tokenizers::normalizers::NormalizerWrapper,
        tokenizers::pre_tokenizers::PreTokenizerWrapper,
        tokenizers::processors::PostProcessorWrapper,
        tokenizers::decoders::DecoderWrapper,
    >,
}

#[cfg(feature = "tokenizers")]
impl VulkanResidentHfTokenDecodeStream<'_> {
    pub fn step(
        &mut self,
        token_id: u32,
    ) -> Result<Option<String>, VulkanResidentTokenTextCodecError> {
        self.stream.step(token_id).map_err(|error| {
            VulkanResidentTokenTextCodecError::new(format!(
                "failed to incrementally decode token id {token_id}: {error}"
            ))
        })
    }
}

#[cfg(feature = "tokenizers")]
impl VulkanResidentHfTokenizerTextCodec {
    pub fn from_model_dir(
        model_dir: impl AsRef<Path>,
    ) -> Result<Self, VulkanResidentTokenTextCodecError> {
        Self::from_file(model_dir.as_ref().join("tokenizer.json"))
    }

    pub fn from_file(
        tokenizer_path: impl AsRef<Path>,
    ) -> Result<Self, VulkanResidentTokenTextCodecError> {
        let tokenizer_path = tokenizer_path.as_ref();
        let tokenizer = tokenizers::Tokenizer::from_file(tokenizer_path).map_err(|error| {
            VulkanResidentTokenTextCodecError::new(format!(
                "failed to load tokenizer file {:?}: {error}",
                tokenizer_path
            ))
        })?;
        Ok(Self {
            tokenizer,
            add_special_tokens: true,
            skip_special_tokens: true,
        })
    }

    pub fn with_add_special_tokens(mut self, add_special_tokens: bool) -> Self {
        self.add_special_tokens = add_special_tokens;
        self
    }

    pub fn with_skip_special_tokens(mut self, skip_special_tokens: bool) -> Self {
        self.skip_special_tokens = skip_special_tokens;
        self
    }

    pub fn add_special_tokens(&self) -> bool {
        self.add_special_tokens
    }

    pub fn skip_special_tokens(&self) -> bool {
        self.skip_special_tokens
    }

    pub fn decode_stream(&self) -> VulkanResidentHfTokenDecodeStream<'_> {
        VulkanResidentHfTokenDecodeStream {
            stream: self.tokenizer.decode_stream(self.skip_special_tokens),
        }
    }
}

#[cfg(feature = "tokenizers")]
impl VulkanResidentTokenTextCodec for VulkanResidentHfTokenizerTextCodec {
    fn encode_text(&self, text: &str) -> Result<Vec<u32>, VulkanResidentTokenTextCodecError> {
        let encoding = self
            .tokenizer
            .encode(text, self.add_special_tokens)
            .map_err(|error| {
                VulkanResidentTokenTextCodecError::new(format!(
                    "failed to encode text with tokenizer: {error}"
                ))
            })?;
        Ok(encoding.get_ids().to_vec())
    }

    fn decode_tokens(
        &self,
        token_ids: &[u32],
    ) -> Result<String, VulkanResidentTokenTextCodecError> {
        self.tokenizer
            .decode(token_ids, self.skip_special_tokens)
            .map_err(|error| {
                VulkanResidentTokenTextCodecError::new(format!(
                    "failed to decode token ids with tokenizer: {error}"
                ))
            })
    }
}

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct VulkanResidentTokenIdTextCodec;

impl VulkanResidentTokenTextCodec for VulkanResidentTokenIdTextCodec {
    fn encode_text(&self, text: &str) -> Result<Vec<u32>, VulkanResidentTokenTextCodecError> {
        let mut tokens = Vec::new();
        for fragment in text
            .split(|character: char| character == ',' || character.is_whitespace())
            .filter(|fragment| !fragment.is_empty())
        {
            tokens.push(fragment.parse::<u32>().map_err(|error| {
                VulkanResidentTokenTextCodecError::new(format!(
                    "invalid numeric token fragment {fragment:?}: {error}"
                ))
            })?);
        }

        if tokens.is_empty() {
            return Err(VulkanResidentTokenTextCodecError::new(
                "numeric token text must contain at least one token id",
            ));
        }

        Ok(tokens)
    }

    fn decode_tokens(
        &self,
        token_ids: &[u32],
    ) -> Result<String, VulkanResidentTokenTextCodecError> {
        Ok(token_ids
            .iter()
            .map(u32::to_string)
            .collect::<Vec<_>>()
            .join(" "))
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentTokenTextCodecError {
    message: String,
}

impl VulkanResidentTokenTextCodecError {
    pub fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
        }
    }
}

impl Display for VulkanResidentTokenTextCodecError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.message)
    }
}

impl Error for VulkanResidentTokenTextCodecError {}

#[derive(Debug)]
pub enum VulkanResidentTokenEngineError {
    Device(VulkanError),
    Build(VulkanResidentTokenModelPackageError),
    Scheduler(VulkanResidentTokenRuntimeSchedulerError),
    TextCodec(VulkanResidentTokenTextCodecError),
    DuplicateModel(String),
    UnknownModel(String),
    RunCycleCountOverflow,
    RunStalled,
}

impl Display for VulkanResidentTokenEngineError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Device(error) => Display::fmt(error, f),
            Self::Build(error) => Display::fmt(error, f),
            Self::Scheduler(error) => Display::fmt(error, f),
            Self::TextCodec(error) => Display::fmt(error, f),
            Self::DuplicateModel(model_id) => {
                write!(
                    f,
                    "resident token engine model {model_id:?} is already loaded"
                )
            }
            Self::UnknownModel(model_id) => {
                write!(f, "resident token engine model {model_id:?} is not loaded")
            }
            Self::RunCycleCountOverflow => {
                f.write_str("resident token engine run cycle count overflowed")
            }
            Self::RunStalled => f.write_str(
                "resident token engine run stalled while scheduler still had active runtimes",
            ),
        }
    }
}

impl Error for VulkanResidentTokenEngineError {}

impl From<VulkanError> for VulkanResidentTokenEngineError {
    fn from(error: VulkanError) -> Self {
        Self::Device(error)
    }
}

impl From<VulkanResidentTokenModelPackageError> for VulkanResidentTokenEngineError {
    fn from(error: VulkanResidentTokenModelPackageError) -> Self {
        Self::Build(error)
    }
}

impl From<VulkanResidentTokenRuntimeSchedulerError> for VulkanResidentTokenEngineError {
    fn from(error: VulkanResidentTokenRuntimeSchedulerError) -> Self {
        Self::Scheduler(error)
    }
}

impl From<VulkanResidentTokenTextCodecError> for VulkanResidentTokenEngineError {
    fn from(error: VulkanResidentTokenTextCodecError) -> Self {
        Self::TextCodec(error)
    }
}

pub struct VulkanMountedPlacedResidentPedalRunner {
    pub pedal_id: String,
    pub dispatches: Vec<VulkanMountedPlacedResidentPedalDispatch>,
    pub total_descriptor_count: usize,
    pub total_push_constant_byte_count: u32,
    stream_control_buffer: Arc<VulkanResidentBuffer>,
}

impl VulkanMountedPlacedResidentPedalRunner {
    fn from_mounted_bound_plan(
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        pedal_id: &str,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
    ) -> Result<Self, VulkanMountedPlacedResidentKernelDispatchError> {
        let mut dispatches = Vec::new();
        let mut total_descriptor_count = 0usize;
        let mut total_push_constant_byte_count = 0u32;

        for dispatch in mounted_bound_plan
            .dispatches
            .iter()
            .filter(|dispatch| dispatch.pedal_id == pedal_id)
        {
            let resident_dispatch = mounted.create_resident_kernel_dispatch_for_bound_dispatch(
                device,
                dispatch,
                loaded_manifest,
            )?;
            total_descriptor_count = total_descriptor_count
                .checked_add(resident_dispatch.descriptor_count())
                .ok_or(VulkanMountedPlacedResidentKernelDispatchError::PedalRunnerDescriptorCountOverflow {
                    pedal_id: pedal_id.to_string(),
                })?;
            total_push_constant_byte_count = total_push_constant_byte_count
                .checked_add(resident_dispatch.push_constant_byte_count())
                .ok_or(VulkanMountedPlacedResidentKernelDispatchError::PedalRunnerPushConstantByteCountOverflow {
                    pedal_id: pedal_id.to_string(),
                })?;
            dispatches.push(VulkanMountedPlacedResidentPedalDispatch {
                dispatch_index: dispatch.dispatch_index,
                kernel_id: dispatch.kernel_id.clone(),
                pedal_id: dispatch.pedal_id.clone(),
                node_id: dispatch.node_id.clone(),
                op: dispatch.op.clone(),
                reusable_family_id: dispatch.reusable_family_id.clone(),
                push_constants: dispatch.push_constants.clone(),
                resident_dispatch,
            });
        }

        if dispatches.is_empty() {
            return Err(
                VulkanMountedPlacedResidentKernelDispatchError::MissingPedalDispatches {
                    pedal_id: pedal_id.to_string(),
                },
            );
        }

        Ok(Self {
            pedal_id: pedal_id.to_string(),
            dispatches,
            total_descriptor_count,
            total_push_constant_byte_count,
            stream_control_buffer: mounted.stream_control_buffer.clone(),
        })
    }

    pub fn dispatch_count(&self) -> usize {
        self.dispatches.len()
    }

    pub fn run_zeroed_push_constants(
        &self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanMountedPlacedResidentPedalRun, VulkanMountedPlacedResidentKernelDispatchError>
    {
        self.run_with_push_constant_bytes(device, |dispatch| {
            Ok(vec![
                0u8;
                dispatch.resident_dispatch.push_constant_byte_count()
                    as usize
            ])
        })
    }

    pub fn run_with_stream_control(
        &self,
        device: &VulkanComputeDevice,
        control: VulkanMountedPlacedStreamControl,
    ) -> Result<VulkanMountedPlacedResidentPedalRun, VulkanMountedPlacedResidentKernelDispatchError>
    {
        self.stream_control_buffer
            .write_bytes_at(
                VULKAN_STREAM_CONTROL_METADATA_OFFSET,
                &stream_control_metadata_bytes(control),
            )
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
        self.run_with_push_constant_bytes(device, |dispatch| {
            stream_control_push_constant_bytes(&dispatch.push_constants, control)
        })
    }

    fn run_with_push_constant_bytes<F>(
        &self,
        device: &VulkanComputeDevice,
        mut push_constant_bytes_for: F,
    ) -> Result<VulkanMountedPlacedResidentPedalRun, VulkanMountedPlacedResidentKernelDispatchError>
    where
        F: FnMut(
            &VulkanMountedPlacedResidentPedalDispatch,
        ) -> Result<Vec<u8>, VulkanMountedPlacedResidentKernelDispatchError>,
    {
        let mut dispatch_runs = Vec::with_capacity(self.dispatches.len());
        for dispatch in &self.dispatches {
            let push_constants = push_constant_bytes_for(dispatch)?;
            let run_start = Instant::now();
            device
                .run_resident_kernel_dispatch(&dispatch.resident_dispatch, &push_constants)
                .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
            let run_time_ns = u64::try_from(run_start.elapsed().as_nanos()).unwrap_or(u64::MAX);
            dispatch_runs.push(VulkanMountedPlacedResidentPedalDispatchRun {
                dispatch_index: dispatch.dispatch_index,
                kernel_id: dispatch.kernel_id.clone(),
                node_id: dispatch.node_id.clone(),
                op: dispatch.op.clone(),
                reusable_family_id: dispatch.reusable_family_id.clone(),
                descriptor_count: dispatch.resident_dispatch.descriptor_count(),
                workgroup_count_x: dispatch.resident_dispatch.workgroup_count_x(),
                push_constant_byte_count: dispatch.resident_dispatch.push_constant_byte_count(),
                run_time_ns,
            });
        }

        Ok(VulkanMountedPlacedResidentPedalRun {
            pedal_id: self.pedal_id.clone(),
            dispatch_runs,
        })
    }

    fn completed_sequence_run(&self) -> VulkanMountedPlacedResidentPedalRun {
        VulkanMountedPlacedResidentPedalRun {
            pedal_id: self.pedal_id.clone(),
            dispatch_runs: self
                .dispatches
                .iter()
                .map(|dispatch| VulkanMountedPlacedResidentPedalDispatchRun {
                    dispatch_index: dispatch.dispatch_index,
                    kernel_id: dispatch.kernel_id.clone(),
                    node_id: dispatch.node_id.clone(),
                    op: dispatch.op.clone(),
                    reusable_family_id: dispatch.reusable_family_id.clone(),
                    descriptor_count: dispatch.resident_dispatch.descriptor_count(),
                    workgroup_count_x: dispatch.resident_dispatch.workgroup_count_x(),
                    push_constant_byte_count: dispatch.resident_dispatch.push_constant_byte_count(),
                    // The composed sequence has one measurable execution boundary.
                    // Per-dispatch timings would be fabricated without timestamp queries.
                    run_time_ns: 0,
                })
                .collect(),
        }
    }
}

pub struct VulkanMountedPlacedResidentPedalDispatch {
    pub dispatch_index: usize,
    pub kernel_id: String,
    pub pedal_id: String,
    pub node_id: String,
    pub op: String,
    pub reusable_family_id: String,
    pub push_constants: Vec<VulkanKernelScalarBinding>,
    pub resident_dispatch: VulkanResidentKernelDispatch,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentPedalRun {
    pub pedal_id: String,
    pub dispatch_runs: Vec<VulkanMountedPlacedResidentPedalDispatchRun>,
}

impl VulkanMountedPlacedResidentPedalRun {
    pub fn dispatch_count(&self) -> usize {
        self.dispatch_runs.len()
    }

    pub fn run_time_ns(&self) -> u64 {
        self.dispatch_runs.iter().fold(0u64, |total, dispatch| {
            total.saturating_add(dispatch.run_time_ns)
        })
    }

    pub fn node_ids(&self) -> Vec<&str> {
        self.dispatch_runs
            .iter()
            .map(|dispatch| dispatch.node_id.as_str())
            .collect()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentPedalDispatchRun {
    pub dispatch_index: usize,
    pub kernel_id: String,
    pub node_id: String,
    pub op: String,
    pub reusable_family_id: String,
    pub descriptor_count: usize,
    pub workgroup_count_x: u32,
    pub push_constant_byte_count: u32,
    pub run_time_ns: u64,
}

pub struct VulkanMountedPlacedResidentPedalboardRunner {
    pub device_id: String,
    pub pedals: Vec<VulkanMountedPlacedResidentPedalRunner>,
    pub total_descriptor_count: usize,
    pub total_push_constant_byte_count: u32,
}

impl VulkanMountedPlacedResidentPedalboardRunner {
    fn from_mounted_bound_plan<I, S>(
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        pedal_ids: I,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
    ) -> Result<Self, VulkanMountedPlacedResidentKernelDispatchError>
    where
        I: IntoIterator<Item = S>,
        S: AsRef<str>,
    {
        let mut pedals = Vec::new();
        let mut total_descriptor_count = 0usize;
        let mut total_push_constant_byte_count = 0u32;

        for pedal_id in pedal_ids {
            let pedal_id = pedal_id.as_ref();
            let runner = VulkanMountedPlacedResidentPedalRunner::from_mounted_bound_plan(
                device,
                mounted,
                mounted_bound_plan,
                pedal_id,
                loaded_manifest,
            )?;
            total_descriptor_count = total_descriptor_count
                .checked_add(runner.total_descriptor_count)
                .ok_or_else(|| {
                    VulkanMountedPlacedResidentKernelDispatchError::PedalboardRunnerDescriptorCountOverflow {
                        device_id: mounted_bound_plan.device_id.clone(),
                    }
                })?;
            total_push_constant_byte_count = total_push_constant_byte_count
                .checked_add(runner.total_push_constant_byte_count)
                .ok_or_else(|| {
                    VulkanMountedPlacedResidentKernelDispatchError::PedalboardRunnerPushConstantByteCountOverflow {
                        device_id: mounted_bound_plan.device_id.clone(),
                    }
                })?;
            pedals.push(runner);
        }

        if pedals.is_empty() {
            return Err(
                VulkanMountedPlacedResidentKernelDispatchError::MissingPedalboardPedals {
                    device_id: mounted_bound_plan.device_id.clone(),
                },
            );
        }

        Ok(Self {
            device_id: mounted_bound_plan.device_id.clone(),
            pedals,
            total_descriptor_count,
            total_push_constant_byte_count,
        })
    }

    pub fn pedal_count(&self) -> usize {
        self.pedals.len()
    }

    pub fn dispatch_count(&self) -> usize {
        self.pedals
            .iter()
            .map(VulkanMountedPlacedResidentPedalRunner::dispatch_count)
            .sum()
    }

    pub fn pedal_ids(&self) -> Vec<&str> {
        self.pedals
            .iter()
            .map(|pedal| pedal.pedal_id.as_str())
            .collect()
    }

    pub fn run_zeroed_push_constants(
        &self,
        device: &VulkanComputeDevice,
    ) -> Result<
        VulkanMountedPlacedResidentPedalboardRun,
        VulkanMountedPlacedResidentKernelDispatchError,
    > {
        let mut pedal_runs = Vec::with_capacity(self.pedals.len());
        for pedal in &self.pedals {
            pedal_runs.push(pedal.run_zeroed_push_constants(device)?);
        }

        Ok(VulkanMountedPlacedResidentPedalboardRun {
            device_id: self.device_id.clone(),
            pedal_runs,
        })
    }

    pub fn run_with_stream_control(
        &self,
        device: &VulkanComputeDevice,
        control: VulkanMountedPlacedStreamControl,
    ) -> Result<
        VulkanMountedPlacedResidentPedalboardRun,
        VulkanMountedPlacedResidentKernelDispatchError,
    > {
        let mut pedal_runs = Vec::with_capacity(self.pedals.len());
        for pedal in &self.pedals {
            pedal_runs.push(pedal.run_with_stream_control(device, control)?);
        }

        Ok(VulkanMountedPlacedResidentPedalboardRun {
            device_id: self.device_id.clone(),
            pedal_runs,
        })
    }

    fn completed_sequence_run(&self) -> VulkanMountedPlacedResidentPedalboardRun {
        VulkanMountedPlacedResidentPedalboardRun {
            device_id: self.device_id.clone(),
            pedal_runs: self
                .pedals
                .iter()
                .map(VulkanMountedPlacedResidentPedalRunner::completed_sequence_run)
                .collect(),
        }
    }
}

/// A maximal sequence of dispatch stages that can execute without crossing a
/// cable transport boundary. The sequence keeps its pipelines, descriptors,
/// command buffer, and fence resident for the lifetime of the mounted model.
pub struct VulkanMountedPlacedResidentDispatchSegmentRunner {
    pub start_stage_index: usize,
    pub end_stage_index: usize,
    pub dispatch_count: usize,
    dispatches: Vec<VulkanMountedPlacedResidentPedalDispatch>,
    stream_control_buffer: Arc<VulkanResidentBuffer>,
    sequences: RefCell<BTreeMap<u8, VulkanResidentKernelSequence>>,
}

impl VulkanMountedPlacedResidentDispatchSegmentRunner {
    fn from_dispatch_stages(
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
        stages: &[VulkanMountedPlacedStreamTickStage],
    ) -> Result<Self, VulkanMountedPlacedResidentKernelDispatchError> {
        let start_stage_index = stages
            .first()
            .map(VulkanMountedPlacedStreamTickStage::stage_index)
            .ok_or_else(|| {
                VulkanMountedPlacedResidentKernelDispatchError::EmptyDispatchSegment {
                    device_id: mounted.device_id().to_string(),
                }
            })?;
        let end_stage_index = stages
            .last()
            .map(VulkanMountedPlacedStreamTickStage::stage_index)
            .and_then(|index| index.checked_add(1))
            .ok_or_else(|| {
                VulkanMountedPlacedResidentKernelDispatchError::DispatchSegmentStageOverflow {
                    device_id: mounted.device_id().to_string(),
                }
            })?;
        let mut dispatches = Vec::with_capacity(stages.len());

        for stage in stages {
            let VulkanMountedPlacedStreamTickStage::Dispatch {
                stage_index,
                dispatch,
            } = stage
            else {
                return Err(
                    VulkanMountedPlacedResidentKernelDispatchError::NonDispatchStageInSegment {
                        device_id: mounted.device_id().to_string(),
                        stage_index: stage.stage_index(),
                    },
                );
            };
            let bound_dispatch = mounted_bound_plan
                .dispatches
                .iter()
                .find(|bound| bound.dispatch_index == dispatch.dispatch_index)
                .ok_or_else(|| {
                    VulkanMountedPlacedResidentKernelDispatchError::MissingSegmentDispatch {
                        device_id: mounted.device_id().to_string(),
                        stage_index: *stage_index,
                        dispatch_index: dispatch.dispatch_index,
                    }
                })?;
            let resident_dispatch = mounted.create_resident_kernel_dispatch_for_bound_dispatch(
                device,
                bound_dispatch,
                loaded_manifest,
            )?;
            dispatches.push(VulkanMountedPlacedResidentPedalDispatch {
                dispatch_index: bound_dispatch.dispatch_index,
                kernel_id: bound_dispatch.kernel_id.clone(),
                pedal_id: bound_dispatch.pedal_id.clone(),
                node_id: bound_dispatch.node_id.clone(),
                op: bound_dispatch.op.clone(),
                reusable_family_id: bound_dispatch.reusable_family_id.clone(),
                push_constants: bound_dispatch.push_constants.clone(),
                resident_dispatch,
            });
        }

        Ok(Self {
            start_stage_index,
            end_stage_index,
            dispatch_count: dispatches.len(),
            dispatches,
            stream_control_buffer: mounted.stream_control_buffer.clone(),
            sequences: RefCell::new(BTreeMap::from([(
                0,
                device
                    .create_resident_kernel_sequence()
                    .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?,
            )])),
        })
    }

    #[allow(clippy::too_many_arguments)]
    fn submit_with_stream_control_and_timeline_semaphores(
        &self,
        device: &VulkanComputeDevice,
        control: VulkanMountedPlacedStreamControl,
        prefix_dispatches: &[&VulkanResidentKernelDispatch],
        suffix_dispatches: &[&VulkanResidentKernelDispatch],
        sequence_variant: u8,
        wait_points: &[VulkanTimelineSemaphorePoint<'_>],
        signal_points: &[VulkanTimelineSemaphorePoint<'_>],
    ) -> Result<(), VulkanMountedPlacedResidentKernelDispatchError> {
        if !self.sequences.borrow().contains_key(&sequence_variant) {
            let sequence = device
                .create_resident_kernel_sequence()
                .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
            self.sequences
                .borrow_mut()
                .entry(sequence_variant)
                .or_insert(sequence);
        }
        let sequences = self.sequences.borrow();
        let sequence = sequences
            .get(&sequence_variant)
            .expect("resident sequence variant was initialized");
        if self.can_replay_recorded_commands(sequence, prefix_dispatches, suffix_dispatches) {
            return device
                .submit_recorded_resident_kernel_sequence_with_timeline_semaphores(
                    sequence,
                    wait_points,
                    signal_points,
                )
                .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan);
        }
        let push_constants = self
            .dispatches
            .iter()
            .map(|dispatch| stream_control_push_constant_bytes(&dispatch.push_constants, control))
            .collect::<Result<Vec<_>, _>>()?;
        let mut steps = Vec::with_capacity(
            prefix_dispatches.len() + self.dispatches.len() + suffix_dispatches.len(),
        );
        steps.extend(
            prefix_dispatches
                .iter()
                .map(|dispatch| VulkanResidentKernelSequenceStep::new(dispatch, &[])),
        );
        steps.extend(self.dispatches.iter().zip(&push_constants).map(
            |(dispatch, push_constants)| {
                VulkanResidentKernelSequenceStep::new(&dispatch.resident_dispatch, push_constants)
            },
        ));
        steps.extend(
            suffix_dispatches
                .iter()
                .map(|dispatch| VulkanResidentKernelSequenceStep::new(dispatch, &[])),
        );
        device
            .record_resident_kernel_sequence(sequence, &steps)
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
        device
            .submit_recorded_resident_kernel_sequence_with_timeline_semaphores(
                sequence,
                wait_points,
                signal_points,
            )
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)
    }

    fn can_replay_recorded_commands(
        &self,
        sequence: &VulkanResidentKernelSequence,
        prefix_dispatches: &[&VulkanResidentKernelDispatch],
        suffix_dispatches: &[&VulkanResidentKernelDispatch],
    ) -> bool {
        std::env::var_os("LLMOOP_VK_PERF_LOGGER").is_none()
            && sequence.has_recorded_commands()
            && self
                .dispatches
                .iter()
                .all(|dispatch| dispatch.push_constants.is_empty())
            && prefix_dispatches
                .iter()
                .all(|dispatch| dispatch.push_constant_byte_count() == 0)
            && suffix_dispatches
                .iter()
                .all(|dispatch| dispatch.push_constant_byte_count() == 0)
    }

    fn wait_submitted(
        &self,
        device: &VulkanComputeDevice,
        sequence_variant: u8,
    ) -> Result<(), VulkanMountedPlacedResidentKernelDispatchError> {
        let sequences = self.sequences.borrow();
        let sequence = sequences
            .get(&sequence_variant)
            .expect("submitted resident sequence variant must remain mounted");
        device
            .wait_resident_kernel_sequence(sequence)
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)
    }

    fn run_with_stream_control(
        &self,
        device: &VulkanComputeDevice,
        control: VulkanMountedPlacedStreamControl,
        prefix_dispatches: &[&VulkanResidentKernelDispatch],
        suffix_dispatches: &[&VulkanResidentKernelDispatch],
        sequence_variant: u8,
        capture_execution_trace: bool,
    ) -> Result<
        Vec<VulkanMountedPlacedResidentPedalRun>,
        VulkanMountedPlacedResidentKernelDispatchError,
    > {
        self.stream_control_buffer
            .write_bytes_at(
                VULKAN_STREAM_CONTROL_METADATA_OFFSET,
                &stream_control_metadata_bytes(control),
            )
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;

        if !self.sequences.borrow().contains_key(&sequence_variant) {
            let sequence = device
                .create_resident_kernel_sequence()
                .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
            self.sequences
                .borrow_mut()
                .entry(sequence_variant)
                .or_insert(sequence);
        }
        let sequences = self.sequences.borrow();
        let sequence = sequences
            .get(&sequence_variant)
            .expect("resident sequence variant was initialized");

        let execution_start = capture_execution_trace.then(Instant::now);
        if self.can_replay_recorded_commands(sequence, prefix_dispatches, suffix_dispatches) {
            device
                .run_recorded_resident_kernel_sequence(sequence)
                .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
            return Ok(execution_start
                .map(|start| {
                    let execution_time_ns =
                        u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX);
                    self.completed_pedal_runs(execution_time_ns)
                })
                .unwrap_or_default());
        }

        let push_constants = self
            .dispatches
            .iter()
            .map(|dispatch| stream_control_push_constant_bytes(&dispatch.push_constants, control))
            .collect::<Result<Vec<_>, _>>()?;
        let mut steps = Vec::with_capacity(
            prefix_dispatches.len() + self.dispatches.len() + suffix_dispatches.len(),
        );
        steps.extend(
            prefix_dispatches
                .iter()
                .map(|dispatch| VulkanResidentKernelSequenceStep::new(dispatch, &[])),
        );
        steps.extend(self.dispatches.iter().zip(&push_constants).map(
            |(dispatch, push_constants)| {
                VulkanResidentKernelSequenceStep::new(&dispatch.resident_dispatch, push_constants)
            },
        ));
        steps.extend(
            suffix_dispatches
                .iter()
                .map(|dispatch| VulkanResidentKernelSequenceStep::new(dispatch, &[])),
        );
        device
            .run_resident_kernel_sequence(sequence, &steps)
            .map_err(VulkanMountedPlacedResidentKernelDispatchError::Vulkan)?;
        Ok(execution_start
            .map(|start| {
                let execution_time_ns =
                    u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX);
                self.completed_pedal_runs(execution_time_ns)
            })
            .unwrap_or_default())
    }

    fn completed_pedal_runs(
        &self,
        execution_time_ns: u64,
    ) -> Vec<VulkanMountedPlacedResidentPedalRun> {
        let mut pedal_runs = Vec::<VulkanMountedPlacedResidentPedalRun>::new();
        for (dispatch_offset, dispatch) in self.dispatches.iter().enumerate() {
            let dispatch_run = VulkanMountedPlacedResidentPedalDispatchRun {
                dispatch_index: dispatch.dispatch_index,
                kernel_id: dispatch.kernel_id.clone(),
                node_id: dispatch.node_id.clone(),
                op: dispatch.op.clone(),
                reusable_family_id: dispatch.reusable_family_id.clone(),
                descriptor_count: dispatch.resident_dispatch.descriptor_count(),
                workgroup_count_x: dispatch.resident_dispatch.workgroup_count_x(),
                push_constant_byte_count: dispatch.resident_dispatch.push_constant_byte_count(),
                // A composed segment has one measurable execution boundary.
                run_time_ns: if dispatch_offset == 0 {
                    execution_time_ns
                } else {
                    0
                },
            };
            if let Some(pedal_run) = pedal_runs
                .last_mut()
                .filter(|run| run.pedal_id == dispatch.pedal_id)
            {
                pedal_run.dispatch_runs.push(dispatch_run);
            } else {
                pedal_runs.push(VulkanMountedPlacedResidentPedalRun {
                    pedal_id: dispatch.pedal_id.clone(),
                    dispatch_runs: vec![dispatch_run],
                });
            }
        }
        pedal_runs
    }
}

/// Resident execution structure for one placed device slice. Cable stages stay
/// visible to the scheduler, while every uninterrupted dispatch region becomes
/// one GPU submission.
pub struct VulkanMountedPlacedResidentStreamTickExecutionPlan {
    pub tick_plan: Arc<VulkanMountedPlacedStreamTickPlan>,
    pub dispatch_segment_count: usize,
    pub dispatch_count: usize,
    pub distributed_dispatch_count: usize,
    dispatch_segments: Vec<VulkanMountedPlacedResidentDispatchSegmentRunner>,
    distributed_dispatch_stages: BTreeMap<usize, VulkanMountedPlacedStreamTickDispatch>,
    distributed_dispatch_dependencies:
        BTreeMap<usize, VulkanMountedPlacedDistributedDispatchDependencies>,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct VulkanMountedPlacedDistributedDispatchDependencies {
    dispatch_index: usize,
    has_owner_producer: bool,
    has_owner_continuation: bool,
}

impl VulkanMountedPlacedResidentStreamTickExecutionPlan {
    pub fn from_tick_plan(
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
        tick_plan: VulkanMountedPlacedStreamTickPlan,
    ) -> Result<Self, VulkanMountedPlacedResidentKernelDispatchError> {
        Self::from_tick_plan_with_distributed_dispatches(
            device,
            mounted,
            mounted_bound_plan,
            loaded_manifest,
            tick_plan,
            &BTreeSet::new(),
        )
    }

    pub fn from_tick_plan_with_distributed_dispatches(
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
        tick_plan: VulkanMountedPlacedStreamTickPlan,
        distributed_dispatch_indices: &BTreeSet<usize>,
    ) -> Result<Self, VulkanMountedPlacedResidentKernelDispatchError> {
        if tick_plan.device_id != mounted.device_id() {
            return Err(
                VulkanMountedPlacedResidentKernelDispatchError::ExecutionPlanDeviceMismatch {
                    plan_device_id: tick_plan.device_id.clone(),
                    mounted_device_id: mounted.device_id().to_string(),
                },
            );
        }
        if tick_plan.device_id != mounted_bound_plan.device_id {
            return Err(
                VulkanMountedPlacedResidentKernelDispatchError::ExecutionBoundPlanDeviceMismatch {
                    plan_device_id: tick_plan.device_id.clone(),
                    bound_plan_device_id: mounted_bound_plan.device_id.clone(),
                },
            );
        }

        let distributed_dispatch_stages =
            distributed_dispatch_stages(&tick_plan, distributed_dispatch_indices)?;

        let dispatch_segment_stage_ranges =
            resident_dispatch_segment_stage_ranges_excluding_dispatches(
                &tick_plan.stages,
                distributed_dispatch_indices,
            );
        let distributed_dispatch_dependencies = distributed_dispatch_dependency_topologies(
            &distributed_dispatch_stages,
            &dispatch_segment_stage_ranges,
        );
        let mut dispatch_segments = Vec::new();
        for &(start, end) in &dispatch_segment_stage_ranges {
            dispatch_segments.push(
                VulkanMountedPlacedResidentDispatchSegmentRunner::from_dispatch_stages(
                    device,
                    mounted,
                    mounted_bound_plan,
                    loaded_manifest,
                    &tick_plan.stages[start..end],
                )?,
            );
        }
        if dispatch_segments.is_empty() && distributed_dispatch_stages.is_empty() {
            return Err(
                VulkanMountedPlacedResidentKernelDispatchError::MissingExecutionDispatchSegments {
                    device_id: tick_plan.device_id.clone(),
                },
            );
        }
        let dispatch_count = dispatch_segments
            .iter()
            .map(|segment| segment.dispatch_count)
            .sum();
        let dispatch_segment_count = dispatch_segments.len();
        let distributed_dispatch_count = distributed_dispatch_stages.len();
        Ok(Self {
            tick_plan: Arc::new(tick_plan),
            dispatch_segment_count,
            dispatch_count,
            distributed_dispatch_count,
            dispatch_segments,
            distributed_dispatch_stages,
            distributed_dispatch_dependencies,
        })
    }

    fn segment_starting_at(
        &self,
        stage_index: usize,
    ) -> Option<&VulkanMountedPlacedResidentDispatchSegmentRunner> {
        self.dispatch_segments
            .iter()
            .find(|segment| segment.start_stage_index == stage_index)
    }

    fn first_dispatch_segment_stage_index(&self) -> Option<usize> {
        self.dispatch_segments
            .first()
            .map(|segment| segment.start_stage_index)
    }

    fn last_dispatch_segment_stage_index(&self) -> Option<usize> {
        self.dispatch_segments
            .last()
            .map(|segment| segment.start_stage_index)
    }

    pub fn distributed_dispatch_at_stage(
        &self,
        stage_index: usize,
    ) -> Option<&VulkanMountedPlacedStreamTickDispatch> {
        self.distributed_dispatch_stages.get(&stage_index)
    }

    fn distributed_dispatch_dependencies_at_stage(
        &self,
        stage_index: usize,
    ) -> Option<VulkanMountedPlacedDistributedDispatchDependencies> {
        self.distributed_dispatch_dependencies
            .get(&stage_index)
            .copied()
    }

    fn resident_stream_tick_cursor(
        &self,
        stream_tick: u64,
    ) -> VulkanMountedPlacedResidentStreamTickCursor {
        VulkanMountedPlacedResidentStreamTickCursor::new_shared(
            Arc::clone(&self.tick_plan),
            stream_tick,
            true,
        )
    }

    fn compact_resident_stream_tick_cursor(
        &self,
        stream_tick: u64,
    ) -> VulkanMountedPlacedResidentStreamTickCursor {
        VulkanMountedPlacedResidentStreamTickCursor::new_shared(
            Arc::clone(&self.tick_plan),
            stream_tick,
            false,
        )
    }
}

fn distributed_dispatch_dependency_topologies(
    distributed_dispatch_stages: &BTreeMap<usize, VulkanMountedPlacedStreamTickDispatch>,
    dispatch_segment_stage_ranges: &[(usize, usize)],
) -> BTreeMap<usize, VulkanMountedPlacedDistributedDispatchDependencies> {
    distributed_dispatch_stages
        .iter()
        .map(|(stage_index, dispatch)| {
            (
                *stage_index,
                VulkanMountedPlacedDistributedDispatchDependencies {
                    dispatch_index: dispatch.dispatch_index,
                    has_owner_producer: dispatch_segment_stage_ranges
                        .iter()
                        .any(|(_, end)| end == stage_index),
                    has_owner_continuation: stage_index.checked_add(1).is_some_and(
                        |next_stage_index| {
                            dispatch_segment_stage_ranges
                                .iter()
                                .any(|(start, _)| *start == next_stage_index)
                        },
                    ),
                },
            )
        })
        .collect()
}

#[cfg(test)]
fn resident_dispatch_segment_stage_ranges(
    stages: &[VulkanMountedPlacedStreamTickStage],
) -> Vec<(usize, usize)> {
    resident_dispatch_segment_stage_ranges_excluding_dispatches(stages, &BTreeSet::new())
}

fn resident_dispatch_segment_stage_ranges_excluding_dispatches(
    stages: &[VulkanMountedPlacedStreamTickStage],
    excluded_dispatch_indices: &BTreeSet<usize>,
) -> Vec<(usize, usize)> {
    let mut ranges = Vec::new();
    let mut stage_index = 0usize;
    while stage_index < stages.len() {
        if !is_canonical_dispatch_stage(&stages[stage_index], excluded_dispatch_indices) {
            stage_index += 1;
            continue;
        }
        let start = stage_index;
        while stage_index < stages.len()
            && is_canonical_dispatch_stage(&stages[stage_index], excluded_dispatch_indices)
        {
            stage_index += 1;
        }
        ranges.push((start, stage_index));
    }
    ranges
}

fn is_canonical_dispatch_stage(
    stage: &VulkanMountedPlacedStreamTickStage,
    excluded_dispatch_indices: &BTreeSet<usize>,
) -> bool {
    matches!(
        stage,
        VulkanMountedPlacedStreamTickStage::Dispatch { dispatch, .. }
            if !excluded_dispatch_indices.contains(&dispatch.dispatch_index)
    )
}

fn distributed_dispatch_stages(
    tick_plan: &VulkanMountedPlacedStreamTickPlan,
    distributed_dispatch_indices: &BTreeSet<usize>,
) -> Result<
    BTreeMap<usize, VulkanMountedPlacedStreamTickDispatch>,
    VulkanMountedPlacedResidentKernelDispatchError,
> {
    let mut stages = BTreeMap::new();
    let mut found = BTreeSet::new();
    for stage in &tick_plan.stages {
        let VulkanMountedPlacedStreamTickStage::Dispatch {
            stage_index,
            dispatch,
        } = stage
        else {
            continue;
        };
        if distributed_dispatch_indices.contains(&dispatch.dispatch_index) {
            found.insert(dispatch.dispatch_index);
            stages.insert(*stage_index, dispatch.clone());
        }
    }
    if let Some(dispatch_index) = distributed_dispatch_indices.difference(&found).next() {
        return Err(
            VulkanMountedPlacedResidentKernelDispatchError::MissingDistributedDispatchStage {
                device_id: tick_plan.device_id.clone(),
                dispatch_index: *dispatch_index,
            },
        );
    }
    Ok(stages)
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentPedalboardRun {
    pub device_id: String,
    pub pedal_runs: Vec<VulkanMountedPlacedResidentPedalRun>,
}

impl VulkanMountedPlacedResidentPedalboardRun {
    pub fn pedal_count(&self) -> usize {
        self.pedal_runs.len()
    }

    pub fn dispatch_count(&self) -> usize {
        self.pedal_runs
            .iter()
            .map(VulkanMountedPlacedResidentPedalRun::dispatch_count)
            .sum()
    }

    pub fn run_time_ns(&self) -> u64 {
        self.pedal_runs.iter().fold(0u64, |total, pedal| {
            total.saturating_add(pedal.run_time_ns())
        })
    }

    pub fn pedal_ids(&self) -> Vec<&str> {
        self.pedal_runs
            .iter()
            .map(|pedal| pedal.pedal_id.as_str())
            .collect()
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedStreamControl {
    pub stream_tick: u64,
    pub control_flags: u32,
    pub dynamic_state_capacity_activations: u32,
}

fn stream_control_bytes(
    token_id: u32,
    control: VulkanMountedPlacedStreamControl,
) -> [u8; VULKAN_STREAM_CONTROL_BYTE_CAPACITY] {
    let mut bytes = [0; VULKAN_STREAM_CONTROL_BYTE_CAPACITY];
    bytes[0..4].copy_from_slice(&token_id.to_le_bytes());
    bytes[4..12].copy_from_slice(&control.stream_tick.to_le_bytes());
    bytes[12..16].copy_from_slice(&control.control_flags.to_le_bytes());
    bytes[16..20].copy_from_slice(&control.dynamic_state_capacity_activations.to_le_bytes());
    bytes
}

fn stream_control_metadata_bytes(
    control: VulkanMountedPlacedStreamControl,
) -> [u8; VULKAN_STREAM_CONTROL_BYTE_CAPACITY - VULKAN_STREAM_CONTROL_METADATA_OFFSET] {
    let mut bytes =
        [0; VULKAN_STREAM_CONTROL_BYTE_CAPACITY - VULKAN_STREAM_CONTROL_METADATA_OFFSET];
    bytes[0..8].copy_from_slice(&control.stream_tick.to_le_bytes());
    bytes[8..12].copy_from_slice(&control.control_flags.to_le_bytes());
    bytes[12..16].copy_from_slice(&control.dynamic_state_capacity_activations.to_le_bytes());
    bytes
}

fn pedal_batch_control_bytes(
    batch_width: u32,
    start_stream_tick: u64,
    dynamic_state_capacity_activations: u32,
) -> [u8; VULKAN_PEDAL_BATCH_CONTROL_BYTE_CAPACITY as usize] {
    let mut bytes = [0; VULKAN_PEDAL_BATCH_CONTROL_BYTE_CAPACITY as usize];
    bytes[0..4].copy_from_slice(&batch_width.to_le_bytes());
    bytes[4..12].copy_from_slice(&start_stream_tick.to_le_bytes());
    bytes[12..16].copy_from_slice(&dynamic_state_capacity_activations.to_le_bytes());
    bytes
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanKernelInterfacePlan {
    pub backend_id: String,
    pub circuits: Vec<VulkanCircuitKernelInterface>,
}

impl VulkanKernelInterfacePlan {
    pub fn from_binding_plan(binding_plan: &VulkanStreamCircuitBindingPlan) -> Self {
        Self {
            backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
            circuits: binding_plan
                .circuits
                .iter()
                .map(VulkanCircuitKernelInterface::from_binding_plan)
                .collect(),
        }
    }

    pub fn total_kernel_count(&self) -> usize {
        self.circuits
            .iter()
            .map(|circuit| circuit.kernels.len())
            .sum()
    }

    pub fn kernel(&self, pedal_id: &str, node_id: &str) -> Option<&VulkanKernelInterface> {
        self.circuits
            .iter()
            .find(|circuit| circuit.pedal_id == pedal_id)
            .and_then(|circuit| circuit.kernel(node_id))
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanCircuitKernelInterface {
    pub pedal_id: String,
    pub circuit_id: String,
    pub kernels: Vec<VulkanKernelInterface>,
}

impl VulkanCircuitKernelInterface {
    fn from_binding_plan(circuit: &VulkanCircuitBindingPlan) -> Self {
        Self {
            pedal_id: circuit.pedal_id.clone(),
            circuit_id: circuit.circuit_id.clone(),
            kernels: circuit
                .nodes
                .iter()
                .map(|node| VulkanKernelInterface::from_node_binding(&circuit.pedal_id, node))
                .collect(),
        }
    }

    pub fn kernel(&self, node_id: &str) -> Option<&VulkanKernelInterface> {
        self.kernels.iter().find(|kernel| kernel.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanKernelInterface {
    pub kernel_id: String,
    pub pedal_id: String,
    pub node_index: usize,
    pub node_id: String,
    pub op: String,
    pub specialization: String,
    pub inputs: Vec<VulkanSignalBinding>,
    pub outputs: Vec<VulkanSignalBinding>,
    pub parameters: Vec<VulkanParameterBinding>,
    pub state_reads: Vec<VulkanStateBinding>,
    pub state_writes: Vec<VulkanStateBinding>,
    pub state_views: Vec<VulkanSignalBinding>,
    pub stream_metadata: VulkanKernelStreamMetadata,
}

impl VulkanKernelInterface {
    fn from_node_binding(pedal_id: &str, node: &VulkanNodeBinding) -> Self {
        let state_views = node
            .inputs
            .iter()
            .chain(&node.outputs)
            .filter(|binding| matches!(binding.resource, VulkanSignalResource::StateView { .. }))
            .cloned()
            .collect();

        Self {
            kernel_id: format!("{}.{}", pedal_id, node.node_id),
            pedal_id: pedal_id.to_string(),
            node_index: node.node_index,
            node_id: node.node_id.clone(),
            op: node.op.clone(),
            specialization: node.specialization.clone(),
            inputs: node.inputs.clone(),
            outputs: node.outputs.clone(),
            parameters: node.parameters.clone(),
            state_reads: node.state_reads.clone(),
            state_writes: node.state_writes.clone(),
            state_views,
            stream_metadata: VulkanKernelStreamMetadata::for_op(&node.op),
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanKernelStreamMetadata {
    pub stream_tick: VulkanKernelScalarBinding,
    pub control_flags: VulkanKernelScalarBinding,
    pub dynamic_state_capacity_activations: VulkanKernelScalarBinding,
    pub uses_stream_tick: bool,
}

impl VulkanKernelStreamMetadata {
    fn for_op(op: &str) -> Self {
        Self {
            stream_tick: VulkanKernelScalarBinding::push_constant("stream_tick", "u64"),
            control_flags: VulkanKernelScalarBinding::push_constant("control_flags", "u32"),
            dynamic_state_capacity_activations: VulkanKernelScalarBinding::push_constant(
                "dynamic_state_capacity_activations",
                "u32",
            ),
            uses_stream_tick: matches!(
                op,
                "rotary_position_embedding"
                    | "parallel_head_norm_rope_2way"
                    | "append_state_update"
                    | "scaled_dot_product_attention"
                    | "append_scaled_dot_product_attention"
                    | "per_layer_embedding"
                    | "rg_lru_step"
            ),
        }
    }

    pub fn push_constants(&self) -> Vec<VulkanKernelScalarBinding> {
        Vec::new()
    }
}

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct VulkanKernelScalarBinding {
    pub name: String,
    pub scalar_type: String,
    pub source: VulkanKernelScalarSource,
}

impl VulkanKernelScalarBinding {
    fn push_constant(name: impl Into<String>, scalar_type: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            scalar_type: scalar_type.into(),
            source: VulkanKernelScalarSource::PushConstant,
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum VulkanKernelScalarSource {
    PushConstant,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanKernelDispatchPlan {
    pub backend_id: String,
    pub commands: Vec<VulkanKernelDispatchCommand>,
}

impl VulkanKernelDispatchPlan {
    pub fn from_binding_plan(binding_plan: &VulkanStreamCircuitBindingPlan) -> Self {
        Self::from_kernel_interfaces(&VulkanKernelInterfacePlan::from_binding_plan(binding_plan))
    }

    pub fn from_kernel_interfaces(interface_plan: &VulkanKernelInterfacePlan) -> Self {
        let mut commands = Vec::with_capacity(interface_plan.total_kernel_count());
        for (circuit_index, circuit) in interface_plan.circuits.iter().enumerate() {
            for kernel in &circuit.kernels {
                commands.push(VulkanKernelDispatchCommand::from_kernel(
                    commands.len(),
                    circuit_index,
                    &circuit.circuit_id,
                    kernel,
                ));
            }
        }

        Self {
            backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
            commands,
        }
    }

    pub fn total_dispatch_count(&self) -> usize {
        self.commands.len()
    }

    pub fn command(&self, pedal_id: &str, node_id: &str) -> Option<&VulkanKernelDispatchCommand> {
        self.commands
            .iter()
            .find(|command| command.pedal_id == pedal_id && command.node_id == node_id)
    }

    pub fn op_counts(&self) -> BTreeMap<String, usize> {
        let mut counts = BTreeMap::new();
        for command in &self.commands {
            *counts.entry(command.op.clone()).or_insert(0) += 1;
        }
        counts
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
