#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanDescriptorResourcePlanError(pub String);

impl Display for VulkanDescriptorResourcePlanError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.0)
    }
}

impl Error for VulkanDescriptorResourcePlanError {}

fn resolve_descriptor_resource(
    command: &VulkanKernelDispatchCommand,
    descriptor: &VulkanKernelDescriptorBinding,
    parameter_index: &BTreeMap<&str, &VulkanResidentParameter>,
    state_index: &BTreeMap<(&str, &str), &VulkanResidentStateBuffer>,
    activation_index: &BTreeMap<(&str, usize), &VulkanResidentActivationSlot>,
    dynamic_state_capacity_activations: usize,
) -> Result<VulkanDescriptorResourceAddress, VulkanDescriptorResourcePlanError> {
    match &descriptor.resource {
        VulkanKernelDescriptorResource::Signal(signal) => resolve_signal_descriptor_resource(
            command,
            descriptor,
            signal,
            state_index,
            activation_index,
            dynamic_state_capacity_activations,
        ),
        VulkanKernelDescriptorResource::Parameter(parameter) => {
            let resident = parameter_index
                .get(parameter.tensor.as_str())
                .ok_or_else(|| {
                    VulkanDescriptorResourcePlanError(format!(
                        "{} descriptor {} parameter tensor {:?} is not resident",
                        command.kernel_id, descriptor.binding, parameter.tensor
                    ))
                })?;
            if parameter.byte_count != resident.byte_count {
                return Err(VulkanDescriptorResourcePlanError(format!(
                    "{} descriptor {} parameter {:?} byte count {:?} does not match resident {:?}",
                    command.kernel_id,
                    descriptor.binding,
                    parameter.tensor,
                    parameter.byte_count,
                    resident.byte_count
                )));
            }
            Ok(VulkanDescriptorResourceAddress::PermanentParameter {
                param_id: parameter.param_id.clone(),
                tensor: parameter.tensor.clone(),
                byte_count: resident.byte_count,
            })
        }
        VulkanKernelDescriptorResource::State { pedal_id, binding } => {
            resolve_state_descriptor_resource(
                command,
                descriptor,
                pedal_id,
                binding,
                state_index,
                dynamic_state_capacity_activations,
                false,
            )
        }
    }
}

fn resolve_signal_descriptor_resource(
    command: &VulkanKernelDispatchCommand,
    descriptor: &VulkanKernelDescriptorBinding,
    signal: &VulkanSignalBinding,
    state_index: &BTreeMap<(&str, &str), &VulkanResidentStateBuffer>,
    activation_index: &BTreeMap<(&str, usize), &VulkanResidentActivationSlot>,
    dynamic_state_capacity_activations: usize,
) -> Result<VulkanDescriptorResourceAddress, VulkanDescriptorResourcePlanError> {
    match &signal.resource {
        VulkanSignalResource::BoundaryInput => Ok(VulkanDescriptorResourceAddress::BoundaryInput {
            signal_id: signal.signal_id.clone(),
        }),
        VulkanSignalResource::BoundaryOutput => {
            Ok(VulkanDescriptorResourceAddress::BoundaryOutput {
                signal_id: signal.signal_id.clone(),
            })
        }
        VulkanSignalResource::ActivationSlot {
            pedal_id,
            slot,
            bytes,
            signal_bytes,
        } => {
            let resident = activation_index
                .get(&(pedal_id.as_str(), *slot))
                .ok_or_else(|| {
                    VulkanDescriptorResourcePlanError(format!(
                        "{} descriptor {} activation slot {}.{} is not resident",
                        command.kernel_id, descriptor.binding, pedal_id, slot
                    ))
                })?;
            let byte_capacity = resident.bytes.ok_or_else(|| {
                VulkanDescriptorResourcePlanError(format!(
                    "{} descriptor {} activation slot {}.{} has unknown byte capacity",
                    command.kernel_id, descriptor.binding, pedal_id, slot
                ))
            })?;
            if *bytes != Some(byte_capacity) {
                return Err(VulkanDescriptorResourcePlanError(format!(
                    "{} descriptor {} activation slot {}.{} byte count {:?} does not match resident {}",
                    command.kernel_id, descriptor.binding, pedal_id, slot, bytes, byte_capacity
                )));
            }
            let signal_byte_capacity = signal_bytes.ok_or_else(|| {
                VulkanDescriptorResourcePlanError(format!(
                    "{} descriptor {} activation signal {:?} has unknown byte capacity",
                    command.kernel_id, descriptor.binding, signal.signal_id
                ))
            })?;
            if signal_byte_capacity > byte_capacity {
                return Err(VulkanDescriptorResourcePlanError(format!(
                    "{} descriptor {} activation signal {:?} byte count {} exceeds resident slot capacity {}",
                    command.kernel_id,
                    descriptor.binding,
                    signal.signal_id,
                    signal_byte_capacity,
                    byte_capacity
                )));
            }
            Ok(VulkanDescriptorResourceAddress::ActivationSlot {
                pedal_id: pedal_id.clone(),
                signal_id: signal.signal_id.clone(),
                slot: *slot,
                byte_capacity,
                signal_byte_capacity,
            })
        }
        VulkanSignalResource::StateBuffer { .. } | VulkanSignalResource::StateView { .. } => {
            resolve_signal_state_descriptor_resource(
                command,
                descriptor,
                &signal.resource,
                state_index,
                dynamic_state_capacity_activations,
            )
        }
    }
}

fn resolve_signal_state_descriptor_resource(
    command: &VulkanKernelDispatchCommand,
    descriptor: &VulkanKernelDescriptorBinding,
    resource: &VulkanSignalResource,
    state_index: &BTreeMap<(&str, &str), &VulkanResidentStateBuffer>,
    dynamic_state_capacity_activations: usize,
) -> Result<VulkanDescriptorResourceAddress, VulkanDescriptorResourcePlanError> {
    let (pedal_id, state_id, static_bytes, bytes_per_activation, state_view) = match resource {
        VulkanSignalResource::StateBuffer {
            pedal_id,
            state_id,
            static_bytes,
            bytes_per_activation,
        } => (
            pedal_id,
            state_id,
            static_bytes,
            bytes_per_activation,
            false,
        ),
        VulkanSignalResource::StateView {
            pedal_id,
            state_id,
            static_bytes,
            bytes_per_activation,
        } => (pedal_id, state_id, static_bytes, bytes_per_activation, true),
        _ => unreachable!("caller only routes state resources"),
    };
    let resident = state_index
        .get(&(pedal_id.as_str(), state_id.as_str()))
        .ok_or_else(|| {
            VulkanDescriptorResourcePlanError(format!(
                "{} descriptor {} state {}.{} is not resident",
                command.kernel_id, descriptor.binding, pedal_id, state_id
            ))
        })?;
    if *static_bytes != resident.static_bytes
        || *bytes_per_activation != resident.bytes_per_activation
    {
        return Err(VulkanDescriptorResourcePlanError(format!(
            "{} descriptor {} state {}.{} byte shape {:?}/{:?} does not match resident {:?}/{:?}",
            command.kernel_id,
            descriptor.binding,
            pedal_id,
            state_id,
            static_bytes,
            bytes_per_activation,
            resident.static_bytes,
            resident.bytes_per_activation
        )));
    }
    let byte_capacity =
        descriptor_state_byte_capacity(resident, dynamic_state_capacity_activations)?;
    if state_view {
        Ok(VulkanDescriptorResourceAddress::StateView {
            pedal_id: pedal_id.to_string(),
            state_id: state_id.to_string(),
            state_type: resident.state_type.clone(),
            byte_capacity,
            static_bytes: resident.static_bytes,
            bytes_per_activation: resident.bytes_per_activation,
        })
    } else {
        Ok(VulkanDescriptorResourceAddress::StateBuffer {
            pedal_id: pedal_id.to_string(),
            state_id: state_id.to_string(),
            state_type: resident.state_type.clone(),
            byte_capacity,
            static_bytes: resident.static_bytes,
            bytes_per_activation: resident.bytes_per_activation,
        })
    }
}

fn resolve_state_descriptor_resource(
    command: &VulkanKernelDispatchCommand,
    descriptor: &VulkanKernelDescriptorBinding,
    pedal_id: &str,
    binding: &VulkanStateBinding,
    state_index: &BTreeMap<(&str, &str), &VulkanResidentStateBuffer>,
    dynamic_state_capacity_activations: usize,
    state_view: bool,
) -> Result<VulkanDescriptorResourceAddress, VulkanDescriptorResourcePlanError> {
    let resident = state_index
        .get(&(pedal_id, binding.state_id.as_str()))
        .ok_or_else(|| {
            VulkanDescriptorResourcePlanError(format!(
                "{} descriptor {} state {}.{} is not resident",
                command.kernel_id, descriptor.binding, pedal_id, binding.state_id
            ))
        })?;
    if binding.state_type != resident.state_type
        || binding.static_bytes != resident.static_bytes
        || binding.bytes_per_activation != resident.bytes_per_activation
    {
        return Err(VulkanDescriptorResourcePlanError(format!(
            "{} descriptor {} state {}.{} binding does not match resident allocation",
            command.kernel_id, descriptor.binding, pedal_id, binding.state_id
        )));
    }
    let byte_capacity =
        descriptor_state_byte_capacity(resident, dynamic_state_capacity_activations)?;
    if state_view {
        Ok(VulkanDescriptorResourceAddress::StateView {
            pedal_id: pedal_id.to_string(),
            state_id: binding.state_id.clone(),
            state_type: binding.state_type.clone(),
            byte_capacity,
            static_bytes: binding.static_bytes,
            bytes_per_activation: binding.bytes_per_activation,
        })
    } else {
        Ok(VulkanDescriptorResourceAddress::StateBuffer {
            pedal_id: pedal_id.to_string(),
            state_id: binding.state_id.clone(),
            state_type: binding.state_type.clone(),
            byte_capacity,
            static_bytes: binding.static_bytes,
            bytes_per_activation: binding.bytes_per_activation,
        })
    }
}

fn descriptor_state_byte_capacity(
    state: &VulkanResidentStateBuffer,
    dynamic_state_capacity_activations: usize,
) -> Result<usize, VulkanDescriptorResourcePlanError> {
    let static_bytes = state.static_bytes.unwrap_or(0);
    let dynamic_bytes = match state.bytes_per_activation {
        Some(bytes_per_activation) => {
            if dynamic_state_capacity_activations == 0 {
                return Err(VulkanDescriptorResourcePlanError(format!(
                    "{}.{} requires non-zero dynamic state capacity",
                    state.pedal_id, state.state_id
                )));
            }
            bytes_per_activation
                .checked_mul(dynamic_state_capacity_activations)
                .ok_or_else(|| {
                    VulkanDescriptorResourcePlanError(format!(
                        "{}.{} dynamic state byte capacity overflowed",
                        state.pedal_id, state.state_id
                    ))
                })?
        }
        None => 0,
    };
    let total = static_bytes.checked_add(dynamic_bytes).ok_or_else(|| {
        VulkanDescriptorResourcePlanError(format!(
            "{}.{} state byte capacity overflowed",
            state.pedal_id, state.state_id
        ))
    })?;
    if total == 0 {
        return Err(VulkanDescriptorResourcePlanError(format!(
            "{}.{} has unknown or zero byte capacity",
            state.pedal_id, state.state_id
        )));
    }
    Ok(total)
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanReusableKernelPlan {
    pub backend_id: String,
    pub total_command_count: usize,
    pub families: Vec<VulkanReusableKernelFamily>,
}

impl VulkanReusableKernelPlan {
    pub fn from_dispatch_plan(dispatch_plan: &VulkanKernelDispatchPlan) -> Self {
        let mut grouped: BTreeMap<VulkanReusableKernelKey, Vec<VulkanKernelDispatchRef>> =
            BTreeMap::new();

        for command in &dispatch_plan.commands {
            grouped
                .entry(VulkanReusableKernelKey::from_command(command))
                .or_default()
                .push(VulkanKernelDispatchRef::from_command(command));
        }

        let mut op_family_indices = BTreeMap::new();
        let families = grouped
            .into_iter()
            .map(|(key, command_refs)| {
                let op_family_index = op_family_indices.entry(key.op.clone()).or_insert(0usize);
                let family_id = if *op_family_index == 0 {
                    key.op.clone()
                } else {
                    format!("{}.signature_{}", key.op, op_family_index)
                };
                *op_family_index += 1;

                VulkanReusableKernelFamily {
                    family_id,
                    op: key.op,
                    descriptor_signature: key.descriptor_signature,
                    push_constants: key.push_constants,
                    uses_stream_tick: key.uses_stream_tick,
                    command_refs,
                }
            })
            .collect();

        Self {
            backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
            total_command_count: dispatch_plan.total_dispatch_count(),
            families,
        }
    }

    pub fn total_family_count(&self) -> usize {
        self.families.len()
    }

    pub fn reusable_family_count(&self) -> usize {
        self.families
            .iter()
            .filter(|family| family.command_refs.len() > 1)
            .count()
    }

    pub fn family(&self, family_id: &str) -> Option<&VulkanReusableKernelFamily> {
        self.families
            .iter()
            .find(|family| family.family_id == family_id)
    }

    pub fn families_for_op(&self, op: &str) -> Vec<&VulkanReusableKernelFamily> {
        self.families
            .iter()
            .filter(|family| family.op == op)
            .collect()
    }

    pub fn coverage_report<I, S>(
        &self,
        available_family_ids: I,
    ) -> VulkanReusableKernelCoverageReport
    where
        I: IntoIterator<Item = S>,
        S: AsRef<str>,
    {
        let available_family_ids: BTreeSet<String> = available_family_ids
            .into_iter()
            .map(|id| id.as_ref().to_string())
            .collect();
        let mut families = Vec::with_capacity(self.families.len());
        let mut available_family_count = 0usize;
        let mut covered_command_count = 0usize;

        for family in &self.families {
            let available = available_family_ids.contains(&family.family_id);
            if available {
                available_family_count += 1;
                covered_command_count += family.command_refs.len();
            }
            families.push(VulkanReusableKernelFamilyCoverage {
                family_id: family.family_id.clone(),
                op: family.op.clone(),
                command_count: family.command_refs.len(),
                available,
            });
        }

        VulkanReusableKernelCoverageReport {
            backend_id: self.backend_id.clone(),
            required_family_count: self.families.len(),
            available_family_count,
            missing_family_count: self.families.len() - available_family_count,
            required_command_count: self.total_command_count,
            covered_command_count,
            missing_command_count: self.total_command_count - covered_command_count,
            families,
        }
    }

    pub fn link_artifacts(
        &self,
        manifest: &VulkanReusableKernelArtifactManifest,
    ) -> VulkanLinkedReusableKernelPlan {
        VulkanLinkedReusableKernelPlan::from_reusable_plan_and_manifest(self, manifest)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanReusableKernelFamily {
    pub family_id: String,
    pub op: String,
    pub descriptor_signature: Vec<VulkanKernelDescriptorSlotSignature>,
    pub push_constants: Vec<VulkanKernelScalarBinding>,
    pub uses_stream_tick: bool,
    pub command_refs: Vec<VulkanKernelDispatchRef>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanReusableKernelCoverageReport {
    pub backend_id: String,
    pub required_family_count: usize,
    pub available_family_count: usize,
    pub missing_family_count: usize,
    pub required_command_count: usize,
    pub covered_command_count: usize,
    pub missing_command_count: usize,
    pub families: Vec<VulkanReusableKernelFamilyCoverage>,
}

impl VulkanReusableKernelCoverageReport {
    pub fn all_available(&self) -> bool {
        self.missing_family_count == 0
    }

    pub fn missing_families(&self) -> Vec<&VulkanReusableKernelFamilyCoverage> {
        self.families
            .iter()
            .filter(|family| !family.available)
            .collect()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanReusableKernelFamilyCoverage {
    pub family_id: String,
    pub op: String,
    pub command_count: usize,
    pub available: bool,
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct VulkanReusableKernelArtifactManifest {
    pub schema: String,
    pub backend_id: String,
    pub artifacts: Vec<VulkanReusableKernelArtifact>,
}

impl VulkanReusableKernelArtifactManifest {
    pub fn new(artifacts: Vec<VulkanReusableKernelArtifact>) -> Self {
        Self {
            schema: VULKAN_REUSABLE_KERNEL_ARTIFACT_MANIFEST_SCHEMA.to_string(),
            backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
            artifacts,
        }
    }

    pub fn empty() -> Self {
        Self::new(Vec::new())
    }

    pub fn with_artifact(mut self, artifact: VulkanReusableKernelArtifact) -> Self {
        self.artifacts.push(artifact);
        self
    }

    pub fn family_ids(&self) -> Vec<&str> {
        self.artifacts
            .iter()
            .map(|artifact| artifact.family_id.as_str())
            .collect()
    }

    pub fn from_json_file(path: impl AsRef<Path>) -> io::Result<Self> {
        let bytes = fs::read(path)?;
        let manifest: Self = serde_json::from_slice(&bytes)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        if manifest.schema != VULKAN_REUSABLE_KERNEL_ARTIFACT_MANIFEST_SCHEMA {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "unsupported reusable kernel manifest schema {:?}",
                    manifest.schema
                ),
            ));
        }
        Ok(manifest)
    }

    pub fn write_json_file(&self, path: impl AsRef<Path>) -> io::Result<()> {
        let bytes = serde_json::to_vec_pretty(self)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        fs::write(path, bytes)
    }

    pub fn load_artifacts(
        &self,
        artifact_root: impl AsRef<Path>,
    ) -> io::Result<VulkanLoadedReusableKernelArtifactManifest> {
        VulkanLoadedReusableKernelArtifactManifest::from_manifest(self, artifact_root)
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct VulkanReusableKernelArtifact {
    pub family_id: String,
    pub op: String,
    pub path: String,
    pub entry_point: String,
    pub local_size_x: u32,
    pub workgroup_count_x: u32,
    pub descriptor_signature: Vec<VulkanKernelDescriptorSlotSignature>,
    pub push_constants: Vec<VulkanKernelScalarBinding>,
    pub uses_stream_tick: bool,
}

impl VulkanReusableKernelArtifact {
    pub fn from_family(family: &VulkanReusableKernelFamily, path: impl Into<String>) -> Self {
        Self {
            family_id: family.family_id.clone(),
            op: family.op.clone(),
            path: path.into(),
            entry_point: DEFAULT_SPIRV_ENTRY_POINT.to_string(),
            local_size_x: DEFAULT_COMPUTE_LOCAL_SIZE_X,
            workgroup_count_x: 1,
            descriptor_signature: family.descriptor_signature.clone(),
            push_constants: family.push_constants.clone(),
            uses_stream_tick: family.uses_stream_tick,
        }
    }

    pub fn with_entry_point(mut self, entry_point: impl Into<String>) -> Self {
        self.entry_point = entry_point.into();
        self
    }

    pub fn with_local_size_x(mut self, local_size_x: u32) -> Self {
        self.local_size_x = local_size_x;
        self
    }

    pub fn with_workgroup_count_x(mut self, workgroup_count_x: u32) -> Self {
        self.workgroup_count_x = workgroup_count_x;
        self
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanLoadedReusableKernelArtifactManifest {
    pub schema: String,
    pub backend_id: String,
    pub artifacts: Vec<VulkanLoadedReusableKernelArtifact>,
    pub total_word_count: usize,
}

impl VulkanLoadedReusableKernelArtifactManifest {
    pub fn from_manifest(
        manifest: &VulkanReusableKernelArtifactManifest,
        artifact_root: impl AsRef<Path>,
    ) -> io::Result<Self> {
        let artifact_root = artifact_root.as_ref();
        let mut artifacts = Vec::with_capacity(manifest.artifacts.len());
        let mut total_word_count = 0usize;

        for artifact in &manifest.artifacts {
            let resolved_path =
                resolve_reusable_kernel_artifact_path(artifact_root, &artifact.path);
            let words = read_spirv_words(&resolved_path)?;
            total_word_count = total_word_count.checked_add(words.len()).ok_or_else(|| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "loaded reusable kernel word count overflowed",
                )
            })?;
            artifacts.push(VulkanLoadedReusableKernelArtifact {
                artifact: artifact.clone(),
                resolved_path,
                words,
            });
        }

        Ok(Self {
            schema: manifest.schema.clone(),
            backend_id: manifest.backend_id.clone(),
            artifacts,
            total_word_count,
        })
    }

    pub fn artifact(&self, family_id: &str) -> Option<&VulkanLoadedReusableKernelArtifact> {
        self.artifacts
            .iter()
            .find(|artifact| artifact.artifact.family_id == family_id)
    }

    pub fn family_ids(&self) -> Vec<&str> {
        self.artifacts
            .iter()
            .map(|artifact| artifact.artifact.family_id.as_str())
            .collect()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanLoadedReusableKernelArtifact {
    pub artifact: VulkanReusableKernelArtifact,
    pub resolved_path: PathBuf,
    pub words: Vec<u32>,
}

fn resolve_reusable_kernel_artifact_path(artifact_root: &Path, path: &str) -> PathBuf {
    let path = Path::new(path);
    if path.is_absolute() {
        path.to_path_buf()
    } else {
        artifact_root.join(path)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanLinkedReusableKernelPlan {
    pub backend_id: String,
    pub manifest_schema: String,
    pub manifest_backend_id: String,
    pub required_family_count: usize,
    pub linked_family_count: usize,
    pub missing_family_count: usize,
    pub incompatible_family_count: usize,
    pub required_command_count: usize,
    pub linked_command_count: usize,
    pub missing_command_count: usize,
    pub incompatible_command_count: usize,
    pub families: Vec<VulkanLinkedReusableKernelFamily>,
    pub issues: Vec<VulkanReusableKernelLinkIssue>,
}

impl VulkanLinkedReusableKernelPlan {
    pub fn from_reusable_plan_and_manifest(
        reusable_plan: &VulkanReusableKernelPlan,
        manifest: &VulkanReusableKernelArtifactManifest,
    ) -> Self {
        let mut artifacts_by_family_id: BTreeMap<&str, Vec<&VulkanReusableKernelArtifact>> =
            BTreeMap::new();
        for artifact in &manifest.artifacts {
            artifacts_by_family_id
                .entry(artifact.family_id.as_str())
                .or_default()
                .push(artifact);
        }

        let mut families = Vec::with_capacity(reusable_plan.families.len());
        let mut issues = Vec::new();
        let mut linked_family_count = 0usize;
        let mut missing_family_count = 0usize;
        let mut incompatible_family_count = 0usize;
        let mut linked_command_count = 0usize;
        let mut missing_command_count = 0usize;
        let mut incompatible_command_count = 0usize;

        for family in &reusable_plan.families {
            let command_count = family.command_refs.len();
            let artifacts = artifacts_by_family_id
                .get(family.family_id.as_str())
                .map(Vec::as_slice)
                .unwrap_or(&[]);
            let mut family_issues = Vec::new();

            if artifacts.is_empty() {
                family_issues.push(VulkanReusableKernelLinkIssue {
                    family_id: family.family_id.clone(),
                    op: family.op.clone(),
                    problem: VulkanReusableKernelLinkProblem::MissingArtifact,
                });
            } else if artifacts.len() > 1 {
                family_issues.push(VulkanReusableKernelLinkIssue {
                    family_id: family.family_id.clone(),
                    op: family.op.clone(),
                    problem: VulkanReusableKernelLinkProblem::DuplicateArtifact {
                        count: artifacts.len(),
                    },
                });
            }

            let artifact = artifacts.first().copied();
            if let Some(artifact) = artifact {
                family_issues.extend(link_compatibility_issues(family, artifact));
            }

            let (status, artifact_path) = if artifacts.is_empty() {
                missing_family_count += 1;
                missing_command_count += command_count;
                (VulkanReusableKernelLinkStatus::Missing, None)
            } else if family_issues.is_empty() {
                linked_family_count += 1;
                linked_command_count += command_count;
                (
                    VulkanReusableKernelLinkStatus::Linked,
                    artifact.map(|artifact| artifact.path.clone()),
                )
            } else {
                incompatible_family_count += 1;
                incompatible_command_count += command_count;
                (
                    VulkanReusableKernelLinkStatus::Incompatible,
                    artifact.map(|artifact| artifact.path.clone()),
                )
            };

            issues.extend(family_issues.iter().cloned());
            families.push(VulkanLinkedReusableKernelFamily {
                family_id: family.family_id.clone(),
                op: family.op.clone(),
                command_count,
                status,
                artifact_path,
                issues: family_issues,
            });
        }

        Self {
            backend_id: reusable_plan.backend_id.clone(),
            manifest_schema: manifest.schema.clone(),
            manifest_backend_id: manifest.backend_id.clone(),
            required_family_count: reusable_plan.families.len(),
            linked_family_count,
            missing_family_count,
            incompatible_family_count,
            required_command_count: reusable_plan.total_command_count,
            linked_command_count,
            missing_command_count,
            incompatible_command_count,
            families,
            issues,
        }
    }

    pub fn is_fully_linked(&self) -> bool {
        self.missing_family_count == 0
            && self.incompatible_family_count == 0
            && self.linked_command_count == self.required_command_count
    }

    pub fn family(&self, family_id: &str) -> Option<&VulkanLinkedReusableKernelFamily> {
        self.families
            .iter()
            .find(|family| family.family_id == family_id)
    }

    pub fn missing_families(&self) -> Vec<&VulkanLinkedReusableKernelFamily> {
        self.families
            .iter()
            .filter(|family| family.status == VulkanReusableKernelLinkStatus::Missing)
            .collect()
    }

    pub fn incompatible_families(&self) -> Vec<&VulkanLinkedReusableKernelFamily> {
        self.families
            .iter()
            .filter(|family| family.status == VulkanReusableKernelLinkStatus::Incompatible)
            .collect()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanLinkedReusableKernelFamily {
    pub family_id: String,
    pub op: String,
    pub command_count: usize,
    pub status: VulkanReusableKernelLinkStatus,
    pub artifact_path: Option<String>,
    pub issues: Vec<VulkanReusableKernelLinkIssue>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanReusableKernelLinkStatus {
    Linked,
    Missing,
    Incompatible,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanReusableKernelLinkIssue {
    pub family_id: String,
    pub op: String,
    pub problem: VulkanReusableKernelLinkProblem,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanReusableKernelLinkProblem {
    MissingArtifact,
    DuplicateArtifact { count: usize },
    OpMismatch { found: String },
    DescriptorSignatureMismatch,
    PushConstantSignatureMismatch,
    StreamTickUsageMismatch { found: bool },
    EmptySpirvPath,
    UnsupportedEntryPoint { found: String },
    InvalidLocalSizeX { found: u32 },
}

fn link_compatibility_issues(
    family: &VulkanReusableKernelFamily,
    artifact: &VulkanReusableKernelArtifact,
) -> Vec<VulkanReusableKernelLinkIssue> {
    let mut issues = Vec::new();
    let family_id = family.family_id.clone();
    let op = family.op.clone();

    if artifact.op != family.op {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::OpMismatch {
                found: artifact.op.clone(),
            },
        });
    }
    if artifact.descriptor_signature != family.descriptor_signature {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::DescriptorSignatureMismatch,
        });
    }
    if artifact.push_constants != family.push_constants {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::PushConstantSignatureMismatch,
        });
    }
    if artifact.uses_stream_tick != family.uses_stream_tick {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::StreamTickUsageMismatch {
                found: artifact.uses_stream_tick,
            },
        });
    }
    if artifact.path.is_empty() {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::EmptySpirvPath,
        });
    }
    if artifact.entry_point != DEFAULT_SPIRV_ENTRY_POINT {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id: family_id.clone(),
            op: op.clone(),
            problem: VulkanReusableKernelLinkProblem::UnsupportedEntryPoint {
                found: artifact.entry_point.clone(),
            },
        });
    }
    if artifact.local_size_x == 0 {
        issues.push(VulkanReusableKernelLinkIssue {
            family_id,
            op,
            problem: VulkanReusableKernelLinkProblem::InvalidLocalSizeX {
                found: artifact.local_size_x,
            },
        });
    }

    issues
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanPreparedDispatchPlan {
    pub backend_id: String,
    pub reusable_family_count: usize,
    pub dispatches: Vec<VulkanPreparedDispatch>,
    pub total_descriptor_count: usize,
}

impl VulkanPreparedDispatchPlan {
    pub fn from_plans(
        dispatch_plan: &VulkanKernelDispatchPlan,
        reusable_plan: &VulkanReusableKernelPlan,
        descriptor_plan: &VulkanDescriptorResourcePlan,
        manifest: &VulkanReusableKernelArtifactManifest,
    ) -> Result<Self, VulkanPreparedDispatchPlanError> {
        let link_plan = reusable_plan.link_artifacts(manifest);
        if !link_plan.is_fully_linked() {
            return Err(VulkanPreparedDispatchPlanError::Link(Box::new(link_plan)));
        }

        let descriptor_by_dispatch: BTreeMap<usize, &VulkanDispatchDescriptorResourcePlan> =
            descriptor_plan
                .dispatches
                .iter()
                .map(|dispatch| (dispatch.dispatch_index, dispatch))
                .collect();
        let mut family_by_dispatch = BTreeMap::new();
        for family in &reusable_plan.families {
            for command_ref in &family.command_refs {
                family_by_dispatch.insert(command_ref.dispatch_index, family);
            }
        }
        let artifact_by_family: BTreeMap<_, _> = manifest
            .artifacts
            .iter()
            .map(|artifact| (artifact.family_id.as_str(), artifact))
            .collect();

        let mut dispatches = Vec::with_capacity(dispatch_plan.commands.len());
        for command in &dispatch_plan.commands {
            let descriptor_dispatch = descriptor_by_dispatch.get(&command.dispatch_index).ok_or(
                VulkanPreparedDispatchPlanError::MissingDescriptorResources {
                    dispatch_index: command.dispatch_index,
                },
            )?;
            let family = family_by_dispatch.get(&command.dispatch_index).ok_or(
                VulkanPreparedDispatchPlanError::MissingReusableFamily {
                    dispatch_index: command.dispatch_index,
                },
            )?;
            let artifact = artifact_by_family
                .get(family.family_id.as_str())
                .ok_or_else(|| VulkanPreparedDispatchPlanError::MissingLinkedArtifact {
                    family_id: family.family_id.clone(),
                })?;

            dispatches.push(VulkanPreparedDispatch {
                dispatch_index: command.dispatch_index,
                kernel_id: command.kernel_id.clone(),
                pedal_id: command.pedal_id.clone(),
                circuit_id: command.circuit_id.clone(),
                node_index: command.node_index,
                node_id: command.node_id.clone(),
                op: command.op.clone(),
                reusable_family_id: family.family_id.clone(),
                artifact_path: artifact.path.clone(),
                entry_point: artifact.entry_point.clone(),
                local_size_x: artifact.local_size_x,
                descriptors: descriptor_dispatch.descriptors.clone(),
                push_constants: command.push_constants.clone(),
                uses_stream_tick: command.uses_stream_tick,
            });
        }
        let total_descriptor_count = dispatches
            .iter()
            .map(|dispatch| dispatch.descriptors.len())
            .sum();

        Ok(Self {
            backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
            reusable_family_count: reusable_plan.total_family_count(),
            dispatches,
            total_descriptor_count,
        })
    }

    pub fn dispatch(&self, pedal_id: &str, node_id: &str) -> Option<&VulkanPreparedDispatch> {
        self.dispatches
            .iter()
            .find(|dispatch| dispatch.pedal_id == pedal_id && dispatch.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanPreparedDispatch {
    pub dispatch_index: usize,
    pub kernel_id: String,
    pub pedal_id: String,
    pub circuit_id: String,
    pub node_index: usize,
    pub node_id: String,
    pub op: String,
    pub reusable_family_id: String,
    pub artifact_path: String,
    pub entry_point: String,
    pub local_size_x: u32,
    pub descriptors: Vec<VulkanResolvedDescriptorBinding>,
    pub push_constants: Vec<VulkanKernelScalarBinding>,
    pub uses_stream_tick: bool,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanPreparedDispatchPlanError {
    DescriptorResource(VulkanDescriptorResourcePlanError),
    Link(Box<VulkanLinkedReusableKernelPlan>),
    MissingDescriptorResources { dispatch_index: usize },
    MissingReusableFamily { dispatch_index: usize },
    MissingLinkedArtifact { family_id: String },
}

impl Display for VulkanPreparedDispatchPlanError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::DescriptorResource(error) => Display::fmt(error, f),
            Self::Link(plan) => write!(
                f,
                "reusable Vulkan kernels are not fully linked: {} missing families, {} incompatible families",
                plan.missing_family_count, plan.incompatible_family_count
            ),
            Self::MissingDescriptorResources { dispatch_index } => write!(
                f,
                "dispatch {dispatch_index} has no resolved descriptor resources"
            ),
            Self::MissingReusableFamily { dispatch_index } => {
                write!(f, "dispatch {dispatch_index} has no reusable kernel family")
            }
            Self::MissingLinkedArtifact { family_id } => {
                write!(f, "reusable family {family_id:?} has no linked artifact")
            }
        }
    }
}

impl Error for VulkanPreparedDispatchPlanError {}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanBoundDispatchPlan {
    pub backend_id: String,
    pub dispatches: Vec<VulkanBoundDispatch>,
    pub total_descriptor_count: usize,
    pub boundary_descriptor_count: usize,
    pub permanent_parameter_descriptor_count: usize,
    pub stream_state_descriptor_count: usize,
    pub activation_slot_descriptor_count: usize,
}

impl VulkanBoundDispatchPlan {
    pub fn from_prepared_plan(
        prepared_plan: &VulkanPreparedDispatchPlan,
        buffers: &VulkanStreamCircuitStreamBuffers,
    ) -> Result<Self, VulkanBoundDispatchPlanError> {
        let mut boundary_descriptor_count = 0usize;
        let mut permanent_parameter_descriptor_count = 0usize;
        let mut stream_state_descriptor_count = 0usize;
        let mut activation_slot_descriptor_count = 0usize;
        let mut dispatches = Vec::with_capacity(prepared_plan.dispatches.len());

        for prepared in &prepared_plan.dispatches {
            let mut descriptors = Vec::with_capacity(prepared.descriptors.len());
            for descriptor in &prepared.descriptors {
                let target =
                    VulkanBoundDescriptorTarget::from_resource(prepared, descriptor, buffers)?;
                match target {
                    VulkanBoundDescriptorTarget::BoundaryInput { .. }
                    | VulkanBoundDescriptorTarget::BoundaryOutput { .. } => {
                        boundary_descriptor_count += 1;
                    }
                    VulkanBoundDescriptorTarget::PermanentParameter { .. } => {
                        permanent_parameter_descriptor_count += 1;
                    }
                    VulkanBoundDescriptorTarget::StreamStateBuffer { .. }
                    | VulkanBoundDescriptorTarget::StreamStateView { .. } => {
                        stream_state_descriptor_count += 1;
                    }
                    VulkanBoundDescriptorTarget::ActivationSlot { .. } => {
                        activation_slot_descriptor_count += 1;
                    }
                }
                descriptors.push(VulkanBoundDescriptor {
                    binding: descriptor.binding,
                    usage: descriptor.usage.clone(),
                    name: descriptor.name.clone(),
                    target,
                });
            }

            dispatches.push(VulkanBoundDispatch {
                dispatch_index: prepared.dispatch_index,
                kernel_id: prepared.kernel_id.clone(),
                pedal_id: prepared.pedal_id.clone(),
                circuit_id: prepared.circuit_id.clone(),
                node_index: prepared.node_index,
                node_id: prepared.node_id.clone(),
                op: prepared.op.clone(),
                reusable_family_id: prepared.reusable_family_id.clone(),
                artifact_path: prepared.artifact_path.clone(),
                entry_point: prepared.entry_point.clone(),
                local_size_x: prepared.local_size_x,
                descriptors,
                push_constants: prepared.push_constants.clone(),
                uses_stream_tick: prepared.uses_stream_tick,
            });
        }

        let total_descriptor_count = boundary_descriptor_count
            + permanent_parameter_descriptor_count
            + stream_state_descriptor_count
            + activation_slot_descriptor_count;
        Ok(Self {
            backend_id: prepared_plan.backend_id.clone(),
            dispatches,
            total_descriptor_count,
            boundary_descriptor_count,
            permanent_parameter_descriptor_count,
            stream_state_descriptor_count,
            activation_slot_descriptor_count,
        })
    }

    pub fn dispatch(&self, pedal_id: &str, node_id: &str) -> Option<&VulkanBoundDispatch> {
        self.dispatches
            .iter()
            .find(|dispatch| dispatch.pedal_id == pedal_id && dispatch.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanPlacedBoundDispatchPlan {
    pub backend_id: String,
    pub device_id: String,
    pub dispatches: Vec<VulkanPlacedBoundDispatch>,
    pub total_descriptor_count: usize,
    pub resident_descriptor_count: usize,
    pub model_boundary_descriptor_count: usize,
    pub local_cable_descriptor_count: usize,
    pub incoming_cable_descriptor_count: usize,
    pub outgoing_cable_descriptor_count: usize,
}

impl VulkanPlacedBoundDispatchPlan {
    pub fn from_bound_plan(
        bound_plan: &VulkanBoundDispatchPlan,
        placed_resident_plan: &VulkanPlacedStreamCircuitResidentPlan,
    ) -> Self {
        let mut resident_descriptor_count = 0usize;
        let mut model_boundary_descriptor_count = 0usize;
        let mut local_cable_descriptor_count = 0usize;
        let mut incoming_cable_descriptor_count = 0usize;
        let mut outgoing_cable_descriptor_count = 0usize;
        let mut dispatches = Vec::with_capacity(bound_plan.dispatches.len());

        for dispatch in &bound_plan.dispatches {
            let mut descriptors = Vec::with_capacity(dispatch.descriptors.len());
            for descriptor in &dispatch.descriptors {
                let target = VulkanPlacedBoundDescriptorTarget::from_bound_target(
                    &dispatch.pedal_id,
                    &descriptor.target,
                    placed_resident_plan,
                );
                match target {
                    VulkanPlacedBoundDescriptorTarget::Resident { .. } => {
                        resident_descriptor_count += 1;
                    }
                    VulkanPlacedBoundDescriptorTarget::ModelInput { .. }
                    | VulkanPlacedBoundDescriptorTarget::ModelOutput { .. } => {
                        model_boundary_descriptor_count += 1;
                    }
                    VulkanPlacedBoundDescriptorTarget::LocalCableInput { .. }
                    | VulkanPlacedBoundDescriptorTarget::LocalCableOutput { .. } => {
                        local_cable_descriptor_count += 1;
                    }
                    VulkanPlacedBoundDescriptorTarget::IncomingCable { .. } => {
                        incoming_cable_descriptor_count += 1;
                    }
                    VulkanPlacedBoundDescriptorTarget::OutgoingCable { .. } => {
                        outgoing_cable_descriptor_count += 1;
                    }
                }
                descriptors.push(VulkanPlacedBoundDescriptor {
                    binding: descriptor.binding,
                    usage: descriptor.usage.clone(),
                    name: descriptor.name.clone(),
                    target,
                });
            }

            dispatches.push(VulkanPlacedBoundDispatch {
                dispatch_index: dispatch.dispatch_index,
                kernel_id: dispatch.kernel_id.clone(),
                pedal_id: dispatch.pedal_id.clone(),
                circuit_id: dispatch.circuit_id.clone(),
                node_index: dispatch.node_index,
                node_id: dispatch.node_id.clone(),
                op: dispatch.op.clone(),
                reusable_family_id: dispatch.reusable_family_id.clone(),
                artifact_path: dispatch.artifact_path.clone(),
                entry_point: dispatch.entry_point.clone(),
                local_size_x: dispatch.local_size_x,
                descriptors,
                push_constants: dispatch.push_constants.clone(),
                uses_stream_tick: dispatch.uses_stream_tick,
            });
        }

        let total_descriptor_count = resident_descriptor_count
            + model_boundary_descriptor_count
            + local_cable_descriptor_count
            + incoming_cable_descriptor_count
            + outgoing_cable_descriptor_count;

        Self {
            backend_id: bound_plan.backend_id.clone(),
            device_id: placed_resident_plan.device_id.clone(),
            dispatches,
            total_descriptor_count,
            resident_descriptor_count,
            model_boundary_descriptor_count,
            local_cable_descriptor_count,
            incoming_cable_descriptor_count,
            outgoing_cable_descriptor_count,
        }
    }

    pub fn dispatch(&self, pedal_id: &str, node_id: &str) -> Option<&VulkanPlacedBoundDispatch> {
        self.dispatches
            .iter()
            .find(|dispatch| dispatch.pedal_id == pedal_id && dispatch.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedBoundDispatchPlan {
    pub backend_id: String,
    pub device_id: String,
    pub dispatches: Vec<VulkanMountedPlacedBoundDispatch>,
    pub total_descriptor_count: usize,
    pub resident_descriptor_count: usize,
    pub model_boundary_descriptor_count: usize,
    pub local_cable_descriptor_count: usize,
    pub cable_endpoint_descriptor_count: usize,
    pub incoming_cable_descriptor_count: usize,
    pub outgoing_cable_descriptor_count: usize,
}

impl VulkanMountedPlacedBoundDispatchPlan {
    pub fn from_placed_bound_plan(
        placed_bound_plan: &VulkanPlacedBoundDispatchPlan,
        cable_io: &VulkanPlacedCableIoBuffers,
    ) -> Result<Self, VulkanBoundDispatchPlanError> {
        if placed_bound_plan.device_id != cable_io.plan.device_id {
            return Err(VulkanBoundDispatchPlanError::CableIoDeviceMismatch {
                plan_device_id: placed_bound_plan.device_id.clone(),
                cable_io_device_id: cable_io.plan.device_id.clone(),
            });
        }

        let mut resident_descriptor_count = 0usize;
        let mut model_boundary_descriptor_count = 0usize;
        let mut local_cable_descriptor_count = 0usize;
        let mut cable_endpoint_descriptor_count = 0usize;
        let mut incoming_cable_descriptor_count = 0usize;
        let mut outgoing_cable_descriptor_count = 0usize;
        let mut dispatches = Vec::with_capacity(placed_bound_plan.dispatches.len());

        for dispatch in &placed_bound_plan.dispatches {
            let mut descriptors = Vec::with_capacity(dispatch.descriptors.len());
            for descriptor in &dispatch.descriptors {
                let target = VulkanMountedPlacedBoundDescriptorTarget::from_placed_target(
                    dispatch, descriptor, cable_io,
                )?;
                match target {
                    VulkanMountedPlacedBoundDescriptorTarget::Resident { .. } => {
                        resident_descriptor_count += 1;
                    }
                    VulkanMountedPlacedBoundDescriptorTarget::ModelInput { .. }
                    | VulkanMountedPlacedBoundDescriptorTarget::ModelOutput { .. } => {
                        model_boundary_descriptor_count += 1;
                    }
                    VulkanMountedPlacedBoundDescriptorTarget::LocalCableInputBuffer { .. }
                    | VulkanMountedPlacedBoundDescriptorTarget::LocalCableOutputBuffer { .. } => {
                        local_cable_descriptor_count += 1;
                    }
                    VulkanMountedPlacedBoundDescriptorTarget::IncomingCableBuffer { .. } => {
                        incoming_cable_descriptor_count += 1;
                        cable_endpoint_descriptor_count += 1;
                    }
                    VulkanMountedPlacedBoundDescriptorTarget::OutgoingCableBuffer { .. } => {
                        outgoing_cable_descriptor_count += 1;
                        cable_endpoint_descriptor_count += 1;
                    }
                }
                descriptors.push(VulkanMountedPlacedBoundDescriptor {
                    binding: descriptor.binding,
                    usage: descriptor.usage.clone(),
                    name: descriptor.name.clone(),
                    target,
                });
            }

            dispatches.push(VulkanMountedPlacedBoundDispatch {
                dispatch_index: dispatch.dispatch_index,
                kernel_id: dispatch.kernel_id.clone(),
                pedal_id: dispatch.pedal_id.clone(),
                circuit_id: dispatch.circuit_id.clone(),
                node_index: dispatch.node_index,
                node_id: dispatch.node_id.clone(),
                op: dispatch.op.clone(),
                reusable_family_id: dispatch.reusable_family_id.clone(),
                artifact_path: dispatch.artifact_path.clone(),
                entry_point: dispatch.entry_point.clone(),
                local_size_x: dispatch.local_size_x,
                descriptors,
                push_constants: dispatch.push_constants.clone(),
                uses_stream_tick: dispatch.uses_stream_tick,
            });
        }

        let total_descriptor_count = resident_descriptor_count
            + model_boundary_descriptor_count
            + local_cable_descriptor_count
            + cable_endpoint_descriptor_count;

        Ok(Self {
            backend_id: placed_bound_plan.backend_id.clone(),
            device_id: placed_bound_plan.device_id.clone(),
            dispatches,
            total_descriptor_count,
            resident_descriptor_count,
            model_boundary_descriptor_count,
            local_cable_descriptor_count,
            cable_endpoint_descriptor_count,
            incoming_cable_descriptor_count,
            outgoing_cable_descriptor_count,
        })
    }

    pub fn dispatch(
        &self,
        pedal_id: &str,
        node_id: &str,
    ) -> Option<&VulkanMountedPlacedBoundDispatch> {
        self.dispatches
            .iter()
            .find(|dispatch| dispatch.pedal_id == pedal_id && dispatch.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedBoundDispatch {
    pub dispatch_index: usize,
    pub kernel_id: String,
    pub pedal_id: String,
    pub circuit_id: String,
    pub node_index: usize,
    pub node_id: String,
    pub op: String,
    pub reusable_family_id: String,
    pub artifact_path: String,
    pub entry_point: String,
    pub local_size_x: u32,
    pub descriptors: Vec<VulkanMountedPlacedBoundDescriptor>,
    pub push_constants: Vec<VulkanKernelScalarBinding>,
    pub uses_stream_tick: bool,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedBoundDescriptor {
    pub binding: usize,
    pub usage: VulkanKernelDescriptorUsage,
    pub name: String,
    pub target: VulkanMountedPlacedBoundDescriptorTarget,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanMountedPlacedBoundDescriptorTarget {
    Resident {
        target: VulkanBoundDescriptorTarget,
    },
    ModelInput {
        signal_id: String,
    },
    ModelOutput {
        signal_id: String,
    },
    LocalCableInputBuffer {
        cable: VulkanPlacedLocalCableBufferBinding,
    },
    LocalCableOutputBuffer {
        cable: VulkanPlacedLocalCableBufferBinding,
    },
    IncomingCableBuffer {
        endpoint: VulkanPlacedCableEndpointBufferBinding,
    },
    OutgoingCableBuffer {
        endpoint: VulkanPlacedCableEndpointBufferBinding,
    },
}

impl VulkanMountedPlacedBoundDescriptorTarget {
    fn from_placed_target(
        dispatch: &VulkanPlacedBoundDispatch,
        descriptor: &VulkanPlacedBoundDescriptor,
        cable_io: &VulkanPlacedCableIoBuffers,
    ) -> Result<Self, VulkanBoundDispatchPlanError> {
        match &descriptor.target {
            VulkanPlacedBoundDescriptorTarget::Resident { target } => Ok(Self::Resident {
                target: target.clone(),
            }),
            VulkanPlacedBoundDescriptorTarget::ModelInput { signal_id } => Ok(Self::ModelInput {
                signal_id: signal_id.clone(),
            }),
            VulkanPlacedBoundDescriptorTarget::ModelOutput { signal_id } => Ok(Self::ModelOutput {
                signal_id: signal_id.clone(),
            }),
            VulkanPlacedBoundDescriptorTarget::LocalCableInput { cable } => {
                Ok(Self::LocalCableInputBuffer {
                    cable: bind_local_cable_buffer(
                        dispatch,
                        descriptor,
                        cable.cable_index,
                        cable_io,
                    )?,
                })
            }
            VulkanPlacedBoundDescriptorTarget::LocalCableOutput { cable } => {
                Ok(Self::LocalCableOutputBuffer {
                    cable: bind_local_cable_buffer(
                        dispatch,
                        descriptor,
                        cable.cable_index,
                        cable_io,
                    )?,
                })
            }
            VulkanPlacedBoundDescriptorTarget::IncomingCable { cable } => {
                Ok(Self::IncomingCableBuffer {
                    endpoint: bind_cable_endpoint_buffer(
                        dispatch,
                        descriptor,
                        VulkanPlacedCableDirection::Incoming,
                        cable.cable_index,
                        cable_io,
                    )?,
                })
            }
            VulkanPlacedBoundDescriptorTarget::OutgoingCable { cable } => {
                Ok(Self::OutgoingCableBuffer {
                    endpoint: bind_cable_endpoint_buffer(
                        dispatch,
                        descriptor,
                        VulkanPlacedCableDirection::Outgoing,
                        cable.cable_index,
                        cable_io,
                    )?,
                })
            }
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentKernelDispatchReadinessPlan {
    pub backend_id: String,
    pub device_id: String,
    pub dispatches: Vec<VulkanMountedPlacedResidentKernelDispatchReadiness>,
    pub dispatch_count: usize,
    pub instantiable_count: usize,
    pub blocked_count: usize,
    pub missing_loaded_artifact_count: usize,
    pub descriptor_binding_blocked_count: usize,
    pub push_constant_blocked_count: usize,
    pub instantiable_descriptor_count: usize,
}

impl VulkanMountedPlacedResidentKernelDispatchReadinessPlan {
    fn from_mounted_bound_plan(
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
    ) -> Self {
        let mut instantiable_count = 0usize;
        let mut blocked_count = 0usize;
        let mut missing_loaded_artifact_count = 0usize;
        let mut descriptor_binding_blocked_count = 0usize;
        let mut push_constant_blocked_count = 0usize;
        let mut instantiable_descriptor_count = 0usize;

        let dispatches = mounted_bound_plan
            .dispatches
            .iter()
            .map(|dispatch| {
                let status = mounted.resident_kernel_dispatch_readiness_for_bound_dispatch(
                    dispatch,
                    loaded_manifest,
                );
                match &status {
                    VulkanMountedPlacedResidentKernelDispatchStatus::Instantiable {
                        descriptor_count,
                        ..
                    } => {
                        instantiable_count += 1;
                        instantiable_descriptor_count += descriptor_count;
                    }
                    VulkanMountedPlacedResidentKernelDispatchStatus::Blocked { error } => {
                        blocked_count += 1;
                        match error {
                            VulkanMountedPlacedResidentKernelDispatchError::MissingLoadedArtifact {
                                ..
                            } => missing_loaded_artifact_count += 1,
                            VulkanMountedPlacedResidentKernelDispatchError::UnsupportedPushConstantScalar {
                                ..
                            }
                            | VulkanMountedPlacedResidentKernelDispatchError::UnsupportedPushConstantBinding {
                                ..
                            }
                            | VulkanMountedPlacedResidentKernelDispatchError::PushConstantByteCountOverflow => {
                                push_constant_blocked_count += 1;
                            }
                            _ => descriptor_binding_blocked_count += 1,
                        }
                    }
                }
                VulkanMountedPlacedResidentKernelDispatchReadiness {
                    dispatch_index: dispatch.dispatch_index,
                    kernel_id: dispatch.kernel_id.clone(),
                    pedal_id: dispatch.pedal_id.clone(),
                    node_id: dispatch.node_id.clone(),
                    op: dispatch.op.clone(),
                    reusable_family_id: dispatch.reusable_family_id.clone(),
                    status,
                }
            })
            .collect::<Vec<_>>();

        let dispatch_count = dispatches.len();
        Self {
            backend_id: mounted_bound_plan.backend_id.clone(),
            device_id: mounted_bound_plan.device_id.clone(),
            dispatches,
            dispatch_count,
            instantiable_count,
            blocked_count,
            missing_loaded_artifact_count,
            descriptor_binding_blocked_count,
            push_constant_blocked_count,
            instantiable_descriptor_count,
        }
    }

    pub fn dispatch(
        &self,
        pedal_id: &str,
        node_id: &str,
    ) -> Option<&VulkanMountedPlacedResidentKernelDispatchReadiness> {
        self.dispatches
            .iter()
            .find(|dispatch| dispatch.pedal_id == pedal_id && dispatch.node_id == node_id)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentKernelDispatchReadiness {
    pub dispatch_index: usize,
    pub kernel_id: String,
    pub pedal_id: String,
    pub node_id: String,
    pub op: String,
    pub reusable_family_id: String,
    pub status: VulkanMountedPlacedResidentKernelDispatchStatus,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanMountedPlacedResidentKernelDispatchStatus {
    Instantiable {
        descriptor_count: usize,
        workgroup_count_x: u32,
        local_size_x: u32,
        push_constant_byte_count: u32,
    },
    Blocked {
        error: VulkanMountedPlacedResidentKernelDispatchError,
    },
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanPlacedLocalCableBufferBinding {
    pub buffer_index: usize,
    pub cable: VulkanPlacedLocalCable,
    pub byte_capacity: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanPlacedCableEndpointBufferBinding {
    pub buffer_index: usize,
    pub endpoint: VulkanPlacedCableEndpoint,
    pub byte_capacity: usize,
}

fn bind_local_cable_buffer(
    dispatch: &VulkanPlacedBoundDispatch,
    descriptor: &VulkanPlacedBoundDescriptor,
    cable_index: usize,
    cable_io: &VulkanPlacedCableIoBuffers,
) -> Result<VulkanPlacedLocalCableBufferBinding, VulkanBoundDispatchPlanError> {
    let (buffer_index, allocation) = cable_io.local_buffer(cable_index).ok_or({
        VulkanBoundDispatchPlanError::MissingLocalCableBuffer {
            dispatch_index: dispatch.dispatch_index,
            binding: descriptor.binding,
            cable_index,
        }
    })?;
    if allocation.cable.byte_capacity != Some(allocation.byte_capacity) {
        return Err(
            VulkanBoundDispatchPlanError::LocalCableByteCapacityMismatch {
                dispatch_index: dispatch.dispatch_index,
                binding: descriptor.binding,
                cable_index,
                cable_byte_capacity: allocation.cable.byte_capacity,
                mounted_byte_capacity: allocation.byte_capacity,
            },
        );
    }

    Ok(VulkanPlacedLocalCableBufferBinding {
        buffer_index,
        cable: allocation.cable.clone(),
        byte_capacity: allocation.byte_capacity,
    })
}

fn bind_cable_endpoint_buffer(
    dispatch: &VulkanPlacedBoundDispatch,
    descriptor: &VulkanPlacedBoundDescriptor,
    direction: VulkanPlacedCableDirection,
    cable_index: usize,
    cable_io: &VulkanPlacedCableIoBuffers,
) -> Result<VulkanPlacedCableEndpointBufferBinding, VulkanBoundDispatchPlanError> {
    let (buffer_index, allocation) = cable_io.buffer(direction, cable_index).ok_or({
        VulkanBoundDispatchPlanError::MissingCableEndpointBuffer {
            dispatch_index: dispatch.dispatch_index,
            binding: descriptor.binding,
            direction,
            cable_index,
        }
    })?;
    if allocation.endpoint.byte_capacity != Some(allocation.byte_capacity) {
        return Err(
            VulkanBoundDispatchPlanError::CableEndpointByteCapacityMismatch {
                dispatch_index: dispatch.dispatch_index,
                binding: descriptor.binding,
                cable_index,
                endpoint_byte_capacity: allocation.endpoint.byte_capacity,
                mounted_byte_capacity: allocation.byte_capacity,
            },
        );
    }

    Ok(VulkanPlacedCableEndpointBufferBinding {
        buffer_index,
        endpoint: allocation.endpoint.clone(),
        byte_capacity: allocation.byte_capacity,
    })
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedStreamTickPlan {
    pub backend_id: String,
    pub device_id: String,
    pub stages: Vec<VulkanMountedPlacedStreamTickStage>,
    pub stage_count: usize,
    pub receive_stage_count: usize,
    pub dispatch_stage_count: usize,
    pub publish_stage_count: usize,
    pub local_cable_read_count: usize,
    pub local_cable_write_count: usize,
    pub incoming_cable_read_count: usize,
    pub outgoing_cable_write_count: usize,
    pub model_input_read_count: usize,
    pub model_output_write_count: usize,
    pub can_execute: bool,
}

impl VulkanMountedPlacedStreamTickPlan {
    pub fn from_mounted_bound_plan(
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
    ) -> Self {
        let mut stages = Vec::new();
        let mut received_endpoints = BTreeSet::<(usize, usize)>::new();
        let mut published_endpoints = BTreeSet::<(usize, usize)>::new();

        let mut local_cable_read_count = 0usize;
        let mut local_cable_write_count = 0usize;
        let mut incoming_cable_read_count = 0usize;
        let mut outgoing_cable_write_count = 0usize;
        let mut model_input_read_count = 0usize;
        let mut model_output_write_count = 0usize;

        for dispatch in &mounted_bound_plan.dispatches {
            let dispatch_stage =
                VulkanMountedPlacedStreamTickDispatch::from_bound_dispatch(dispatch);
            local_cable_read_count += dispatch_stage
                .reads
                .iter()
                .filter(|io| matches!(io, VulkanMountedPlacedStreamTickIo::LocalCableBuffer { .. }))
                .count();
            local_cable_write_count += dispatch_stage
                .writes
                .iter()
                .filter(|io| matches!(io, VulkanMountedPlacedStreamTickIo::LocalCableBuffer { .. }))
                .count();
            incoming_cable_read_count += dispatch_stage
                .reads
                .iter()
                .filter(|io| {
                    matches!(
                        io,
                        VulkanMountedPlacedStreamTickIo::IncomingCableBuffer { .. }
                    )
                })
                .count();
            outgoing_cable_write_count += dispatch_stage
                .writes
                .iter()
                .filter(|io| {
                    matches!(
                        io,
                        VulkanMountedPlacedStreamTickIo::OutgoingCableBuffer { .. }
                    )
                })
                .count();
            model_input_read_count += dispatch_stage
                .reads
                .iter()
                .filter(|io| matches!(io, VulkanMountedPlacedStreamTickIo::ModelSignal { .. }))
                .count();
            model_output_write_count += dispatch_stage
                .writes
                .iter()
                .filter(|io| matches!(io, VulkanMountedPlacedStreamTickIo::ModelSignal { .. }))
                .count();

            for descriptor in &dispatch.descriptors {
                if let VulkanMountedPlacedBoundDescriptorTarget::IncomingCableBuffer { endpoint } =
                    &descriptor.target
                    && received_endpoints
                        .insert((endpoint.endpoint.cable_index, endpoint.buffer_index))
                {
                    stages.push(VulkanMountedPlacedStreamTickStage::ReceiveCable {
                        stage_index: stages.len(),
                        cable_index: endpoint.endpoint.cable_index,
                        endpoint_id: endpoint.endpoint.endpoint_id.clone(),
                        buffer_index: endpoint.buffer_index,
                        byte_capacity: endpoint.byte_capacity,
                        remote_device_id: endpoint.endpoint.remote_device_id.clone(),
                        remote_pedal_id: endpoint.endpoint.remote_pedal_id.clone(),
                    });
                }
            }

            stages.push(VulkanMountedPlacedStreamTickStage::Dispatch {
                stage_index: stages.len(),
                dispatch: dispatch_stage,
            });

            for descriptor in &dispatch.descriptors {
                if let VulkanMountedPlacedBoundDescriptorTarget::OutgoingCableBuffer { endpoint } =
                    &descriptor.target
                    && published_endpoints
                        .insert((endpoint.endpoint.cable_index, endpoint.buffer_index))
                {
                    stages.push(VulkanMountedPlacedStreamTickStage::PublishCable {
                        stage_index: stages.len(),
                        cable_index: endpoint.endpoint.cable_index,
                        endpoint_id: endpoint.endpoint.endpoint_id.clone(),
                        buffer_index: endpoint.buffer_index,
                        byte_capacity: endpoint.byte_capacity,
                        remote_device_id: endpoint.endpoint.remote_device_id.clone(),
                        remote_pedal_id: endpoint.endpoint.remote_pedal_id.clone(),
                    });
                }
            }
        }

        let receive_stage_count = received_endpoints.len();
        let publish_stage_count = published_endpoints.len();
        let dispatch_stage_count = mounted_bound_plan.dispatches.len();
        let stage_count = stages.len();

        Self {
            backend_id: mounted_bound_plan.backend_id.clone(),
            device_id: mounted_bound_plan.device_id.clone(),
            stages,
            stage_count,
            receive_stage_count,
            dispatch_stage_count,
            publish_stage_count,
            local_cable_read_count,
            local_cable_write_count,
            incoming_cable_read_count,
            outgoing_cable_write_count,
            model_input_read_count,
            model_output_write_count,
            can_execute: false,
        }
    }

    pub fn advance(&self, stream_tick: u64) -> VulkanMountedPlacedStreamTickRun {
        let mut stages = Vec::with_capacity(self.stages.len());
        let mut blocked = None;
        let mut attempted_stage_count = 0usize;
        let mut completed_stage_count = 0usize;

        for stage in &self.stages {
            let status = if blocked.is_some() {
                VulkanMountedPlacedStreamTickStageStatus::Pending
            } else {
                attempted_stage_count += 1;
                let reason = match stage {
                    VulkanMountedPlacedStreamTickStage::ReceiveCable { .. } => {
                        VulkanMountedPlacedStreamTickBlockReason::CableReceiveTransportUnavailable
                    }
                    VulkanMountedPlacedStreamTickStage::Dispatch { .. } => {
                        VulkanMountedPlacedStreamTickBlockReason::KernelDispatchUnavailable
                    }
                    VulkanMountedPlacedStreamTickStage::PublishCable { .. } => {
                        VulkanMountedPlacedStreamTickBlockReason::CablePublishTransportUnavailable
                    }
                };
                blocked = Some((stage.stage_index(), reason.clone()));
                VulkanMountedPlacedStreamTickStageStatus::Blocked { reason }
            };
            if matches!(status, VulkanMountedPlacedStreamTickStageStatus::Completed) {
                completed_stage_count += 1;
            }
            stages.push(VulkanMountedPlacedStreamTickStageRun {
                stage_index: stage.stage_index(),
                stage: stage.clone(),
                status,
            });
        }

        let pending_stage_count = stages
            .iter()
            .filter(|stage| {
                matches!(
                    stage.status,
                    VulkanMountedPlacedStreamTickStageStatus::Pending
                )
            })
            .count();
        let status = blocked
            .map(
                |(stage_index, reason)| VulkanMountedPlacedStreamTickRunStatus::Blocked {
                    stage_index,
                    reason,
                },
            )
            .unwrap_or(VulkanMountedPlacedStreamTickRunStatus::Completed);

        VulkanMountedPlacedStreamTickRun {
            backend_id: self.backend_id.clone(),
            device_id: self.device_id.clone(),
            stream_tick,
            stages,
            planned_stage_count: self.stage_count,
            attempted_stage_count,
            completed_stage_count,
            pending_stage_count,
            status,
            can_execute: self.can_execute,
        }
    }

    pub fn advance_with_in_process_transport(
        &self,
        mounted: &VulkanMountedPlacedStreamCircuit,
        transport: &mut VulkanInProcessPlacedCableTransport,
        stream_tick: u64,
    ) -> Result<VulkanMountedPlacedStreamTickRun, VulkanMountedPlacedStreamTickTransportError> {
        if self.device_id != mounted.device_id() {
            return Err(
                VulkanMountedPlacedStreamTickTransportError::DeviceMismatch {
                    plan_device_id: self.device_id.clone(),
                    mounted_device_id: mounted.device_id().to_string(),
                },
            );
        }

        let mut stages = Vec::with_capacity(self.stages.len());
        let mut blocked = None;
        let mut attempted_stage_count = 0usize;
        let mut completed_stage_count = 0usize;

        for stage in &self.stages {
            let status = if blocked.is_some() {
                VulkanMountedPlacedStreamTickStageStatus::Pending
            } else {
                attempted_stage_count += 1;
                match stage {
                    VulkanMountedPlacedStreamTickStage::ReceiveCable { cable_index, .. } => {
                        match transport.receive_incoming_cable(mounted, *cable_index) {
                            Ok(_) => {
                                completed_stage_count += 1;
                                VulkanMountedPlacedStreamTickStageStatus::Completed
                            }
                            Err(VulkanPlacedCableTransportError::MissingPacket { .. }) => {
                                let reason =
                                    VulkanMountedPlacedStreamTickBlockReason::CableReceiveTransportUnavailable;
                                blocked = Some((stage.stage_index(), reason.clone()));
                                VulkanMountedPlacedStreamTickStageStatus::Blocked { reason }
                            }
                            Err(error) => {
                                return Err(
                                    VulkanMountedPlacedStreamTickTransportError::Transport(error),
                                );
                            }
                        }
                    }
                    VulkanMountedPlacedStreamTickStage::Dispatch { .. } => {
                        let reason =
                            VulkanMountedPlacedStreamTickBlockReason::KernelDispatchUnavailable;
                        blocked = Some((stage.stage_index(), reason.clone()));
                        VulkanMountedPlacedStreamTickStageStatus::Blocked { reason }
                    }
                    VulkanMountedPlacedStreamTickStage::PublishCable { cable_index, .. } => {
                        transport
                            .publish_outgoing_cable(mounted, *cable_index)
                            .map_err(VulkanMountedPlacedStreamTickTransportError::Transport)?;
                        completed_stage_count += 1;
                        VulkanMountedPlacedStreamTickStageStatus::Completed
                    }
                }
            };
            stages.push(VulkanMountedPlacedStreamTickStageRun {
                stage_index: stage.stage_index(),
                stage: stage.clone(),
                status,
            });
        }

        let pending_stage_count = stages
            .iter()
            .filter(|stage| {
                matches!(
                    stage.status,
                    VulkanMountedPlacedStreamTickStageStatus::Pending
                )
            })
            .count();
        let status = blocked
            .map(
                |(stage_index, reason)| VulkanMountedPlacedStreamTickRunStatus::Blocked {
                    stage_index,
                    reason,
                },
            )
            .unwrap_or(VulkanMountedPlacedStreamTickRunStatus::Completed);

        Ok(VulkanMountedPlacedStreamTickRun {
            backend_id: self.backend_id.clone(),
            device_id: self.device_id.clone(),
            stream_tick,
            stages,
            planned_stage_count: self.stage_count,
            attempted_stage_count,
            completed_stage_count,
            pending_stage_count,
            status,
            can_execute: self.can_execute,
        })
    }

    pub fn advance_with_resident_pedalboard_and_in_process_transport(
        &self,
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
        transport: &mut VulkanInProcessPlacedCableTransport,
        stream_tick: u64,
    ) -> Result<VulkanMountedPlacedResidentStreamTickRun, VulkanMountedPlacedResidentStreamTickError>
    {
        let mut cursor = self.resident_stream_tick_cursor(stream_tick);
        cursor.advance_with_resident_pedals_and_in_process_transport(
            device,
            mounted,
            mounted_bound_plan,
            loaded_manifest,
            transport,
        )?;
        Ok(cursor.snapshot())
    }

    pub fn resident_stream_tick_cursor(
        &self,
        stream_tick: u64,
    ) -> VulkanMountedPlacedResidentStreamTickCursor {
        VulkanMountedPlacedResidentStreamTickCursor::new(self.clone(), stream_tick)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentStreamTickCursor {
    pub tick_plan: Arc<VulkanMountedPlacedStreamTickPlan>,
    pub stream_tick: u64,
    pub next_stage_index: usize,
    pub completed_stage_count: usize,
    pub pedal_runs: Vec<VulkanMountedPlacedResidentPedalRun>,
    capture_execution_trace: bool,
    last_blocked: Option<(usize, VulkanMountedPlacedStreamTickBlockReason)>,
}

impl VulkanMountedPlacedResidentStreamTickCursor {
    pub fn new(tick_plan: VulkanMountedPlacedStreamTickPlan, stream_tick: u64) -> Self {
        Self::new_shared(Arc::new(tick_plan), stream_tick, true)
    }

    fn new_shared(
        tick_plan: Arc<VulkanMountedPlacedStreamTickPlan>,
        stream_tick: u64,
        capture_execution_trace: bool,
    ) -> Self {
        Self {
            tick_plan,
            stream_tick,
            next_stage_index: 0,
            completed_stage_count: 0,
            pedal_runs: Vec::new(),
            capture_execution_trace,
            last_blocked: None,
        }
    }

    pub fn is_completed(&self) -> bool {
        self.next_stage_index == self.tick_plan.stages.len()
    }

    pub fn advance_with_resident_pedals_and_in_process_transport(
        &mut self,
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        mounted_bound_plan: &VulkanMountedPlacedBoundDispatchPlan,
        loaded_manifest: &VulkanLoadedReusableKernelArtifactManifest,
        transport: &mut VulkanInProcessPlacedCableTransport,
    ) -> Result<
        VulkanMountedPlacedResidentStreamTickCursorAdvance,
        VulkanMountedPlacedResidentStreamTickError,
    > {
        let execution_plan = VulkanMountedPlacedResidentStreamTickExecutionPlan::from_tick_plan(
            device,
            mounted,
            mounted_bound_plan,
            loaded_manifest,
            self.tick_plan.as_ref().clone(),
        )
        .map_err(VulkanMountedPlacedResidentStreamTickError::Dispatch)?;
        let dispatch_extensions =
            VulkanMountedPlacedResidentStreamTickDispatchExtensions::default();
        self.advance_with_resident_execution_plan_and_in_process_transport(
            device,
            mounted,
            &execution_plan,
            &dispatch_extensions,
            transport,
        )
    }

    pub fn advance_with_resident_execution_plan_and_in_process_transport(
        &mut self,
        device: &VulkanComputeDevice,
        mounted: &VulkanMountedPlacedStreamCircuit,
        execution_plan: &VulkanMountedPlacedResidentStreamTickExecutionPlan,
        dispatch_extensions: &VulkanMountedPlacedResidentStreamTickDispatchExtensions<'_>,
        transport: &mut VulkanInProcessPlacedCableTransport,
    ) -> Result<
        VulkanMountedPlacedResidentStreamTickCursorAdvance,
        VulkanMountedPlacedResidentStreamTickError,
    > {
        if self.tick_plan.device_id != mounted.device_id() {
            return Err(VulkanMountedPlacedResidentStreamTickError::DeviceMismatch {
                plan_device_id: self.tick_plan.device_id.clone(),
                mounted_device_id: mounted.device_id().to_string(),
            });
        }
        if self.tick_plan.device_id != execution_plan.tick_plan.device_id {
            return Err(
                VulkanMountedPlacedResidentStreamTickError::BoundPlanDeviceMismatch {
                    plan_device_id: self.tick_plan.device_id.clone(),
                    bound_plan_device_id: execution_plan.tick_plan.device_id.clone(),
                },
            );
        }

        let dynamic_state_capacity_activations =
            u32::try_from(mounted.buffers.dynamic_state_capacity_activations).map_err(|_| {
                VulkanMountedPlacedResidentStreamTickError::DynamicStateCapacityOverflow {
                    capacity: mounted.buffers.dynamic_state_capacity_activations,
                }
            })?;
        let control = VulkanMountedPlacedStreamControl {
            stream_tick: self.stream_tick,
            control_flags: 0,
            dynamic_state_capacity_activations,
        };

        self.last_blocked = None;
        let completed_before = self.completed_stage_count;

        while self.next_stage_index < self.tick_plan.stages.len() {
            let stage = &self.tick_plan.stages[self.next_stage_index];
            match stage {
                VulkanMountedPlacedStreamTickStage::ReceiveCable { cable_index, .. } => {
                    match transport.receive_incoming_cable(mounted, *cable_index) {
                        Ok(_) => self.complete_current_stage(),
                        Err(VulkanPlacedCableTransportError::MissingPacket { .. }) => {
                            let reason =
                                VulkanMountedPlacedStreamTickBlockReason::CableReceiveTransportUnavailable;
                            self.last_blocked = Some((stage.stage_index(), reason));
                            return Ok(self.advance_report(completed_before));
                        }
                        Err(error) => {
                            return Err(VulkanMountedPlacedResidentStreamTickError::Transport(
                                error,
                            ));
                        }
                    }
                }
                VulkanMountedPlacedStreamTickStage::Dispatch { .. } => {
                    if let Some(dispatch) =
                        execution_plan.distributed_dispatch_at_stage(self.next_stage_index)
                    {
                        self.last_blocked = Some((
                            stage.stage_index(),
                            VulkanMountedPlacedStreamTickBlockReason::DistributedDispatchPending {
                                dispatch_index: dispatch.dispatch_index,
                            },
                        ));
                        return Ok(self.advance_report(completed_before));
                    }
                    let segment = execution_plan
                        .segment_starting_at(self.next_stage_index)
                        .ok_or_else(|| {
                            VulkanMountedPlacedResidentStreamTickError::Dispatch(
                                VulkanMountedPlacedResidentKernelDispatchError::MissingDispatchSegment {
                                    device_id: mounted.device_id().to_string(),
                                    stage_index: self.next_stage_index,
                                },
                            )
                        })?;
                    self.pedal_runs.extend(
                        segment
                            .run_with_stream_control(
                                device,
                                control,
                                if execution_plan.first_dispatch_segment_stage_index()
                                    == Some(segment.start_stage_index)
                                {
                                    &dispatch_extensions.prefix_dispatches
                                } else {
                                    &[]
                                },
                                if execution_plan.last_dispatch_segment_stage_index()
                                    == Some(segment.start_stage_index)
                                {
                                    &dispatch_extensions.suffix_dispatches
                                } else {
                                    &[]
                                },
                                dispatch_extensions.sequence_variant,
                                self.capture_execution_trace,
                            )
                            .map_err(VulkanMountedPlacedResidentStreamTickError::Dispatch)?,
                    );
                    while self.next_stage_index < segment.end_stage_index {
                        self.complete_current_stage();
                    }
                }
                VulkanMountedPlacedStreamTickStage::PublishCable { cable_index, .. } => {
                    transport
                        .publish_outgoing_cable(mounted, *cable_index)
                        .map_err(VulkanMountedPlacedResidentStreamTickError::Transport)?;
                    self.complete_current_stage();
                }
            }
        }

        Ok(self.advance_report(completed_before))
    }

    fn pending_distributed_dispatch<'a>(
        &self,
        execution_plan: &'a VulkanMountedPlacedResidentStreamTickExecutionPlan,
    ) -> Option<&'a VulkanMountedPlacedStreamTickDispatch> {
        execution_plan.distributed_dispatch_at_stage(self.next_stage_index)
    }

    fn complete_pending_distributed_dispatch(
        &mut self,
        execution_plan: &VulkanMountedPlacedResidentStreamTickExecutionPlan,
        dispatch_index: usize,
    ) -> Result<(), VulkanMountedPlacedResidentStreamTickError> {
        let dispatch = self
            .pending_distributed_dispatch(execution_plan)
            .ok_or_else(|| {
                VulkanMountedPlacedResidentStreamTickError::Dispatch(
                    VulkanMountedPlacedResidentKernelDispatchError::MissingDispatchSegment {
                        device_id: execution_plan.tick_plan.device_id.clone(),
                        stage_index: self.next_stage_index,
                    },
                )
            })?;
        if dispatch.dispatch_index != dispatch_index {
            return Err(VulkanMountedPlacedResidentStreamTickError::Dispatch(
                VulkanMountedPlacedResidentKernelDispatchError::DistributedDispatchMismatch {
                    device_id: execution_plan.tick_plan.device_id.clone(),
                    stage_index: self.next_stage_index,
                    expected_dispatch_index: dispatch.dispatch_index,
                    completed_dispatch_index: dispatch_index,
                },
            ));
        }
        self.last_blocked = None;
        self.complete_current_stage();
        Ok(())
    }

    fn complete_current_stage(&mut self) {
        self.completed_stage_count += 1;
        self.next_stage_index += 1;
    }

    fn advance_report(
        &self,
        completed_before: usize,
    ) -> VulkanMountedPlacedResidentStreamTickCursorAdvance {
        VulkanMountedPlacedResidentStreamTickCursorAdvance {
            completed_stage_delta: self.completed_stage_count - completed_before,
            completed: self.is_completed(),
        }
    }

    pub fn snapshot(&self) -> VulkanMountedPlacedResidentStreamTickRun {
        let stages = if self.capture_execution_trace {
            let mut stages = Vec::with_capacity(self.tick_plan.stages.len());
            for (index, stage) in self.tick_plan.stages.iter().enumerate() {
                let status = if index < self.next_stage_index {
                    VulkanMountedPlacedStreamTickStageStatus::Completed
                } else if self
                    .last_blocked
                    .as_ref()
                    .is_some_and(|(stage_index, _)| *stage_index == index)
                {
                    VulkanMountedPlacedStreamTickStageStatus::Blocked {
                        reason: self.last_blocked.as_ref().unwrap().1.clone(),
                    }
                } else {
                    VulkanMountedPlacedStreamTickStageStatus::Pending
                };
                stages.push(VulkanMountedPlacedStreamTickStageRun {
                    stage_index: stage.stage_index(),
                    stage: stage.clone(),
                    status,
                });
            }
            stages
        } else {
            Vec::new()
        };
        let blocked_stage_count = usize::from(self.last_blocked.is_some());
        let pending_stage_count = self.tick_plan.stage_count.saturating_sub(
            self.completed_stage_count
                .saturating_add(blocked_stage_count),
        );
        let status = self
            .last_blocked
            .clone()
            .map(
                |(stage_index, reason)| VulkanMountedPlacedStreamTickRunStatus::Blocked {
                    stage_index,
                    reason,
                },
            )
            .unwrap_or_else(|| {
                if self.is_completed() {
                    VulkanMountedPlacedStreamTickRunStatus::Completed
                } else {
                    VulkanMountedPlacedStreamTickRunStatus::Blocked {
                        stage_index: self.next_stage_index,
                        reason: VulkanMountedPlacedStreamTickBlockReason::KernelDispatchUnavailable,
                    }
                }
            });
        let attempted_stage_count =
            self.completed_stage_count + usize::from(self.last_blocked.is_some());

        VulkanMountedPlacedResidentStreamTickRun {
            tick_run: VulkanMountedPlacedStreamTickRun {
                backend_id: self.tick_plan.backend_id.clone(),
                device_id: self.tick_plan.device_id.clone(),
                stream_tick: self.stream_tick,
                stages,
                planned_stage_count: self.tick_plan.stage_count,
                attempted_stage_count,
                completed_stage_count: self.completed_stage_count,
                pending_stage_count,
                status,
                can_execute: true,
            },
            pedalboard_run: if !self.capture_execution_trace || self.pedal_runs.is_empty() {
                None
            } else {
                Some(VulkanMountedPlacedResidentPedalboardRun {
                    device_id: self.tick_plan.device_id.clone(),
                    pedal_runs: self.pedal_runs.clone(),
                })
            },
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentStreamTickCursorAdvance {
    pub completed_stage_delta: usize,
    pub completed: bool,
}

#[derive(Default)]
pub struct VulkanMountedPlacedResidentStreamTickDispatchExtensions<'a> {
    pub prefix_dispatches: SmallVec<[&'a VulkanResidentKernelDispatch; 1]>,
    pub suffix_dispatches: SmallVec<[&'a VulkanResidentKernelDispatch; 3]>,
    sequence_variant: u8,
}

pub struct VulkanMountedPlacedResidentInProcessStreamTickSlice<'a> {
    pub device: &'a VulkanComputeDevice,
    pub mounted: &'a VulkanMountedPlacedStreamCircuit,
    pub execution_plan: &'a VulkanMountedPlacedResidentStreamTickExecutionPlan,
    pub dispatch_extensions: VulkanMountedPlacedResidentStreamTickDispatchExtensions<'a>,
    pub cursor: VulkanMountedPlacedResidentStreamTickCursor,
}

impl<'a> VulkanMountedPlacedResidentInProcessStreamTickSlice<'a> {
    pub fn new(
        device: &'a VulkanComputeDevice,
        mounted: &'a VulkanMountedPlacedStreamCircuit,
        execution_plan: &'a VulkanMountedPlacedResidentStreamTickExecutionPlan,
        stream_tick: u64,
    ) -> Self {
        Self {
            device,
            mounted,
            execution_plan,
            dispatch_extensions: VulkanMountedPlacedResidentStreamTickDispatchExtensions::default(),
            cursor: execution_plan.resident_stream_tick_cursor(stream_tick),
        }
    }

    pub fn new_with_dispatch_extensions(
        device: &'a VulkanComputeDevice,
        mounted: &'a VulkanMountedPlacedStreamCircuit,
        execution_plan: &'a VulkanMountedPlacedResidentStreamTickExecutionPlan,
        dispatch_extensions: VulkanMountedPlacedResidentStreamTickDispatchExtensions<'a>,
        stream_tick: u64,
    ) -> Self {
        Self {
            device,
            mounted,
            execution_plan,
            dispatch_extensions,
            cursor: execution_plan.compact_resident_stream_tick_cursor(stream_tick),
        }
    }

    pub fn device_id(&self) -> &str {
        self.mounted.device_id()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentInProcessStreamTickRun {
    pub status: VulkanMountedPlacedResidentInProcessStreamTickRunStatus,
    pub scheduler_turn_count: usize,
    pub completed_stage_delta: usize,
    pub completed_slice_count: usize,
    pub pending_slice_count: usize,
    pub transport_stats: VulkanPlacedCableTransportStats,
    pub device_runs: Vec<VulkanMountedPlacedResidentStreamTickRun>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanMountedPlacedResidentInProcessStreamTickRunStatus {
    Completed,
    Blocked { pending_device_ids: Vec<String> },
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct VulkanMountedPlacedResidentInProcessSchedule {
    device_ids: Vec<String>,
    turns: Vec<Vec<usize>>,
}

impl VulkanMountedPlacedResidentInProcessSchedule {
    fn from_tick_plans(
        tick_plans: &[&VulkanMountedPlacedStreamTickPlan],
    ) -> Result<Self, VulkanError> {
        let device_ids = tick_plans
            .iter()
            .map(|plan| plan.device_id.clone())
            .collect::<Vec<_>>();
        let mut unique_device_ids = BTreeSet::new();
        for device_id in &device_ids {
            if !unique_device_ids.insert(device_id.clone()) {
                return Err(VulkanError(format!(
                    "placed activation schedule repeats device {device_id:?}"
                )));
            }
        }

        let mut next_stage_indices = vec![0usize; tick_plans.len()];
        let mut ready_cables = BTreeSet::<VulkanPlacedCablePacketKey>::new();
        let mut turns = Vec::new();

        while tick_plans
            .iter()
            .enumerate()
            .any(|(index, plan)| next_stage_indices[index] < plan.stages.len())
        {
            let mut turn = Vec::new();
            for (device_index, plan) in tick_plans.iter().enumerate() {
                let completed_before = next_stage_indices[device_index];
                while next_stage_indices[device_index] < plan.stages.len() {
                    match &plan.stages[next_stage_indices[device_index]] {
                        VulkanMountedPlacedStreamTickStage::ReceiveCable {
                            cable_index,
                            remote_device_id,
                            ..
                        } => {
                            let key = VulkanPlacedCablePacketKey {
                                cable_index: *cable_index,
                                from_device_id: remote_device_id.clone(),
                                to_device_id: plan.device_id.clone(),
                            };
                            if !ready_cables.remove(&key) {
                                break;
                            }
                        }
                        VulkanMountedPlacedStreamTickStage::Dispatch { .. } => {}
                        VulkanMountedPlacedStreamTickStage::PublishCable {
                            cable_index,
                            remote_device_id,
                            ..
                        } => {
                            ready_cables.insert(VulkanPlacedCablePacketKey {
                                cable_index: *cable_index,
                                from_device_id: plan.device_id.clone(),
                                to_device_id: remote_device_id.clone(),
                            });
                        }
                    }
                    next_stage_indices[device_index] += 1;
                }
                if next_stage_indices[device_index] != completed_before {
                    turn.push(device_index);
                }
            }

            if turn.is_empty() {
                let pending_device_ids = tick_plans
                    .iter()
                    .enumerate()
                    .filter(|(index, plan)| next_stage_indices[*index] < plan.stages.len())
                    .map(|(_, plan)| plan.device_id.clone())
                    .collect::<Vec<_>>();
                return Err(VulkanError(format!(
                    "placed activation topology is blocked with pending devices {pending_device_ids:?}"
                )));
            }
            turns.push(turn);
        }

        if !ready_cables.is_empty() {
            return Err(VulkanError(format!(
                "placed activation topology leaves unconsumed cables {:?}",
                ready_cables.into_iter().collect::<Vec<_>>()
            )));
        }

        Ok(Self { device_ids, turns })
    }

    fn validate_slices(
        &self,
        slices: &[VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    ) -> Result<(), VulkanError> {
        if slices.len() != self.device_ids.len() {
            return Err(VulkanError(format!(
                "placed activation schedule expects {} device slices, found {}",
                self.device_ids.len(),
                slices.len()
            )));
        }
        for (device_index, (expected, slice)) in self.device_ids.iter().zip(slices).enumerate() {
            if expected != slice.device_id() {
                return Err(VulkanError(format!(
                    "placed activation schedule device {device_index} is {expected:?}, found {:?}",
                    slice.device_id()
                )));
            }
        }
        Ok(())
    }
}

#[derive(Debug)]
pub enum VulkanMountedPlacedResidentInProcessStreamTickError {
    StreamTick(VulkanMountedPlacedResidentStreamTickError),
    Distributed(VulkanDistributedDispatchRunnerError),
    Schedule(VulkanError),
}

impl Display for VulkanMountedPlacedResidentInProcessStreamTickError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::StreamTick(error) => Display::fmt(error, f),
            Self::Distributed(error) => Display::fmt(error, f),
            Self::Schedule(error) => Display::fmt(error, f),
        }
    }
}

impl Error for VulkanMountedPlacedResidentInProcessStreamTickError {}

impl From<VulkanMountedPlacedResidentStreamTickError>
    for VulkanMountedPlacedResidentInProcessStreamTickError
{
    fn from(error: VulkanMountedPlacedResidentStreamTickError) -> Self {
        Self::StreamTick(error)
    }
}

fn register_in_process_direct_cable_copies(
    slices: &[VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    transport: &mut VulkanInProcessPlacedCableTransport,
) -> Result<(), VulkanMountedPlacedResidentInProcessStreamTickError> {
    for source_slice in slices {
        for outgoing in &source_slice.mounted.cable_io.outgoing_buffers {
            let destination_slice = slices
                .iter()
                .find(|slice| slice.device_id() == outgoing.endpoint.remote_device_id);
            let Some(destination_slice) = destination_slice else {
                continue;
            };
            let Some(incoming) = destination_slice
                .mounted
                .cable_io
                .incoming_buffer(outgoing.endpoint.cable_index)
            else {
                continue;
            };
            transport
                .register_direct_cable_copy(outgoing, incoming)
                .map_err(VulkanMountedPlacedResidentStreamTickError::Transport)?;
        }
    }
    Ok(())
}

fn wait_for_compact_slice_submitted_work(
    slice: &VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>,
    device_by_id: &BTreeMap<String, &VulkanComputeDevice>,
    distributed_runners: &VulkanDistributedDispatchRunners,
    last_submitted_segment: Option<&VulkanMountedPlacedResidentDispatchSegmentRunner>,
    completion_dependency: Option<(usize, u64)>,
) -> Result<(), VulkanMountedPlacedResidentInProcessStreamTickError> {
    if let Some((dispatch_index, _)) = completion_dependency {
        return distributed_runners
            .wait_dispatch(slice.device_id(), dispatch_index, |device_id| {
                device_by_id.get(device_id).copied().ok_or_else(|| {
                    VulkanError(format!(
                        "distributed shard device {device_id:?} is not mounted"
                    ))
                })
            })
            .map_err(VulkanMountedPlacedResidentInProcessStreamTickError::Distributed);
    }
    if let Some(segment) = last_submitted_segment {
        segment
            .wait_submitted(slice.device, slice.dispatch_extensions.sequence_variant)
            .map_err(|error| {
                VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                    VulkanMountedPlacedResidentStreamTickError::Dispatch(error),
                )
            })?;
    }
    Ok(())
}

fn wait_for_compact_slice_terminal_work(
    slice: &VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>,
    device_by_id: &BTreeMap<String, &VulkanComputeDevice>,
    distributed_runners: &VulkanDistributedDispatchRunners,
) -> Result<(), VulkanMountedPlacedResidentInProcessStreamTickError> {
    let terminal_segment = slice.execution_plan.dispatch_segments.last();
    let terminal_distributed = slice
        .execution_plan
        .distributed_dispatch_stages
        .iter()
        .next_back();
    if terminal_distributed.is_some_and(|(stage_index, _)| {
        terminal_segment.is_none_or(|segment| *stage_index >= segment.end_stage_index)
    }) {
        let (_, dispatch) = terminal_distributed.expect("terminal distributed stage exists");
        return distributed_runners
            .wait_dispatch(slice.device_id(), dispatch.dispatch_index, |device_id| {
                device_by_id.get(device_id).copied().ok_or_else(|| {
                    VulkanError(format!(
                        "distributed shard device {device_id:?} is not mounted"
                    ))
                })
            })
            .map_err(VulkanMountedPlacedResidentInProcessStreamTickError::Distributed);
    }
    if let Some(segment) = terminal_segment {
        segment
            .wait_submitted(slice.device, slice.dispatch_extensions.sequence_variant)
            .map_err(|error| {
                VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                    VulkanMountedPlacedResidentStreamTickError::Dispatch(error),
                )
            })?;
    }
    Ok(())
}

fn prepare_compact_shared_stream_control(
    slices: &[VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
) -> Result<(), VulkanMountedPlacedResidentInProcessStreamTickError> {
    let mut compact_slices = slices
        .iter()
        .filter(|slice| !slice.cursor.capture_execution_trace);
    let Some(first) = compact_slices.next() else {
        return Ok(());
    };
    let dynamic_state_capacity_activations =
        u32::try_from(first.mounted.buffers.dynamic_state_capacity_activations).map_err(|_| {
            VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                VulkanMountedPlacedResidentStreamTickError::DynamicStateCapacityOverflow {
                    capacity: first.mounted.buffers.dynamic_state_capacity_activations,
                },
            )
        })?;
    for slice in compact_slices {
        let buffers_alias = Arc::ptr_eq(
            &first.mounted.stream_control_buffer,
            &slice.mounted.stream_control_buffer,
        ) || first
            .mounted
            .stream_control_buffer
            .shares_host_allocation_with(&slice.mounted.stream_control_buffer);
        if !buffers_alias
            || slice.cursor.stream_tick != first.cursor.stream_tick
            || slice.mounted.buffers.dynamic_state_capacity_activations
                != first.mounted.buffers.dynamic_state_capacity_activations
        {
            return Err(
                VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                    "compact placed slices do not share one stream-control timeline".to_string(),
                )),
            );
        }
    }
    first
        .mounted
        .stream_control_buffer
        .write_bytes_at(
            VULKAN_STREAM_CONTROL_METADATA_OFFSET,
            &stream_control_metadata_bytes(VulkanMountedPlacedStreamControl {
                stream_tick: first.cursor.stream_tick,
                control_flags: 0,
                dynamic_state_capacity_activations,
            }),
        )
        .map_err(|error| {
            VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                VulkanMountedPlacedResidentStreamTickError::Dispatch(
                    VulkanMountedPlacedResidentKernelDispatchError::Vulkan(error),
                ),
            )
        })
}

fn advance_compact_slice_with_distributed_dependencies(
    slice: &mut VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>,
    device_by_id: &BTreeMap<String, &VulkanComputeDevice>,
    transport: &mut VulkanInProcessPlacedCableTransport,
    distributed_runners: &VulkanDistributedDispatchRunners,
    cable_synchronizations: &VulkanPlacedCableTimelineSynchronizations,
) -> Result<usize, VulkanMountedPlacedResidentInProcessStreamTickError> {
    debug_assert!(!slice.cursor.capture_execution_trace);
    let dynamic_state_capacity_activations =
        u32::try_from(slice.mounted.buffers.dynamic_state_capacity_activations).map_err(|_| {
            VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                VulkanMountedPlacedResidentStreamTickError::DynamicStateCapacityOverflow {
                    capacity: slice.mounted.buffers.dynamic_state_capacity_activations,
                },
            )
        })?;
    let control = VulkanMountedPlacedStreamControl {
        stream_tick: slice.cursor.stream_tick,
        control_flags: 0,
        dynamic_state_capacity_activations,
    };
    let completed_before = slice.cursor.completed_stage_count;
    let mut last_submitted_segment: Option<&VulkanMountedPlacedResidentDispatchSegmentRunner> =
        None;
    let mut ready_dependency = None;
    let mut completion_dependency = None;
    let mut pending_cable_wait_points = Vec::new();

    while slice.cursor.next_stage_index < slice.cursor.tick_plan.stages.len() {
        let stage = &slice.cursor.tick_plan.stages[slice.cursor.next_stage_index];
        match stage {
            VulkanMountedPlacedStreamTickStage::ReceiveCable { cable_index, .. } => {
                let incoming = slice
                    .mounted
                    .cable_io
                    .incoming_buffer(*cable_index)
                    .ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                            VulkanMountedPlacedResidentStreamTickError::Transport(
                                VulkanPlacedCableTransportError::MissingIncomingCable {
                                    device_id: slice.device_id().to_string(),
                                    cable_index: *cable_index,
                                },
                            ),
                        )
                    })?;
                let cable_key =
                    VulkanPlacedCablePacketKey::from_incoming_endpoint(&incoming.endpoint);
                let uses_shared_allocation = transport.cable_uses_shared_allocation(&cable_key);
                if !uses_shared_allocation {
                    wait_for_compact_slice_submitted_work(
                        slice,
                        device_by_id,
                        distributed_runners,
                        last_submitted_segment.take(),
                        completion_dependency.take(),
                    )?;
                }
                match transport.receive_incoming_cable(slice.mounted, *cable_index) {
                    Ok(_) => {
                        if uses_shared_allocation
                            && let Some(wait_point) = cable_synchronizations
                                .take_destination_wait(&incoming.endpoint)
                                .map_err(
                                    VulkanMountedPlacedResidentInProcessStreamTickError::Schedule,
                                )?
                        {
                            pending_cable_wait_points.push(wait_point);
                        }
                        slice.cursor.complete_current_stage();
                    }
                    Err(VulkanPlacedCableTransportError::MissingPacket { .. }) => break,
                    Err(error) => {
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                                VulkanMountedPlacedResidentStreamTickError::Transport(error),
                            ),
                        );
                    }
                }
            }
            VulkanMountedPlacedStreamTickStage::Dispatch { .. } => {
                if let Some(distributed) = slice
                    .execution_plan
                    .distributed_dispatch_at_stage(slice.cursor.next_stage_index)
                {
                    let dependencies = slice
                        .execution_plan
                        .distributed_dispatch_dependencies_at_stage(slice.cursor.next_stage_index)
                        .expect("every distributed stage has a dependency topology");
                    debug_assert_eq!(dependencies.dispatch_index, distributed.dispatch_index);
                    let consumes_ready = ready_dependency.is_some_and(|(dispatch_index, _)| {
                        dispatch_index == distributed.dispatch_index
                    });
                    if consumes_ready != dependencies.has_owner_producer {
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(
                                VulkanError(format!(
                                    "distributed dispatch {} on device {:?} expected owner producer={}, but queued ready dependency={consumes_ready}",
                                    distributed.dispatch_index,
                                    slice.device_id(),
                                    dependencies.has_owner_producer
                                )),
                            ),
                        );
                    }
                    let dependency_value = if let Some((_, dependency_value)) = ready_dependency {
                        dependency_value
                    } else {
                        distributed_runners
                            .reserve_dependency_value(slice.device_id(), distributed.dispatch_index)
                            .map_err(
                                VulkanMountedPlacedResidentInProcessStreamTickError::Distributed,
                            )?
                    };
                    let submission = distributed_runners.submit_dispatch_with_device_dependencies(
                        slice.device_id(),
                        distributed.dispatch_index,
                        dependency_value,
                        consumes_ready,
                        dependencies.has_owner_continuation,
                        |device_id| {
                            device_by_id.get(device_id).copied().ok_or_else(|| {
                                VulkanError(format!(
                                    "distributed shard device {device_id:?} is not mounted"
                                ))
                            })
                        },
                    );
                    if let Err(error) = submission {
                        if let Some(segment) = last_submitted_segment {
                            let _ = segment.wait_submitted(
                                slice.device,
                                slice.dispatch_extensions.sequence_variant,
                            );
                        }
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::Distributed(error),
                        );
                    }
                    if let Err(error) = slice.cursor.complete_pending_distributed_dispatch(
                        slice.execution_plan,
                        distributed.dispatch_index,
                    ) {
                        let _ = distributed_runners.wait_dispatch(
                            slice.device_id(),
                            distributed.dispatch_index,
                            |device_id| {
                                device_by_id.get(device_id).copied().ok_or_else(|| {
                                    VulkanError(format!(
                                        "distributed shard device {device_id:?} is not mounted"
                                    ))
                                })
                            },
                        );
                        return Err(error.into());
                    }
                    ready_dependency = None;
                    if dependencies.has_owner_continuation {
                        completion_dependency =
                            Some((distributed.dispatch_index, dependency_value));
                    } else {
                        distributed_runners
                            .wait_dispatch(
                                slice.device_id(),
                                distributed.dispatch_index,
                                |device_id| {
                                    device_by_id.get(device_id).copied().ok_or_else(|| {
                                        VulkanError(format!(
                                            "distributed shard device {device_id:?} is not mounted"
                                        ))
                                    })
                                },
                            )
                            .map_err(
                                VulkanMountedPlacedResidentInProcessStreamTickError::Distributed,
                            )?;
                    }
                    continue;
                }

                let segment = slice
                    .execution_plan
                    .segment_starting_at(slice.cursor.next_stage_index)
                    .ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                            VulkanMountedPlacedResidentStreamTickError::Dispatch(
                                VulkanMountedPlacedResidentKernelDispatchError::MissingDispatchSegment {
                                    device_id: slice.device_id().to_string(),
                                    stage_index: slice.cursor.next_stage_index,
                                },
                            ),
                        )
                    })?;
                let next_distributed = slice
                    .execution_plan
                    .distributed_dispatch_at_stage(segment.end_stage_index)
                    .map(|dispatch| dispatch.dispatch_index);
                let mut wait_points = match completion_dependency
                    .map(|(dispatch_index, dependency_value)| {
                        distributed_runners.owner_completion_wait_points(
                            slice.device_id(),
                            dispatch_index,
                            dependency_value,
                        )
                    })
                    .transpose()
                {
                    Ok(semaphores) => semaphores.unwrap_or_default(),
                    Err(error) => {
                        let _ = wait_for_compact_slice_submitted_work(
                            slice,
                            device_by_id,
                            distributed_runners,
                            last_submitted_segment,
                            completion_dependency,
                        );
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::Distributed(error),
                        );
                    }
                };
                wait_points.append(&mut pending_cable_wait_points);
                let next_dependency = match next_distributed
                    .map(|dispatch_index| {
                        distributed_runners
                            .reserve_dependency_value(slice.device_id(), dispatch_index)
                            .map(|dependency_value| (dispatch_index, dependency_value))
                    })
                    .transpose()
                {
                    Ok(dependency) => dependency,
                    Err(error) => {
                        let _ = wait_for_compact_slice_submitted_work(
                            slice,
                            device_by_id,
                            distributed_runners,
                            last_submitted_segment,
                            completion_dependency,
                        );
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::Distributed(error),
                        );
                    }
                };
                let mut signal_points = match next_dependency
                    .map(|(dispatch_index, dependency_value)| {
                        distributed_runners.owner_ready_signal_points(
                            slice.device_id(),
                            dispatch_index,
                            dependency_value,
                        )
                    })
                    .transpose()
                {
                    Ok(points) => points.unwrap_or_default(),
                    Err(error) => {
                        let _ = wait_for_compact_slice_submitted_work(
                            slice,
                            device_by_id,
                            distributed_runners,
                            last_submitted_segment,
                            completion_dependency,
                        );
                        return Err(
                            VulkanMountedPlacedResidentInProcessStreamTickError::Distributed(error),
                        );
                    }
                };
                if let Some(VulkanMountedPlacedStreamTickStage::PublishCable {
                    cable_index, ..
                }) = slice.cursor.tick_plan.stages.get(segment.end_stage_index)
                {
                    let outgoing = slice
                        .mounted
                        .cable_io
                        .outgoing_buffer(*cable_index)
                        .ok_or_else(|| {
                            VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                                VulkanMountedPlacedResidentStreamTickError::Transport(
                                    VulkanPlacedCableTransportError::MissingOutgoingCable {
                                        device_id: slice.device_id().to_string(),
                                        cable_index: *cable_index,
                                    },
                                ),
                            )
                        })?;
                    let cable_key =
                        VulkanPlacedCablePacketKey::from_outgoing_endpoint(&outgoing.endpoint);
                    if transport.cable_uses_shared_allocation(&cable_key)
                        && let Some(signal_point) = cable_synchronizations
                            .prepare_source_signal(&outgoing.endpoint)
                            .map_err(
                                VulkanMountedPlacedResidentInProcessStreamTickError::Schedule,
                            )?
                    {
                        signal_points.push(signal_point);
                    }
                }
                let submission = segment.submit_with_stream_control_and_timeline_semaphores(
                    slice.device,
                    control,
                    if slice.execution_plan.first_dispatch_segment_stage_index()
                        == Some(segment.start_stage_index)
                    {
                        &slice.dispatch_extensions.prefix_dispatches
                    } else {
                        &[]
                    },
                    if slice.execution_plan.last_dispatch_segment_stage_index()
                        == Some(segment.start_stage_index)
                    {
                        &slice.dispatch_extensions.suffix_dispatches
                    } else {
                        &[]
                    },
                    slice.dispatch_extensions.sequence_variant,
                    &wait_points,
                    &signal_points,
                );
                if let Err(error) = submission {
                    let _ = wait_for_compact_slice_submitted_work(
                        slice,
                        device_by_id,
                        distributed_runners,
                        last_submitted_segment,
                        completion_dependency,
                    );
                    return Err(
                        VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                            VulkanMountedPlacedResidentStreamTickError::Dispatch(error),
                        ),
                    );
                }
                completion_dependency = None;
                ready_dependency = next_dependency;
                last_submitted_segment = Some(segment);
                while slice.cursor.next_stage_index < segment.end_stage_index {
                    slice.cursor.complete_current_stage();
                }
            }
            VulkanMountedPlacedStreamTickStage::PublishCable { cable_index, .. } => {
                let outgoing = slice
                    .mounted
                    .cable_io
                    .outgoing_buffer(*cable_index)
                    .ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                            VulkanMountedPlacedResidentStreamTickError::Transport(
                                VulkanPlacedCableTransportError::MissingOutgoingCable {
                                    device_id: slice.device_id().to_string(),
                                    cable_index: *cable_index,
                                },
                            ),
                        )
                    })?;
                let cable_key =
                    VulkanPlacedCablePacketKey::from_outgoing_endpoint(&outgoing.endpoint);
                if !transport.cable_uses_shared_allocation(&cable_key) {
                    wait_for_compact_slice_submitted_work(
                        slice,
                        device_by_id,
                        distributed_runners,
                        last_submitted_segment.take(),
                        completion_dependency.take(),
                    )?;
                }
                transport
                    .publish_outgoing_cable(slice.mounted, *cable_index)
                    .map_err(|error| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::StreamTick(
                            VulkanMountedPlacedResidentStreamTickError::Transport(error),
                        )
                    })?;
                slice.cursor.complete_current_stage();
            }
        }
    }
    if !pending_cable_wait_points.is_empty() {
        return Err(
            VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(format!(
                "device {:?} completed without consuming {} cable timeline dependencies",
                slice.device_id(),
                pending_cable_wait_points.len()
            ))),
        );
    }
    Ok(slice.cursor.completed_stage_count - completed_before)
}

pub fn run_mounted_placed_resident_stream_tick_slices_in_process(
    slices: &mut [VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    transport: &mut VulkanInProcessPlacedCableTransport,
) -> Result<
    VulkanMountedPlacedResidentInProcessStreamTickRun,
    VulkanMountedPlacedResidentInProcessStreamTickError,
> {
    let tick_plans = slices
        .iter()
        .map(|slice| slice.execution_plan.tick_plan.as_ref())
        .collect::<Vec<_>>();
    let schedule = VulkanMountedPlacedResidentInProcessSchedule::from_tick_plans(&tick_plans)
        .map_err(VulkanMountedPlacedResidentInProcessStreamTickError::Schedule)?;
    run_mounted_placed_resident_stream_tick_slices_in_process_with_schedule(
        slices, transport, &schedule,
    )
}

fn run_mounted_placed_resident_stream_tick_slices_in_process_with_schedule(
    slices: &mut [VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    transport: &mut VulkanInProcessPlacedCableTransport,
    schedule: &VulkanMountedPlacedResidentInProcessSchedule,
) -> Result<
    VulkanMountedPlacedResidentInProcessStreamTickRun,
    VulkanMountedPlacedResidentInProcessStreamTickError,
> {
    run_mounted_placed_resident_stream_tick_slices_in_process_with_schedule_and_distributed(
        slices, transport, schedule, None, None,
    )
}

fn run_mounted_placed_resident_stream_tick_slices_in_process_with_schedule_and_distributed(
    slices: &mut [VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    transport: &mut VulkanInProcessPlacedCableTransport,
    schedule: &VulkanMountedPlacedResidentInProcessSchedule,
    distributed_runners: Option<&VulkanDistributedDispatchRunners>,
    cable_synchronizations: Option<&VulkanPlacedCableTimelineSynchronizations>,
) -> Result<
    VulkanMountedPlacedResidentInProcessStreamTickRun,
    VulkanMountedPlacedResidentInProcessStreamTickError,
> {
    schedule
        .validate_slices(slices)
        .map_err(VulkanMountedPlacedResidentInProcessStreamTickError::Schedule)?;
    transport.reset_tick_state();
    register_in_process_direct_cable_copies(slices, transport)?;
    if cable_synchronizations
        .is_some_and(VulkanPlacedCableTimelineSynchronizations::has_pending_dependencies)
    {
        return Err(
            VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                "placed cable timeline state leaked across stream ticks".to_string(),
            )),
        );
    }
    if distributed_runners.is_some() {
        prepare_compact_shared_stream_control(slices)?;
    }

    let mut completed_stage_delta = 0usize;
    let device_by_id = slices
        .iter()
        .map(|slice| (slice.device_id().to_string(), slice.device))
        .collect::<BTreeMap<_, _>>();

    for (turn_index, device_indices) in schedule.turns.iter().enumerate() {
        for device_index in device_indices {
            if let Some(runners) = distributed_runners
                && !slices[*device_index].cursor.capture_execution_trace
            {
                let cable_synchronizations = cable_synchronizations.ok_or_else(|| {
                    VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                        "compact placed execution requires mounted cable timeline synchronization"
                            .to_string(),
                    ))
                })?;
                let device_completed_stage_delta =
                    advance_compact_slice_with_distributed_dependencies(
                        &mut slices[*device_index],
                        &device_by_id,
                        transport,
                        runners,
                        cable_synchronizations,
                    )?;
                if device_completed_stage_delta == 0 {
                    return Err(
                        VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                            format!(
                                "placed activation schedule turn {turn_index} made no progress on device {:?}",
                                slices[*device_index].device_id()
                            ),
                        )),
                    );
                }
                completed_stage_delta = completed_stage_delta
                    .checked_add(device_completed_stage_delta)
                    .ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                            "placed activation schedule progress overflowed".to_string(),
                        ))
                    })?;
                continue;
            }
            let mut device_completed_stage_delta = 0usize;
            loop {
                let advance = {
                    let slice = &mut slices[*device_index];
                    slice
                        .cursor
                        .advance_with_resident_execution_plan_and_in_process_transport(
                            slice.device,
                            slice.mounted,
                            slice.execution_plan,
                            &slice.dispatch_extensions,
                            transport,
                        )?
                };
                device_completed_stage_delta = device_completed_stage_delta
                    .checked_add(advance.completed_stage_delta)
                    .ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                            "placed distributed stage progress overflowed".to_string(),
                        ))
                    })?;
                let pending_distributed_dispatch = {
                    let slice = &slices[*device_index];
                    slice
                        .cursor
                        .pending_distributed_dispatch(slice.execution_plan)
                        .map(|dispatch| dispatch.dispatch_index)
                };
                let Some(dispatch_index) = pending_distributed_dispatch else {
                    break;
                };
                let runners = distributed_runners.ok_or_else(|| {
                    VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                        format!(
                            "placed device {:?} reached distributed dispatch {dispatch_index} without mounted distributed runners",
                            slices[*device_index].device_id()
                        ),
                    ))
                })?;
                let owner_device_id = slices[*device_index].device_id().to_string();
                runners
                    .run_dispatch(&owner_device_id, dispatch_index, |shard_device_id| {
                        slices
                            .iter()
                            .find(|slice| slice.device_id() == shard_device_id)
                            .map(|slice| slice.device)
                            .ok_or_else(|| {
                                VulkanError(format!(
                                    "distributed shard device {shard_device_id:?} is not mounted"
                                ))
                            })
                    })
                    .map_err(VulkanMountedPlacedResidentInProcessStreamTickError::Distributed)?;
                {
                    let slice = &mut slices[*device_index];
                    slice.cursor.complete_pending_distributed_dispatch(
                        slice.execution_plan,
                        dispatch_index,
                    )?;
                }
                device_completed_stage_delta =
                    device_completed_stage_delta.checked_add(1).ok_or_else(|| {
                        VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                            "placed distributed stage progress overflowed".to_string(),
                        ))
                    })?;
            }
            if device_completed_stage_delta == 0 {
                return Err(
                    VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                        format!(
                            "placed activation schedule turn {turn_index} made no progress on device {:?}",
                            slices[*device_index].device_id()
                        ),
                    )),
                );
            }
            completed_stage_delta = completed_stage_delta
                .checked_add(device_completed_stage_delta)
                .ok_or_else(|| {
                    VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                        "placed activation schedule progress overflowed".to_string(),
                    ))
                })?;
        }
    }

    if !slices.iter().all(|slice| slice.cursor.is_completed()) {
        return Err(
            VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(format!(
                "placed activation schedule ended with pending devices {:?}",
                pending_in_process_stream_tick_device_ids(slices)
            ))),
        );
    }
    if cable_synchronizations
        .is_some_and(VulkanPlacedCableTimelineSynchronizations::has_pending_dependencies)
    {
        return Err(
            VulkanMountedPlacedResidentInProcessStreamTickError::Schedule(VulkanError(
                "placed cable timeline dependencies were not consumed".to_string(),
            )),
        );
    }
    if let Some(distributed_runners) = distributed_runners {
        for slice in slices
            .iter()
            .filter(|slice| !slice.cursor.capture_execution_trace)
        {
            wait_for_compact_slice_terminal_work(slice, &device_by_id, distributed_runners)?;
        }
    }

    Ok(in_process_stream_tick_run_snapshot(
        slices,
        transport,
        VulkanMountedPlacedResidentInProcessStreamTickRunStatus::Completed,
        schedule.turns.len(),
        completed_stage_delta,
    ))
}

fn pending_in_process_stream_tick_device_ids(
    slices: &[VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
) -> Vec<String> {
    slices
        .iter()
        .filter(|slice| !slice.cursor.is_completed())
        .map(|slice| slice.device_id().to_string())
        .collect()
}

fn in_process_stream_tick_run_snapshot(
    slices: &[VulkanMountedPlacedResidentInProcessStreamTickSlice<'_>],
    transport: &VulkanInProcessPlacedCableTransport,
    status: VulkanMountedPlacedResidentInProcessStreamTickRunStatus,
    scheduler_turn_count: usize,
    completed_stage_delta: usize,
) -> VulkanMountedPlacedResidentInProcessStreamTickRun {
    let completed_slice_count = slices
        .iter()
        .filter(|slice| slice.cursor.is_completed())
        .count();
    VulkanMountedPlacedResidentInProcessStreamTickRun {
        status,
        scheduler_turn_count,
        completed_stage_delta,
        completed_slice_count,
        pending_slice_count: slices.len() - completed_slice_count,
        transport_stats: transport.stats(),
        device_runs: if slices
            .iter()
            .any(|slice| slice.cursor.capture_execution_trace)
        {
            slices.iter().map(|slice| slice.cursor.snapshot()).collect()
        } else {
            Vec::new()
        },
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanMountedPlacedResidentStreamTickRun {
    pub tick_run: VulkanMountedPlacedStreamTickRun,
    pub pedalboard_run: Option<VulkanMountedPlacedResidentPedalboardRun>,
}

impl VulkanMountedPlacedResidentStreamTickRun {
    pub fn pedalboard_dispatch_count(&self) -> usize {
        self.pedalboard_run
            .as_ref()
            .map(VulkanMountedPlacedResidentPedalboardRun::dispatch_count)
            .unwrap_or(0)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
