    #[test]
    fn pedal_batch_signal_liveness_reuses_only_compatible_dead_buffers() {
        let key = |signal_id: &str| VulkanPedalBatchSignalKey::Activation {
            pedal_id: "pedal".to_string(),
            signal_id: signal_id.to_string(),
        };
        let lifetimes = vec![
            VulkanPedalBatchSignalLifetime {
                key: key("first"),
                frame_byte_capacity: 4_096,
                host_visible: false,
                first_dispatch: 0,
                last_dispatch: 2,
            },
            VulkanPedalBatchSignalLifetime {
                key: key("overlapping"),
                frame_byte_capacity: 4_096,
                host_visible: false,
                first_dispatch: 2,
                last_dispatch: 3,
            },
            VulkanPedalBatchSignalLifetime {
                key: key("reusable"),
                frame_byte_capacity: 4_096,
                host_visible: false,
                first_dispatch: 3,
                last_dispatch: 4,
            },
            VulkanPedalBatchSignalLifetime {
                key: key("different_size"),
                frame_byte_capacity: 8_192,
                host_visible: false,
                first_dispatch: 5,
                last_dispatch: 6,
            },
            VulkanPedalBatchSignalLifetime {
                key: VulkanPedalBatchSignalKey::IncomingCable(7),
                frame_byte_capacity: 4_096,
                host_visible: true,
                first_dispatch: 5,
                last_dispatch: 6,
            },
        ];

        let (indices, buffers) = allocate_pedal_batch_signal_lifetimes(lifetimes);

        assert_eq!(buffers.len(), 4);
        assert_ne!(indices[&key("first")], indices[&key("overlapping")]);
        assert_eq!(indices[&key("first")], indices[&key("reusable")]);
        assert_ne!(indices[&key("first")], indices[&key("different_size")]);
        assert_ne!(
            indices[&key("first")],
            indices[&VulkanPedalBatchSignalKey::IncomingCable(7)]
        );
    }
    const FIXTURE_MODEL_FRAME_BYTES: usize = FIXTURE_MODEL_HIDDEN_SIZE * 2;
    const FIXTURE_MODEL_LOGITS_BYTES: usize = 65_536 * 4;
    const FIXTURE_MODEL_SAMPLER_OUTPUT_BYTES: usize = 16;
    const FIXTURE_MODEL_EMBED_TOKENS_BYTES: usize = 65_536 * FIXTURE_MODEL_FRAME_BYTES;

    #[test]
    fn speculative_verification_commits_through_the_first_mismatch() {
        let result = verify_speculative_token_prefix(&[11, 12, 13], &[11, 99, 88, 77]).unwrap();

        assert_eq!(result.accepted_draft_count, 1);
        assert_eq!(result.committed_target_tick_count, 2);
        assert_eq!(result.emitted_token_ids, [11, 99]);
    }

    #[test]
    fn speculative_verification_emits_the_bonus_token_when_all_drafts_match() {
        let result = verify_speculative_token_prefix(&[11, 12], &[11, 12, 13]).unwrap();

        assert_eq!(result.accepted_draft_count, 2);
        assert_eq!(result.committed_target_tick_count, 3);
        assert_eq!(result.emitted_token_ids, [11, 12, 13]);
    }

    #[test]
    fn speculative_verification_rejects_incomplete_target_results() {
        let error = verify_speculative_token_prefix(&[11, 12], &[11, 12]).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("2 draft tokens but 2 target predictions; expected 3")
        );
    }

    #[test]
    fn speculative_verification_stops_at_the_first_emitted_stop_token() {
        let mut result = verify_speculative_token_prefix(&[11, 12], &[11, 12, 99]).unwrap();

        truncate_speculative_verification_at_stop(&mut result, &BTreeSet::from([11]));

        assert_eq!(result.accepted_draft_count, 1);
        assert_eq!(result.committed_target_tick_count, 1);
        assert_eq!(result.emitted_token_ids, [11]);
    }

    #[test]
    fn speculative_batches_select_the_smallest_exact_covering_tile() {
        let artifact =
            |lane_tile_width, exact_primary_equivalence| VulkanResidentPedalBatchKernelArtifact {
                pedal_id: "processor".to_string(),
                node_id: "project".to_string(),
                batch_mode: VulkanResidentPedalKernelBatchMode::WeightShared,
                lane_tile_width,
                exact_primary_equivalence,
                device_requirements: VulkanResidentVulkanDeviceRequirements::default(),
                stages: Vec::new(),
            };
        let artifacts = vec![
            artifact(64, false),
            artifact(2, true),
            artifact(4, true),
            artifact(8, true),
            artifact(16, true),
        ];

        let verification = select_pedal_batch_kernel_artifact(
            &artifacts,
            "processor",
            "project",
            VulkanPedalBatchExecutionMode::IndependentCandidates,
            6,
        )
        .unwrap();
        assert_eq!(verification.lane_tile_width, 8);
        assert!(verification.exact_primary_equivalence);

        let causal = select_pedal_batch_kernel_artifact(
            &artifacts,
            "processor",
            "project",
            VulkanPedalBatchExecutionMode::CausalSequence,
            6,
        )
        .unwrap();
        assert_eq!(causal.lane_tile_width, 64);

        let heterogeneous = select_pedal_batch_kernel_artifact_where(
            &artifacts,
            "processor",
            "project",
            VulkanPedalBatchExecutionMode::CausalSequence,
            6,
            |artifact| artifact.lane_tile_width != 64,
        )
        .unwrap();
        assert_eq!(heterogeneous.lane_tile_width, 16);
    }

    #[test]
    fn pedal_batch_execution_contract_requires_matching_shader_mode() {
        let execution = |batch_mode, batch_shader_path: Option<String>| {
            let batch_implementations = batch_shader_path
                .into_iter()
                .map(|shader_path| VulkanResidentPedalBatchImplementationSpec {
                    lane_tile_width: 16,
                    exact_primary_equivalence: true,
                    device_requirements: VulkanResidentVulkanDeviceRequirements::default(),
                    stages: vec![VulkanResidentPedalBatchStageSpec {
                        shader_path,
                        local_size_x: 64,
                        workgroup_count_x: 1,
                    }],
                })
                .collect();
            vec![VulkanResidentPedalExecutionSpec {
                pedal_id: "processor".to_string(),
                operator_type: "fixture".to_string(),
                implementation: "exact_reference".to_string(),
                kernels: vec![VulkanResidentPedalKernelSpec {
                    execution_index: 0,
                    node_id: "project".to_string(),
                    op: "linear".to_string(),
                    shader_path: "shaders/project.spv".to_string(),
                    local_size_x: 64,
                    workgroup_count_x: 1,
                    batch_mode,
                    batch_implementations,
                }],
            }]
        };

        validate_pedal_executions(
            "fixture",
            &execution(VulkanResidentPedalKernelBatchMode::SerialLanes, None),
        )
        .unwrap();
        validate_pedal_executions(
            "fixture",
            &execution(
                VulkanResidentPedalKernelBatchMode::WeightShared,
                Some("shaders/project_batch.spv".to_string()),
            ),
        )
        .unwrap();
        validate_pedal_executions(
            "fixture",
            &execution(
                VulkanResidentPedalKernelBatchMode::CausalScan,
                Some("shaders/project_scan.spv".to_string()),
            ),
        )
        .unwrap();

        let serial_error = validate_pedal_executions(
            "fixture",
            &execution(
                VulkanResidentPedalKernelBatchMode::SerialLanes,
                Some("shaders/project_batch.spv".to_string()),
            ),
        )
        .unwrap_err();
        assert!(serial_error.to_string().contains("invalid SerialLanes"));

        let batch_error = validate_pedal_executions(
            "fixture",
            &execution(VulkanResidentPedalKernelBatchMode::WeightShared, None),
        )
        .unwrap_err();
        assert!(batch_error.to_string().contains("invalid WeightShared"));
    }

