    fn fixture_model_execution_graph() -> ResolvedLoweredPedalboard {
        let full = ResolvedLoweredPedalboard::from_index_file(fixture_model_index_path()).unwrap();
        let processor_ids = full
            .circuits
            .iter()
            .filter(|artifact| artifact.circuit.runtime_role.is_signal_processor())
            .map(|artifact| artifact.pedal.id.as_str())
            .collect::<BTreeSet<_>>();
        let circuits = full
            .circuits
            .iter()
            .filter(|artifact| processor_ids.contains(artifact.pedal.id.as_str()))
            .cloned()
            .collect::<Vec<_>>();
        let mut index = full.index.clone();
        index.graph.circuits = circuits
            .iter()
            .map(|artifact| artifact.pedal.clone())
            .collect();
        index.graph.cables = full
            .index
            .graph
            .cables
            .iter()
            .filter(|cable| {
                cable.connection.is_forward()
                    && processor_ids.contains(cable.source.pedal_id.as_str())
                    && processor_ids.contains(cable.destination.pedal_id.as_str())
            })
            .cloned()
            .collect();
        index.graph.boundary = StreamCircuitGraphBoundary {
            external_inputs: execution_boundary_inputs(&full, &processor_ids),
            public_outputs: execution_boundary_outputs(&full, &processor_ids),
        };
        let mut operator_counts = BTreeMap::new();
        for artifact in &circuits {
            *operator_counts
                .entry(artifact.pedal.operator_type.clone())
                .or_insert(0) += 1;
        }
        index.summary = LoweredPedalboardSummary {
            circuit_count: circuits.len(),
            operator_counts,
        };
        ResolvedLoweredPedalboard {
            artifact_root: full.artifact_root,
            index,
            circuits,
        }
    }

    fn copy_package_integrity_artifacts(
        source_root: &Path,
        destination_root: &Path,
        manifest: &VulkanResidentModelPackageManifest,
    ) {
        for relative_path in manifest.artifact_integrity.files.keys() {
            let destination = destination_root.join(relative_path);
            std::fs::create_dir_all(destination.parent().unwrap()).unwrap();
            std::fs::copy(source_root.join(relative_path), destination).unwrap();
        }
    }

    #[test]
    fn package_loader_rejects_shallow_and_stale_behavioral_evidence() {
        let source_manifest_path = fixture_model_package_manifest_path();
        let source_manifest = fixture_model_package_manifest();
        let source_root = source_manifest_path.parent().unwrap();
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let root = std::env::temp_dir().join(format!(
            "llmoop-behavioral-evidence-{}-{unique}",
            std::process::id()
        ));
        std::fs::create_dir_all(&root).unwrap();
        let manifest_path = root.join("vulkan_resident_package.json");
        let evidence_path = root.join("behavioral_validation.json");
        std::fs::copy(&source_manifest_path, &manifest_path).unwrap();

        std::fs::write(
            &evidence_path,
            serde_json::to_vec_pretty(&serde_json::json!({
                "schema": "llmoop.behavioral_validation.v1",
                "status": "passed",
                "candidate_kind": "exact_reference",
                "candidate_contract_digest_algorithm": CONTRACT_DIGEST_ALGORITHM
            }))
            .unwrap(),
        )
        .unwrap();
        let shallow_error = VulkanResidentModelPackageManifest::from_json_file(&manifest_path)
            .unwrap_err()
            .to_string();
        assert!(shallow_error.contains("source oracle contract"));

        let mut evidence: Value = serde_json::from_slice(
            &std::fs::read(source_root.join(&source_manifest.behavioral_validation_path)).unwrap(),
        )
        .unwrap();
        evidence["circuits"][0]["candidate_node_count"] = Value::from(u64::MAX);
        std::fs::write(
            &evidence_path,
            serde_json::to_vec_pretty(&evidence).unwrap(),
        )
        .unwrap();
        let stale_error = VulkanResidentModelPackageManifest::from_json_file(&manifest_path)
            .unwrap_err()
            .to_string();
        assert!(stale_error.contains("incomplete or stale proof"));

        let original_evidence =
            std::fs::read(source_root.join(&source_manifest.behavioral_validation_path)).unwrap();
        std::fs::write(&evidence_path, original_evidence).unwrap();
        let mut raw_manifest: Value =
            serde_json::from_slice(&std::fs::read(&source_manifest_path).unwrap()).unwrap();
        raw_manifest["circuit_graph"]["pedals"][0]["circuit"]["nodes"][0]["attrs"]["adversarial_drift"] =
            Value::from(true);
        std::fs::write(
            &manifest_path,
            serde_json::to_vec_pretty(&raw_manifest).unwrap(),
        )
        .unwrap();
        let same_size_stale_error =
            VulkanResidentModelPackageManifest::from_json_file(&manifest_path)
                .unwrap_err()
                .to_string();
        assert!(same_size_stale_error.contains("incomplete or stale proof"));

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn package_loader_rejects_compiler_owned_runtime_placement() {
        let source_manifest_path = fixture_model_package_manifest_path();
        let raw_manifest: Value =
            serde_json::from_slice(&std::fs::read(source_manifest_path).unwrap()).unwrap();
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let root = std::env::temp_dir().join(format!(
            "llmoop-compiler-placement-{}-{unique}",
            std::process::id()
        ));
        std::fs::create_dir_all(&root).unwrap();
        let manifest_path = root.join("vulkan_resident_package.json");

        for (field, value) in [
            ("device_id", Value::from("gpu0")),
            (
                "placement",
                serde_json::json!({
                    "schema": "llmoop.stream_circuit_placement.v1",
                    "default_device_id": "gpu0",
                    "pedal_devices": {}
                }),
            ),
        ] {
            let mut invalid_manifest = raw_manifest.clone();
            invalid_manifest[field] = value;
            std::fs::write(
                &manifest_path,
                serde_json::to_vec_pretty(&invalid_manifest).unwrap(),
            )
            .unwrap();

            let error = VulkanResidentModelPackageManifest::from_json_file(&manifest_path)
                .unwrap_err()
                .to_string();
            assert!(error.contains("must not contain runtime placement fields"));
            assert!(error.contains(field));
        }

        std::fs::remove_dir_all(root).unwrap();
    }

