    #[test]
    fn resident_token_engine_creates_two_streams_from_one_shared_model() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping resident token shared model streams: {error}");
                return;
            }
        };
        let model = fixture_model_resident_greedy_model(&device, 8).unwrap();
        let mut engine = VulkanResidentTokenEngine::new(device);
        let loaded_model = engine
            .add_model_package("shared_compiled_model", model)
            .unwrap();
        assert_eq!(loaded_model.model_id, "shared_compiled_model");
        assert_eq!(loaded_model.device_id, "runtime_default");
        assert_eq!(loaded_model.registered_stream_count, 0);
        assert_eq!(loaded_model.dynamic_state_capacity_activations, 8);
        assert!(loaded_model.permanent_parameter_count > 0);
        assert!(loaded_model.permanent_parameter_bytes > 0);
        assert!(loaded_model.transducer_parameter_count > 0);
        assert!(loaded_model.transducer_parameter_bytes > 0);
        assert!(loaded_model.reusable_kernel_word_count > 0);

        let stream_a = engine
            .create_stream_from_model("shared_compiled_model", "shared_stream_a", 0)
            .unwrap();
        let stream_b = engine
            .create_stream_from_model("shared_compiled_model", "shared_stream_b", 1)
            .unwrap();
        assert_eq!(stream_a.model_id.as_deref(), Some("shared_compiled_model"));
        assert_eq!(stream_b.model_id.as_deref(), Some("shared_compiled_model"));
        assert_eq!(
            stream_a.residency,
            VulkanResidentTokenEngineStreamResidency::SharedModel
        );
        assert_eq!(
            stream_b.residency,
            VulkanResidentTokenEngineStreamResidency::SharedModel
        );
        assert_eq!(stream_a.pedal_count, stream_b.pedal_count);
        assert_eq!(
            stream_a.dynamic_state_capacity_activations,
            stream_b.dynamic_state_capacity_activations
        );

        let registered = engine.snapshot();
        assert_eq!(registered.models.len(), 1);
        assert_eq!(registered.models[0].model_id, "shared_compiled_model");
        assert_eq!(registered.models[0].registered_stream_count, 2);
        assert_eq!(registered.streams.len(), 2);
        assert_eq!(registered.scheduler.registered_runtime_count, 2);
        assert_eq!(registered.scheduler.active_runtime_count, 0);

        engine
            .enqueue_input_event(
                "shared_stream_a",
                VulkanResidentTokenInputEvent::new("event_a", vec![1], 2).with_origin("test_host"),
            )
            .unwrap();
        engine
            .enqueue_input_event(
                "shared_stream_b",
                VulkanResidentTokenInputEvent::new("event_b", vec![1], 2).with_origin("test_host"),
            )
            .unwrap();
        assert_eq!(engine.snapshot().scheduler.active_runtime_count, 2);

        let run = engine.run_until_idle(8, 2, 2).unwrap();
        assert_eq!(
            run.stop_condition,
            VulkanResidentTokenEngineRunStopCondition::Idle
        );
        assert_eq!(run.start_snapshot.scheduler.active_runtime_count, 2);
        assert_eq!(run.end_snapshot.scheduler.active_runtime_count, 0);
        assert_eq!(run.runtime_cycle_count, 4);
        assert_eq!(run.scheduler_runs.len(), 2);

        let mut generated_by_stream = BTreeMap::<String, Vec<u32>>::new();
        for event in &run.output_events {
            generated_by_stream
                .entry(event.stream_id.clone())
                .or_default()
                .push(event.output_event.token_id);
        }

        assert_eq!(
            generated_by_stream.get("shared_stream_a"),
            Some(&vec![1, 1])
        );
        assert_eq!(
            generated_by_stream.get("shared_stream_b"),
            Some(&vec![1, 1])
        );
        let final_snapshot = run.end_snapshot;
        assert_eq!(final_snapshot.models[0].registered_stream_count, 2);
        assert_eq!(final_snapshot.scheduler.registered_runtime_count, 2);
        assert_eq!(final_snapshot.scheduler.active_runtime_count, 0);
        assert!(final_snapshot.scheduler.idle);
        let runtime_a = engine.runtime_snapshot("shared_stream_a").unwrap();
        let runtime_b = engine.runtime_snapshot("shared_stream_b").unwrap();
        assert!(runtime_a.idle);
        assert!(runtime_b.idle);
        assert_eq!(runtime_a.stream.total_public_outputs, 2);
        assert_eq!(runtime_b.stream.total_public_outputs, 2);
        assert_eq!(runtime_a.stream.next_stream_tick, 3);
        assert_eq!(runtime_b.stream.next_stream_tick, 3);
        assert_eq!(runtime_a.pending_input_event_count, 0);
        assert_eq!(runtime_b.pending_input_event_count, 0);
    }

    #[test]
    fn resident_greedy_running_stream_interrupt_clears_feedback_without_resetting_state() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping resident running stream interrupt: {error}");
                return;
            }
        };
        let Some(processor) = create_fixture_model_resident_greedy_stream_processor(
            &device,
            "resident running stream interrupt",
        ) else {
            return;
        };
        let mut stream = processor.into_running_stream("stream_0");

        stream.inject_prompt(&[1], 3, None).unwrap();
        let first_tick = stream.tick(&device).unwrap();
        assert_eq!(first_tick.stream_tick, Some(0));
        assert_eq!(
            first_tick.input_signal.as_ref().unwrap().route(),
            VulkanResidentPromptEventInputRoute::ExternalInput
        );
        assert!(first_tick.public_output.is_some());
        assert!(first_tick.private_feedback.is_some());
        assert_eq!(stream.remaining_public_outputs, 2);
        assert_eq!(stream.pending_private_feedback_count(), 1);
        assert_eq!(stream.next_stream_tick, 1);

        let event = stream.interrupt("user_interrupt");
        assert_eq!(
            event.event_type,
            VulkanResidentStreamControlEventType::Interrupt
        );
        assert_eq!(event.reason, "user_interrupt");
        assert_eq!(event.cleared_private_feedback_ids, vec!["feedback_0"]);
        assert_eq!(event.closing_private_feedback_id, None);
        assert!(event.state_preserved);
        assert_eq!(stream.pending_private_feedback_count(), 0);
        assert_eq!(stream.remaining_public_outputs, 0);
        assert!(!stream.loop_open);
        assert_eq!(stream.last_stop_reason.as_deref(), Some("user_interrupt"));

        let idle = stream.tick(&device).unwrap();
        assert_eq!(idle.status, VulkanResidentRunningStreamTickStatus::Idle);
        assert_eq!(idle.stream_tick, None);
        assert_eq!(stream.next_stream_tick, 1);

        let resumed = stream.run_prompt(&device, &[36_309], 1, None).unwrap();
        assert_eq!(resumed.start_stream_tick, 1);
        assert_eq!(resumed.next_stream_tick, 3);
        assert_eq!(resumed.prompt_token_ids, vec![36_309]);
        assert_eq!(resumed.generated_token_ids.len(), 1);
        assert_eq!(stream.next_stream_tick, 3);
        assert_eq!(stream.public_outputs().len(), 2);
        assert_eq!(stream.private_feedback_history().len(), 2);
    }

    #[test]
    fn resident_greedy_running_stream_stop_after_current_processes_one_feedback_then_idles() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping resident running stream stop-after-current: {error}");
                return;
            }
        };
        let Some(processor) = create_fixture_model_resident_greedy_stream_processor(
            &device,
            "resident running stream stop-after-current",
        ) else {
            return;
        };
        let mut stream = processor.into_running_stream("stream_0");

        stream.inject_prompt(&[1], 3, None).unwrap();
        let first_tick = stream.tick(&device).unwrap();
        assert_eq!(first_tick.stream_tick, Some(0));
        assert!(first_tick.public_output.is_some());
        assert!(
            !first_tick
                .private_feedback
                .as_ref()
                .unwrap()
                .closes_loop_after_processing
        );
        assert_eq!(stream.pending_private_feedback_count(), 1);
        assert_eq!(stream.remaining_public_outputs, 2);

        let event = stream.stop_after_current("user_stop");
        assert_eq!(
            event.event_type,
            VulkanResidentStreamControlEventType::StopAfterCurrent
        );
        assert_eq!(event.reason, "user_stop");
        assert_eq!(
            event.closing_private_feedback_id.as_deref(),
            Some("feedback_0")
        );
        assert!(event.cleared_private_feedback_ids.is_empty());
        assert!(event.state_preserved);
        assert_eq!(stream.pending_private_feedback_count(), 1);
        assert_eq!(stream.remaining_public_outputs, 0);
        assert!(stream.loop_open);
        assert!(stream.private_feedback_history()[0].closes_loop_after_processing);
        assert_eq!(
            stream.private_feedback_history()[0].stop_reason.as_deref(),
            Some("user_stop")
        );

        let closing_tick = stream.tick(&device).unwrap();
        assert_eq!(closing_tick.stream_tick, Some(1));
        assert_eq!(
            closing_tick.input_signal.as_ref().unwrap().route(),
            VulkanResidentPromptEventInputRoute::PrivateFeedback
        );
        assert!(
            closing_tick
                .input_signal
                .as_ref()
                .unwrap()
                .closes_loop_after_processing()
        );
        assert!(closing_tick.public_output.is_none());
        assert!(closing_tick.private_feedback.is_none());
        assert_eq!(closing_tick.stop_reason.as_deref(), Some("user_stop"));
        assert!(!stream.loop_open);
        assert_eq!(stream.last_stop_reason.as_deref(), Some("user_stop"));

        let idle = stream.tick(&device).unwrap();
        assert_eq!(idle.status, VulkanResidentRunningStreamTickStatus::Idle);
        assert_eq!(idle.stream_tick, None);
        assert_eq!(stream.next_stream_tick, 2);
        assert_eq!(stream.pending_private_feedback_count(), 0);
        assert_eq!(stream.public_outputs().len(), 1);
        assert_eq!(stream.private_feedback_history().len(), 1);
    }

