        assert!(Arc::ptr_eq(&stream_a.package, &stream_b.package));
        assert!(Arc::ptr_eq(
            &stream_a.processor.device_slices[0]
                .package_slice
                .parameter_buffers,
            &stream_b.processor.device_slices[0]
                .package_slice
                .parameter_buffers,
        ));
        assert!(!std::ptr::eq(
            &stream_a.processor.device_slices[0]
                .mounted
                .buffers
                .state_buffers[0]
                .buffer,
            &stream_b.processor.device_slices[0]
                .mounted
                .buffers
                .state_buffers[0]
                .buffer,
        ));

        let mut engine = VulkanResidentInProcessPlacedPromptEngine::new();
