    #[test]
    fn placed_prompt_engine_preserves_queued_work_at_input_event_budget() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping placed prompt engine budget test: {error}");
                return;
            }
        };
        let runtime_model = fixture_model_runtime_model_with_placement(
            StreamCircuitPlacementSpec::new("gpu0").with_pedal_device("layer_02", "gpu1"),
        );
        let manifest_path = fixture_model_package_manifest_path();
        let manifest_dir = manifest_path.parent().unwrap();
        let device = Rc::new(device);
        let devices = BTreeMap::from([
            ("gpu0".to_string(), device.clone()),
            ("gpu1".to_string(), device.clone()),
        ]);
        let stream =
            VulkanResidentInProcessPlacedPromptStream::from_runtime_model_for_bound_devices(
                devices,
                manifest_dir,
                runtime_model,
                Some(8),
                0,
                0,
            )
            .unwrap();

        let mut engine = VulkanResidentInProcessPlacedPromptEngine::new();
        engine.add_stream("main", stream).unwrap();
        engine
            .enqueue_input_event(
                "main",
                VulkanResidentTokenInputEvent::new("event_a", vec![1], 1),
            )
            .unwrap();
        engine
            .enqueue_input_event(
                "main",
                VulkanResidentTokenInputEvent::new("event_b", vec![36_309], 1),
            )
            .unwrap();

        let budgeted = engine.run_until_idle_bounded(1).unwrap();

        assert_eq!(
            budgeted.stop_condition,
            VulkanResidentInProcessPlacedPromptEngineRunStopCondition::InputEventBudget
        );
        assert_eq!(budgeted.processed_input_event_count, 1);
        assert_eq!(budgeted.input_runs.len(), 1);
        assert_eq!(
            budgeted.input_runs[0].submitted_run.input_event.id,
            "event_a"
        );
        assert_eq!(budgeted.output_events.len(), 1);
        assert_eq!(
            budgeted.output_events[0].output_event.input_event_id,
            "event_a"
        );
        assert!(!budgeted.end_snapshot.idle);
        assert_eq!(
            budgeted.end_snapshot.streams[0].pending_input_event_count,
            1
        );
        assert_eq!(budgeted.end_snapshot.streams[0].next_stream_tick, 2);

        let completed_b = engine.run_until_idle_bounded(1).unwrap();
        assert_eq!(
            completed_b.stop_condition,
            VulkanResidentInProcessPlacedPromptEngineRunStopCondition::Idle
        );
        assert_eq!(completed_b.processed_input_event_count, 1);
        assert_eq!(
            completed_b.input_runs[0].submitted_run.input_event.id,
            "event_b"
        );
        assert_eq!(completed_b.output_events.len(), 1);
        assert_eq!(
            completed_b.output_events[0].output_event.input_event_id,
            "event_b"
        );
        assert!(completed_b.end_snapshot.idle);
        assert_eq!(completed_b.end_snapshot.streams[0].next_stream_tick, 4);
    }

    #[test]
    fn placed_model_package_runs_runtime_patched_duplicate_layer() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping placed model package duplicate layer patch: {error}");
                return;
            }
        };
        let manifest = fixture_model_package_manifest();
        let manifest_path = fixture_model_package_manifest_path();
        let manifest_dir = manifest_path.parent().unwrap();
        let source_graph = manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(manifest_dir)
            .unwrap();
        let patch = StreamCircuitRuntimePatch::from_source_series(&source_graph, "gpu0")
            .unwrap()
            .duplicate_after_instance(&source_graph, "layer_05", "layer_05_repeat")
            .unwrap()
            .with_instance_device("layer_05_repeat", "gpu1")
            .unwrap();
        let runtime_model = manifest.mount_runtime_patch(&patch).unwrap();

        let placed_model = Arc::new(
            VulkanResidentInProcessPlacedModelPackage::from_runtime_model_for_devices(
                &device,
                manifest_dir,
                runtime_model,
                Some(4),
            )
            .unwrap(),
        );
        let placed_package = placed_model
            .create_stream_processor_for_devices(&device, 0)
            .unwrap();
        assert_eq!(placed_model.device_ids, vec!["gpu0", "gpu1"]);
        assert_eq!(placed_model.device_count, 2);
        assert_eq!(placed_model.hosted_pedal_count, 15);
        assert_eq!(placed_package.device("gpu1").unwrap().hosted_pedal_count, 1);

        let run = placed_package
            .sample_token_id_stream_tick_in_process(&device, 1, 0)
            .unwrap();

        assert_eq!(
            run.tick_run.placed_run.status,
            VulkanMountedPlacedResidentInProcessStreamTickRunStatus::Completed
        );
        assert!(run.tick_run.placed_run.completed_stage_delta > 204);
        assert_eq!(run.sampler_run.descriptor_count, 3);
    }

    #[test]
    fn placed_stream_remount_clones_live_pedal_state_without_sharing_it() {
        let device = match VulkanComputeDevice::new() {
            Ok(device) => device,
            Err(error) => {
                eprintln!("skipping placed live state clone test: {error}");
                return;
            }
        };
        let manifest = fixture_model_package_manifest();
        let manifest_path = fixture_model_package_manifest_path();
        let manifest_dir = manifest_path.parent().unwrap();
        let source_graph = manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(manifest_dir)
            .unwrap();
        let source_patch =
            StreamCircuitRuntimePatch::from_source_series(&source_graph, "gpu0").unwrap();
        let source_model = manifest.clone().mount_runtime_patch(&source_patch).unwrap();
        let device = Rc::new(device);
        let devices = BTreeMap::from([("gpu0".to_string(), device)]);
        let source_package = Arc::new(
            VulkanResidentInProcessPlacedModelPackage::from_runtime_model_for_bound_devices(
                &devices,
                manifest_dir,
                source_model,
                Some(4),
                false,
            )
            .unwrap(),
        );
        let mut stream =
            VulkanResidentInProcessPlacedPromptStream::new(source_package, devices.clone(), 0)
                .unwrap();
        let source_state = stream
            .processor
            .device("gpu0")
            .unwrap()
            .mounted
            .buffers
            .state_buffers
            .iter()
            .find(|state| state.pedal_id == "layer_05")
            .unwrap();
        let state_id = source_state.state_id.clone();
        source_state.buffer.write_bytes(&[0xa5; 16]).unwrap();

        let mut clone_patch = source_patch
            .duplicate_after_instance(&source_graph, "layer_05", "layer_05_repeat")
            .unwrap();
        clone_patch
            .instances
            .iter_mut()
            .find(|instance| instance.instance_id == "layer_05_repeat")
            .unwrap()
            .state_policy = StreamCircuitPedalInstanceStatePolicy::CloneFrom {
            instance_id: "layer_05".to_string(),
        };
        clone_patch.validate_against_graph(&source_graph).unwrap();
        let clone_model = manifest.mount_runtime_patch(&clone_patch).unwrap();
        let clone_package = Arc::new(
            VulkanResidentInProcessPlacedModelPackage::from_runtime_model_for_bound_devices(
                &devices,
                manifest_dir,
                clone_model,
                Some(4),
                false,
            )
            .unwrap(),
        );

        stream
            .remount_model_preserving_state(clone_package.clone(), 0)
            .unwrap();
        let mounted = &stream.processor.device("gpu0").unwrap().mounted;
        let inherited = mounted.buffers.state_buffer("layer_05", &state_id).unwrap();
        let cloned = mounted
            .buffers
            .state_buffer("layer_05_repeat", &state_id)
            .unwrap();
        assert_eq!(inherited.buffer.read_bytes(16).unwrap(), vec![0xa5; 16]);
        assert_eq!(cloned.buffer.read_bytes(16).unwrap(), vec![0xa5; 16]);
        assert!(!std::ptr::eq(&inherited.buffer, &cloned.buffer));

        cloned.buffer.write_bytes(&[0x5a; 16]).unwrap();
        stream
            .remount_model_preserving_state(clone_package, 0)
            .unwrap();
        let remounted = &stream.processor.device("gpu0").unwrap().mounted;
        assert_eq!(
            remounted
                .buffers
                .state_buffer("layer_05", &state_id)
                .unwrap()
                .buffer
                .read_bytes(16)
                .unwrap(),
            vec![0xa5; 16]
        );
        assert_eq!(
            remounted
                .buffers
                .state_buffer("layer_05_repeat", &state_id)
                .unwrap()
                .buffer
                .read_bytes(16)
                .unwrap(),
            vec![0x5a; 16]
        );
    }

